const GLOBAL_LAYOUT_EXCLUDED_VIEWS = new Set(['vision', 'studerria-codex']);
const BACKGROUND_STYLE_TAG_RE = /<link[^>]+href=["']\/css\/(?:dynamic-bg|login-bg|schedule-bg|vision-bg|studerria-background|studerria-ui)\.css["'][^>]*>\s*/gi;
const BACKGROUND_SCRIPT_TAG_RE = /<script[^>]+src=["']\/js\/(?:dynamic-bg|login-bg|schedule-bg|vision-bg|studerria-background)\.js["'][^>]*><\/script>\s*/gi;
const BACKGROUND_ELEMENT_IDS = ['dynamic-bg', 'dynamic-login-bg', 'schedule-bg', 'visionBg', 'showcaseBg', 'studerriaBg'];

function extractHtmlAttribute(rawAttributes, attributeName) {
  const source = String(rawAttributes || '');
  const attr = String(attributeName || '').trim();
  if (!attr) return '';
  const pattern = new RegExp(`\\b${attr}\\s*=\\s*(["'])(.*?)\\1`, 'i');
  const match = source.match(pattern);
  return match ? String(match[2] || '') : '';
}

function stripRootElementById(html, elementId) {
  const source = String(html || '');
  const id = String(elementId || '').trim();
  if (!source || !id) return source;
  const openPattern = new RegExp(`<div\\b[^>]*\\bid=(["'])${id}\\1[^>]*>`, 'i');
  const opening = openPattern.exec(source);
  if (!opening) return source;
  const start = opening.index;
  let depth = 1;
  const tokenPattern = /<\/?div\b[^>]*>/gi;
  tokenPattern.lastIndex = start + opening[0].length;
  let endIndex = source.length;
  while (depth > 0) {
    const token = tokenPattern.exec(source);
    if (!token) break;
    const isClose = token[0].startsWith('</');
    depth += isClose ? -1 : 1;
    if (depth === 0) {
      endIndex = tokenPattern.lastIndex;
      break;
    }
  }
  return `${source.slice(0, start)}${source.slice(endIndex)}`;
}

function splitRenderedDocument(renderedHtml) {
  const source = String(renderedHtml || '');
  const htmlTagMatch = source.match(/<html\b([^>]*)>/i);
  const pageLang = extractHtmlAttribute(htmlTagMatch ? htmlTagMatch[1] : '', 'lang');

  const headMatch = source.match(/<head\b[^>]*>([\s\S]*?)<\/head>/i);
  let headContent = headMatch ? String(headMatch[1] || '') : '';
  const titleMatch = headContent.match(/<title\b[^>]*>([\s\S]*?)<\/title>/i);
  const pageTitle = titleMatch ? String(titleMatch[1] || '').replace(/\s+/g, ' ').trim() : '';
  headContent = headContent.replace(/<title\b[^>]*>[\s\S]*?<\/title>/i, '');
  headContent = headContent.replace(BACKGROUND_STYLE_TAG_RE, '');
  headContent = headContent.replace(BACKGROUND_SCRIPT_TAG_RE, '');
  headContent = headContent.trim();

  const bodyMatch = source.match(/<body\b([^>]*)>([\s\S]*?)<\/body>/i);
  const bodyAttributes = bodyMatch ? String(bodyMatch[1] || '') : '';
  let bodyContent = bodyMatch ? String(bodyMatch[2] || '') : source;
  const bodyClass = extractHtmlAttribute(bodyAttributes, 'class');
  const bodyTheme = extractHtmlAttribute(bodyAttributes, 'data-theme');

  BACKGROUND_ELEMENT_IDS.forEach((elementId) => {
    bodyContent = stripRootElementById(bodyContent, elementId);
  });
  bodyContent = bodyContent.replace(BACKGROUND_SCRIPT_TAG_RE, '').trim();

  const hasLegacyTopbar = /class=["'][^"']*\btopbar\b[^"']*["']/i.test(bodyContent);
  const hasStuderriaNavbar = /class=["'][^"']*\bstuderria-navbar\b[^"']*["']/i.test(bodyContent);
  const hasAdminNavbar = /<nav\b[^>]*class=["'][^"']*\badmin-nav\b[^"']*["'][^>]*>/i.test(bodyContent);

  return {
    pageLang,
    pageTitle,
    headContent,
    bodyContent,
    bodyClass,
    bodyTheme,
    hasTopbar: hasLegacyTopbar || hasStuderriaNavbar || hasAdminNavbar,
  };
}

app.use((req, res, next) => {
  const rawRender = res.render.bind(res);
  res.render = (view, options, callback) => {
    let viewOptions = options;
    let done = callback;
    if (typeof viewOptions === 'function') {
      done = viewOptions;
      viewOptions = {};
    }
    const normalizedOptions = viewOptions && typeof viewOptions === 'object' ? viewOptions : {};
    const viewName = String(view || '').trim();
    const isAuthView = viewName === 'login'
      || viewName === 'register'
      || viewName.startsWith('register-')
      || viewName.startsWith('register/');
    const shouldUseGlobalLayout = normalizedOptions.layout !== false
      && !viewName.startsWith('layouts/')
      && !viewName.startsWith('partials/')
      && !GLOBAL_LAYOUT_EXCLUDED_VIEWS.has(viewName);

    if (!shouldUseGlobalLayout) {
      return rawRender(view, normalizedOptions, done);
    }

    const baseOptions = { ...normalizedOptions, layout: false };
    return rawRender(view, baseOptions, (renderErr, renderedHtml) => {
      if (renderErr) {
        if (typeof done === 'function') return done(renderErr);
        return next(renderErr);
      }

      const parsed = splitRenderedDocument(renderedHtml);
      const sessionUser = req.session && req.session.user ? req.session.user : null;
      const sessionRole = req.session && req.session.role ? req.session.role : '';
      const mergedBodyClass = [
        String(parsed.bodyClass || '').trim(),
        parsed.hasTopbar ? 'page-local-topbar' : '',
        isAuthView ? 'page-auth' : '',
        viewName === 'login' ? 'page-login' : '',
        isAuthView && viewName !== 'login' ? 'page-register' : '',
      ]
        .filter(Boolean)
        .join(' ')
        .replace(/\s+/g, ' ')
        .trim();
      const hideGlobalNavbar = /\bpage-auth\b/.test(mergedBodyClass) || parsed.hasTopbar;
      const layoutLocals = {
        ...baseOptions,
        layout: false,
        pageLang: parsed.pageLang || res.locals.lang || 'uk',
        pageTitle: parsed.pageTitle || baseOptions.pageTitle || 'Studerria',
        pageHead: parsed.headContent,
        pageBodyClass: mergedBodyClass,
        pageTheme: parsed.bodyTheme || (/\btheme-dark\b/.test(mergedBodyClass) ? 'dark' : 'light'),
        showGlobalNavbar: !hideGlobalNavbar,
        role: baseOptions.role || res.locals.role || sessionRole || '',
        username: baseOptions.username || res.locals.username || (sessionUser && sessionUser.username ? sessionUser.username : ''),
        body: parsed.bodyContent,
      };

      return rawRender('layouts/main', layoutLocals, (layoutErr, layoutHtml) => {
        if (layoutErr) {
          if (typeof done === 'function') return done(layoutErr);
          return next(layoutErr);
        }
        if (typeof done === 'function') return done(null, layoutHtml);
        if (!res.headersSent) res.send(layoutHtml);
        return null;
      });
    });
  };
  next();
});

const isProd = process.env.NODE_ENV === 'production';
const bodyFormLimit = String(process.env.BODY_FORM_LIMIT || '512kb').trim() || '512kb';
const bodyJsonLimit = String(process.env.BODY_JSON_LIMIT || '512kb').trim() || '512kb';
const trustProxyRaw = String(process.env.TRUST_PROXY || '').trim();
const trustProxySetting = securityHelpers.resolveTrustProxySetting(trustProxyRaw, { isProd });
const sessionCookieName = String(process.env.SESSION_COOKIE_NAME || 'sid').trim() || 'sid';
const contentSecurityDirectives = {
  defaultSrc: ["'self'"],
  baseUri: ["'self'"],
  objectSrc: ["'none'"],
  frameAncestors: ["'self'"],
  formAction: ["'self'"],
  imgSrc: ["'self'", 'data:', 'blob:', 'https:'],
  mediaSrc: ["'self'", 'data:', 'blob:'],
  fontSrc: ["'self'", 'data:', 'https://fonts.gstatic.com'],
  styleSrc: ["'self'", "'unsafe-inline'", 'https://cdn.jsdelivr.net', 'https://fonts.googleapis.com'],
  scriptSrc: ["'self'", "'unsafe-inline'", 'https://cdn.jsdelivr.net'],
  connectSrc: ["'self'", 'ws:', 'wss:'],
};
if (isProd) {
  contentSecurityDirectives.upgradeInsecureRequests = [];
}

app.disable('x-powered-by');
app.set('trust proxy', trustProxySetting);
app.use(helmet({
  contentSecurityPolicy: {
    useDefaults: true,
    directives: contentSecurityDirectives,
  },
  crossOriginEmbedderPolicy: false,
  referrerPolicy: { policy: 'strict-origin-when-cross-origin' },
  frameguard: { action: 'sameorigin' },
  permittedCrossDomainPolicies: { permittedPolicies: 'none' },
}));
app.use((_req, res, next) => {
  res.setHeader(
    'Permissions-Policy',
    'accelerometer=(), ambient-light-sensor=(), camera=(), geolocation=(), gyroscope=(), magnetometer=(), microphone=(), payment=(), usb=()'
  );
  return next();
});
app.use(express.urlencoded({
  extended: true,
  limit: bodyFormLimit,
  parameterLimit: 1000,
}));
app.use(express.json({ limit: bodyJsonLimit }));
app.use((err, req, res, next) => {
  if (!(err && (err.type === 'entity.too.large' || Number(err.status) === 413))) {
    return next(err);
  }
  if (req.accepts('json') || req.path.startsWith('/api') || req.path.endsWith('.json')) {
    return res.status(413).json({ ok: false, error: 'payload_too_large' });
  }
  return res.status(413).send('Request body too large');
});
app.use(express.static('public'));

const dbSslEnabled = String(process.env.DB_SSL || '').trim().toLowerCase() === 'true';

const pool = new Pool({
  host: process.env.DB_HOST || `/cloudsql/${process.env.INSTANCE_CONNECTION_NAME}`,
  user: process.env.DB_USER,
  password: process.env.DB_PASS,
  database: process.env.DB_NAME,
  port: process.env.DB_PORT ? Number(process.env.DB_PORT) : 5432,
  ssl: securityHelpers.resolveDbSslConfig({
    enabled: dbSslEnabled,
    ca: process.env.DB_SSL_CA || '',
  }),
});

const sessionSecretState = securityHelpers.resolveSessionSecret(process.env.SESSION_SECRET || '', { isProd });
const resolvedSessionSecret = sessionSecretState.secret;
if (!isProd && sessionSecretState.usedFallback) {
  console.warn('SESSION_SECRET is not set; using the local development fallback secret.');
}
const sessionTableNameRaw = String(process.env.SESSION_TABLE_NAME || 'user_sessions').trim();
const sessionTableName = /^[a-zA-Z_][a-zA-Z0-9_]*$/.test(sessionTableNameRaw)
  ? sessionTableNameRaw
  : 'user_sessions';
if (sessionTableName !== sessionTableNameRaw) {
  console.warn(`Invalid SESSION_TABLE_NAME "${sessionTableNameRaw}", fallback to "${sessionTableName}".`);
}
const pruneIntervalRaw = Number(process.env.SESSION_PRUNE_INTERVAL_SECONDS || 900);
const pruneIntervalSeconds = Number.isFinite(pruneIntervalRaw) && pruneIntervalRaw >= 60
  ? Math.floor(pruneIntervalRaw)
  : 900;
const sessionHealthProbeIntervalRaw = Number(process.env.SESSION_HEALTHCHECK_INTERVAL_SECONDS || 60);
const sessionHealthProbeIntervalSeconds = Number.isFinite(sessionHealthProbeIntervalRaw) && sessionHealthProbeIntervalRaw >= 15
  ? Math.floor(sessionHealthProbeIntervalRaw)
  : 60;
const sessionHealthProbeIntervalMs = sessionHealthProbeIntervalSeconds * 1000;

const normalizeSessionHealthError = (rawError) => {
  const normalized = String(rawError || '')
    .replace(/\s+/g, ' ')
    .trim();
  if (normalized.length <= 220) return normalized;
  return `${normalized.slice(0, 217)}...`;
};

const sessionHealthState = {
  ok: true,
  table: sessionTableName,
  lastCheckedAt: null,
  lastOkAt: null,
  lastErrorAt: null,
  lastError: null,
  checks: 0,
  failures: 0,
  lastDurationMs: null,
};

const logSessionHealth = (event, payload = {}) => {
  const record = {
    type: 'session_health',
    event,
    ...payload,
  };
  if (event === 'probe_failed' || event === 'store_error' || event === 'probe_crashed') {
    console.error('SESSION_HEALTH', JSON.stringify(record));
    return;
  }
  console.log('SESSION_HEALTH', JSON.stringify(record));
};

const probeSessionStoreHealth = async (reason = 'interval') => {
  const startedAt = Date.now();
  const wasOk = sessionHealthState.ok;
  try {
    await new Promise((resolve, reject) => {
      sessionStore.get('__healthcheck__', (err) => {
        if (err) return reject(err);
        return resolve();
      });
    });
    const nowIso = new Date().toISOString();
    const durationMs = Date.now() - startedAt;
    sessionHealthState.ok = true;
    sessionHealthState.lastCheckedAt = nowIso;
    sessionHealthState.lastOkAt = nowIso;
    sessionHealthState.lastDurationMs = durationMs;
    sessionHealthState.lastError = null;
    sessionHealthState.checks += 1;
    logSessionHealth(wasOk ? 'probe_ok' : 'probe_recovered', { reason, duration_ms: durationMs });
  } catch (err) {
    const nowIso = new Date().toISOString();
    const durationMs = Date.now() - startedAt;
    const message = normalizeSessionHealthError(err && err.message ? err.message : err);
    sessionHealthState.ok = false;
    sessionHealthState.lastCheckedAt = nowIso;
    sessionHealthState.lastErrorAt = nowIso;
    sessionHealthState.lastError = message;
    sessionHealthState.lastDurationMs = durationMs;
    sessionHealthState.checks += 1;
    sessionHealthState.failures += 1;
    pushRuntimeErrorEvent('session', `probe:${reason}`, message);
    logSessionHealth('probe_failed', { reason, duration_ms: durationMs, error: message });
  }
};

const sessionStore = new PgSession({
  pool,
  tableName: sessionTableName,
  createTableIfMissing: true,
  pruneSessionInterval: pruneIntervalSeconds,
  ttl: Math.floor(resolveSessionTtlMs(DEFAULT_SETTINGS.session_duration_days) / 1000),
  errorLog: (...args) => {
    const nowIso = new Date().toISOString();
    const message = normalizeSessionHealthError(args
      .map((item) => (item && item.message ? item.message : String(item)))
      .join(' | '));
    sessionHealthState.ok = false;
    sessionHealthState.lastCheckedAt = nowIso;
    sessionHealthState.lastErrorAt = nowIso;
    sessionHealthState.lastError = message;
    sessionHealthState.failures += 1;
    pushRuntimeErrorEvent('session', 'store_error', message);
    console.error('SESSION_STORE_ERROR', ...args);
    logSessionHealth('store_error', { error: message });
  },
});

const sessionMiddleware = session({
  name: sessionCookieName,
  store: sessionStore,
  secret: resolvedSessionSecret,
  resave: false,
  saveUninitialized: false,
  rolling: true,
  unset: 'destroy',
  cookie: {
    httpOnly: true,
    sameSite: 'lax',
    secure: isProd,
    maxAge: resolveSessionTtlMs(DEFAULT_SETTINGS.session_duration_days),
  },
});

app.use(sessionMiddleware);

const buildSessionRoleFingerprint = (roles = []) => {
  const normalizedRoles = normalizeRoleList(roles);
  return normalizedRoles.length ? normalizedRoles.join('|') : 'student';
};

const regenerateRequestSession = (req) => new Promise((resolve, reject) => {
  if (!req.session) {
    return reject(new Error('Session is not initialized.'));
  }
  return req.session.regenerate((err) => (err ? reject(err) : resolve()));
});

const saveRequestSession = (req) => new Promise((resolve, reject) => {
  if (!req.session) return resolve();
  return req.session.save((err) => (err ? reject(err) : resolve()));
});

const destroyRequestSession = (req) => new Promise((resolve, reject) => {
  if (!req.session) return resolve();
  return req.session.destroy((err) => (err ? reject(err) : resolve()));
});

const establishAuthenticatedSession = async (req, {
  user,
  role,
  remember = false,
  sessionData = {},
} = {}) => {
  const normalizedUser = user && typeof user === 'object' ? { ...user } : null;
  const normalizedUserId = Number(normalizedUser && normalizedUser.id);
  if (!Number.isInteger(normalizedUserId) || normalizedUserId < 1) {
    throw new Error('Authenticated session requires a valid user id.');
  }
  const safeRole = normalizeRoleKey(role || 'student');
  const existingLang = req.session && req.session.lang ? req.session.lang : null;
  await regenerateRequestSession(req);
  req.session.user = normalizedUser;
  req.session.role = safeRole;
  req.session.roles = normalizeRoleList([safeRole]);
  req.session.role_fingerprint = buildSessionRoleFingerprint(req.session.roles);
  req.session.lang = normalizedUser.language || existingLang || getPreferredLang(req);
  req.session.rememberMe = remember;
  Object.assign(req.session, sessionData);
  applyRememberMe(req, remember);
};

const rotateSessionForRoleChange = async (req, nextRoleKeys = [], nextLegacyRole = 'student') => {
  if (!req.session || !req.session.user) return false;
  const nextRoles = normalizeRoleList(nextRoleKeys);
  const nextFingerprint = buildSessionRoleFingerprint(nextRoles);
  if (!req.session.role_fingerprint || req.session.role_fingerprint === nextFingerprint) {
    req.session.role_fingerprint = nextFingerprint;
    return false;
  }
  const remember = Boolean(req.session.rememberMe);
  const sessionUser = { ...req.session.user };
  const preservedState = {
    adminCourse: Number.isFinite(Number(req.session.adminCourse)) ? Number(req.session.adminCourse) : null,
    viewAs: req.session.viewAs || null,
    viewAsMode: req.session.viewAsMode || null,
    viewAsCourseId: Number.isFinite(Number(req.session.viewAsCourseId)) ? Number(req.session.viewAsCourseId) : null,
    viewAsGroupNumber: Number.isFinite(Number(req.session.viewAsGroupNumber)) ? Number(req.session.viewAsGroupNumber) : null,
    lang: req.session.lang || null,
    last_seen_route: req.session.last_seen_route || null,
    last_seen_at: req.session.last_seen_at || null,
    last_seen_ip: req.session.last_seen_ip || null,
    last_seen_user_agent: req.session.last_seen_user_agent || null,
    session_created_at: req.session.session_created_at || null,
  };
  await regenerateRequestSession(req);
  req.session.user = sessionUser;
  req.session.role = normalizeRoleKey(nextLegacyRole || 'student');
  req.session.roles = nextRoles;
  req.session.role_fingerprint = nextFingerprint;
  Object.entries(preservedState).forEach(([key, value]) => {
    if (value !== null && value !== undefined && value !== '') {
      req.session[key] = value;
    }
  });
  req.session.rememberMe = remember;
  applyRememberMe(req, remember);
  return true;
};

app.use((req, _res, next) => {
  if (req.session && req.session.cookie) {
    if (req.session.rememberMe) {
      req.session.cookie.maxAge = resolveSessionTtlMs(settingsCache.session_duration_days);
    } else {
      req.session.cookie.expires = false;
      req.session.cookie.maxAge = null;
    }
  }
  return next();
});

