async function createAssetFromUpload({ file, userId, courseId = null, name = '', kind = 'attachment' } = {}) {
  if (!file || !file.path || !file.filename) return null;
  const normalizedUserId = Number(userId || 0);
  if (!Number.isInteger(normalizedUserId) || normalizedUserId < 1) return null;
  try {
    const inserted = await db.get(
      `
        INSERT INTO assets
          (user_id, course_id, name, original_name, file_path, mime_type, file_size, kind, created_at, updated_at)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, NOW(), NOW())
        RETURNING id
      `,
      [
        normalizedUserId,
        Number.isInteger(Number(courseId)) && Number(courseId) > 0 ? Number(courseId) : null,
        name ? String(name).trim().slice(0, 160) : null,
        file.originalname ? String(file.originalname).slice(0, 255) : null,
        `/uploads/${file.filename}`,
        file.mimetype ? String(file.mimetype).slice(0, 120) : null,
        Number.isFinite(Number(file.size)) ? Number(file.size) : null,
        String(kind || 'attachment').slice(0, 60),
      ]
    );
    return inserted && inserted.id ? Number(inserted.id) : null;
  } catch (err) {
    if (isDbSchemaCompatibilityError(err)) {
      return null;
    }
    throw err;
  }
}

function unlinkUploadedFiles(files = []) {
  (Array.isArray(files) ? files : []).forEach((file) => {
    if (!file || !file.path) return;
    fs.unlink(file.path, () => {});
  });
}

async function deleteAssetsByIds(rawAssetIds = []) {
  const assetIds = teacherTemplateHelpers.normalizeTemplateAssetIds(rawAssetIds, 64);
  if (!assetIds.length) return;
  try {
    await db.run('DELETE FROM assets WHERE id = ANY(?::int[])', [assetIds]);
  } catch (err) {
    if (!isDbSchemaCompatibilityError(err)) {
      throw err;
    }
  }
}

async function cleanupFailedUploadedAssets({ files = [], assetIds = [] } = {}) {
  await deleteAssetsByIds(assetIds);
  unlinkUploadedFiles(files);
}

async function createAssetsFromUploads({ files = [], userId, courseId = null, kind = 'attachment' } = {}) {
  const uploadedFiles = Array.isArray(files) ? files.filter(Boolean) : [];
  const createdAssetIds = [];
  for (const file of uploadedFiles) {
    const assetId = await createAssetFromUpload({
      file,
      userId,
      courseId,
      kind,
    });
    if (!assetId) {
      const error = new Error('Asset storage unavailable');
      error.code = 'ASSET_STORAGE_UNAVAILABLE';
      error.assetIds = createdAssetIds.slice();
      throw error;
    }
    createdAssetIds.push(assetId);
  }
  return createdAssetIds;
}

async function syncTemplateAssetMap(templateId, userId, rawAssetIds = []) {
  const normalizedTemplateId = Number(templateId || 0);
  const normalizedUserId = Number(userId || 0);
  if (!Number.isInteger(normalizedTemplateId) || normalizedTemplateId < 1) return;
  if (!Number.isInteger(normalizedUserId) || normalizedUserId < 1) return;
  const assetIds = teacherTemplateHelpers.normalizeTemplateAssetIds(rawAssetIds, 48);
  try {
    await db.run('DELETE FROM teacher_template_asset_map WHERE template_id = ?', [normalizedTemplateId]);
    if (!assetIds.length) {
      return;
    }
    const rows = await db.all(
      `
        SELECT id
        FROM assets
        WHERE user_id = ?
          AND id = ANY(?::int[])
      `,
      [normalizedUserId, assetIds]
    );
    const allowedIds = Array.from(new Set((rows || [])
      .map((row) => Number(row.id))
      .filter((value) => Number.isInteger(value) && value > 0)));
    for (let index = 0; index < allowedIds.length; index += 1) {
      await db.run(
        `
          INSERT INTO teacher_template_asset_map (template_id, asset_id, sort_order, created_at)
          VALUES (?, ?, ?, NOW())
        `,
        [normalizedTemplateId, allowedIds[index], index]
      );
    }
  } catch (err) {
    if (!isDbSchemaCompatibilityError(err)) {
      throw err;
    }
  }
}

async function copyTemplateAssetsToHomework(templateId, homeworkIds = [], extraAssetIds = []) {
  const normalizedTemplateId = Number(templateId || 0);
  const normalizedHomeworkIds = Array.from(new Set((homeworkIds || [])
    .map((value) => Number(value))
    .filter((value) => Number.isInteger(value) && value > 0)));
  if (!normalizedHomeworkIds.length) return;
  try {
    let templateAssetIds = [];
    if (Number.isInteger(normalizedTemplateId) && normalizedTemplateId > 0) {
      const rows = await db.all(
        `
          SELECT asset_id
          FROM teacher_template_asset_map
          WHERE template_id = ?
          ORDER BY sort_order ASC, asset_id ASC
        `,
        [normalizedTemplateId]
      );
      templateAssetIds = (rows || [])
        .map((row) => Number(row.asset_id))
        .filter((value) => Number.isInteger(value) && value > 0);
    }
    const assetIds = teacherTemplateHelpers.buildAppliedHomeworkAssetIds({
      templateAssetIds,
      uploadedAssetIds: extraAssetIds,
    });
    if (!assetIds.length) return;
    for (const homeworkId of normalizedHomeworkIds) {
      await db.run('DELETE FROM homework_asset_map WHERE homework_id = ?', [homeworkId]);
      for (let index = 0; index < assetIds.length; index += 1) {
        await db.run(
          `
            INSERT INTO homework_asset_map (homework_id, asset_id, sort_order, created_at)
            VALUES (?, ?, ?, NOW())
            ON CONFLICT (homework_id, asset_id) DO NOTHING
          `,
          [homeworkId, assetIds[index], index]
        );
      }
    }
  } catch (err) {
    if (!isDbSchemaCompatibilityError(err)) {
      throw err;
    }
  }
}

async function resolveTeacherTemplateScope(userId, requestedCourseIdRaw, requestedSubjectIdRaw) {
  const requestedCourseId = Number(requestedCourseIdRaw);
  const requestedSubjectId = Number(requestedSubjectIdRaw);
  let resolvedSubject = null;
  if (Number.isInteger(requestedSubjectId) && requestedSubjectId > 0) {
    resolvedSubject = await db.get(
      `
        SELECT s.id, s.course_id AS owner_course_id
        FROM teacher_subjects ts
        JOIN subjects s ON s.id = ts.subject_id
        WHERE ts.user_id = ? AND ts.subject_id = ?
        LIMIT 1
      `,
      [userId, requestedSubjectId]
    );
    if (!resolvedSubject) {
      return { ok: false, error: 'Invalid%20subject' };
    }
  }

  let validatedCourseId = null;
  if (Number.isInteger(requestedCourseId) && requestedCourseId > 0) {
    let hasCourseAccess = null;
    try {
      hasCourseAccess = await db.get(
        `
          SELECT 1
          FROM teacher_subjects ts
          JOIN subject_course_bindings scb ON scb.subject_id = ts.subject_id
          WHERE ts.user_id = ? AND scb.course_id = ?
          LIMIT 1
        `,
        [userId, requestedCourseId]
      );
    } catch (err) {
      if (!isDbSchemaCompatibilityError(err)) {
        throw err;
      }
      hasCourseAccess = await db.get(
        `
          SELECT 1
          FROM teacher_subjects ts
          JOIN subjects s ON s.id = ts.subject_id
          WHERE ts.user_id = ? AND s.course_id = ?
          LIMIT 1
        `,
        [userId, requestedCourseId]
      );
    }
    if (!hasCourseAccess) {
      return { ok: false, error: 'Invalid%20course' };
    }
    validatedCourseId = requestedCourseId;
  }

  if (
    resolvedSubject
    && validatedCourseId
  ) {
    const boundSubject = await getSubjectForCourse(resolvedSubject.id, validatedCourseId, { includeHidden: true });
    if (!boundSubject) {
      return { ok: false, error: 'Subject%20does%20not%20match%20course' };
    }
  }

  const courseId = resolvedSubject
    ? (validatedCourseId || Number(resolvedSubject.owner_course_id || 0) || null)
    : (validatedCourseId || null);
  const subjectId = resolvedSubject ? Number(resolvedSubject.id) : null;
  return {
    ok: true,
    courseId,
    subjectId,
    validatedCourseId,
  };
}

function normalizeHomeworkTemplateTitleInput(rawTitle, fallbackDescription, fallbackSubjectName) {
  return teacherTemplateHelpers.normalizeHomeworkTemplateTitleInput(
    rawTitle,
    fallbackDescription,
    fallbackSubjectName
  );
}

async function maybeCreateTeacherTemplateFromHomework(req, payload = {}) {
  if (!req || !hasSessionRole(req, 'teacher')) {
    return null;
  }
  const shouldSave = ['1', 'true', 'on', 'yes'].includes(String((req.body && req.body.save_as_template) || '').toLowerCase());
  if (!shouldSave) {
    return null;
  }

  const userId = Number(payload.userId || req.session?.user?.id);
  const requestedCourseId = Number(payload.courseId);
  const requestedSubjectId = Number(payload.subjectId);
  const description = String(payload.description || '').trim();
  if (!Number.isInteger(userId) || userId < 1 || !Number.isInteger(requestedSubjectId) || requestedSubjectId < 1 || !description) {
    return null;
  }

  const title = normalizeHomeworkTemplateTitleInput(
    payload.title || (req.body && req.body.template_title),
    description,
    payload.subjectName
  );
  const tags = normalizeTemplateTagsInput(payload.tags).join(', ');
  const linkUrl = normalizeExternalUrl(payload.linkUrl) || null;
  const meetingUrl = normalizeExternalUrl(payload.meetingUrl) || null;
  const isControl = Number(payload.isControl) === 1 ? 1 : 0;
  const isCredit = Number(payload.isCredit) === 1 ? 1 : 0;

  try {
    const resolvedScope = await resolveTeacherTemplateScope(userId, requestedCourseId, requestedSubjectId);
    if (!resolvedScope.ok || !resolvedScope.subjectId) {
      return null;
    }
    const courseId = resolvedScope.courseId || null;
    const subjectId = resolvedScope.subjectId || null;
    const inserted = await db.get(
      `
        INSERT INTO teacher_homework_templates
          (course_id, subject_id, user_id, title, description, link_url, meeting_url, tags, is_control, is_credit, created_at, updated_at)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, NOW(), NOW())
        RETURNING id
      `,
      [
        courseId,
        subjectId,
        userId,
        title,
        description,
        linkUrl,
        meetingUrl,
        tags,
        isControl,
        isCredit,
      ]
    );
    const templateId = inserted && inserted.id ? Number(inserted.id) : null;
    if (templateId) {
      const selectedAssetIds = teacherTemplateHelpers.normalizeTemplateAssetIds(req.body && req.body.asset_ids, 48);
      let uploadedAssetIds = teacherTemplateHelpers.normalizeTemplateAssetIds(payload.uploadedAssetIds, 16);
      if (!uploadedAssetIds.length && req.file) {
        let uploadedAssetId = null;
        uploadedAssetId = await createAssetFromUpload({
          file: req.file,
          userId,
          courseId,
          name: payload.title || (req.body && req.body.template_title) || title,
          kind: 'template_capture',
        });
        uploadedAssetIds = uploadedAssetId ? [uploadedAssetId] : [];
      }
      await syncTemplateAssetMap(
        templateId,
        userId,
        teacherTemplateHelpers.buildAppliedHomeworkAssetIds({
          templateAssetIds: selectedAssetIds,
          uploadedAssetIds,
        })
      );
    }
    logAction(db, req, 'teacher_homework_template_create', {
      template_id: templateId,
      title,
      course_id: courseId,
      subject_id: subjectId,
      tags: tags ? tags.split(',').map((item) => item.trim()).filter(Boolean) : [],
      is_control: isControl,
      is_credit: isCredit,
      source: String(payload.source || 'homework_form'),
    });
    return templateId;
  } catch (err) {
    console.error('Teacher homework template auto-save failed', err);
    return null;
  }
}

async function upsertTeacherRequestStatus(userId, options = {}) {
  const normalizedUserId = parsePositiveIntStrict(userId);
  if (!normalizedUserId) {
    return 'pending';
  }
  const allowPendingReset = options.allowPendingReset === true;
  const existing = await db.get('SELECT status FROM teacher_requests WHERE user_id = ?', [normalizedUserId]);
  let nextStatus = existing ? String(existing.status || 'pending') : 'pending';
  if (nextStatus === 'rejected') {
    nextStatus = 'pending';
  }
  if (existing) {
    if (nextStatus !== 'approved' || allowPendingReset) {
      await db.run(
        'UPDATE teacher_requests SET status = ?, updated_at = NOW() WHERE user_id = ?',
        [nextStatus, normalizedUserId]
      );
    } else {
      await db.run('UPDATE teacher_requests SET updated_at = NOW() WHERE user_id = ?', [normalizedUserId]);
    }
  } else {
    await db.run(
      'INSERT INTO teacher_requests (user_id, status) VALUES (?, ?)',
      [normalizedUserId, nextStatus]
    );
  }
  return nextStatus;
}

function extractTeacherOfferingSelectionIds(body = {}) {
  const selectionMode = String(body.selection_mode || '').trim().toLowerCase();
  const directIds = Array.from(new Set(
    (Array.isArray(body.offering_ids) ? body.offering_ids : [body.offering_ids])
      .map((value) => parsePositiveIntStrict(value))
      .filter((value) => Number.isInteger(value) && value > 0)
  ));
  const legacyStyledIds = selectionMode === 'offering'
    ? Object.keys(body || {})
      .map((key) => {
        const match = key.match(/^subject_(\d+)$/);
        if (!match) return null;
        const isSelected = ['1', 'true', 'on', 'yes'].includes(String(body[key] || '').trim().toLowerCase());
        return isSelected ? parsePositiveIntStrict(match[1]) : null;
      })
      .filter((value) => Number.isInteger(value) && value > 0)
    : [];
  const keyedIds = Object.keys(body || {})
    .map((key) => {
      const match = key.match(/^offering_(\d+)$/);
      if (!match) return null;
      const isSelected = ['1', 'true', 'on', 'yes'].includes(String(body[key] || '').trim().toLowerCase());
      return isSelected ? parsePositiveIntStrict(match[1]) : null;
    })
    .filter((value) => Number.isInteger(value) && value > 0);
  return Array.from(new Set([...directIds, ...legacyStyledIds, ...keyedIds]));
}

async function saveTeacherOfferingSelections(userId, body, options = {}) {
  const offeringCatalog = await listTeacherOfferingCatalog();
  const selectedOfferingIds = extractTeacherOfferingSelectionIds(body);
  if (!selectedOfferingIds.length) {
    return { ok: false, error: 'Select%20subject' };
  }
  if (!offeringCatalog.length) {
    return { ok: false, error: 'Offering%20catalog%20is%20not%20ready' };
  }

  const offeringsById = new Map(
    (offeringCatalog || [])
      .map((item) => [Number(item.id || 0), item])
      .filter((entry) => Number.isInteger(entry[0]) && entry[0] > 0)
  );
  const selections = [];
  for (const offeringId of selectedOfferingIds) {
    const offering = offeringsById.get(offeringId);
    if (!offering || !parsePositiveIntStrict(offering.legacy_subject_id)) {
      return { ok: false, error: 'Offering%20not%20ready' };
    }
    const isGeneral = offering.is_general === true || Number(offering.is_general) === 1;
    let groupNumber = null;
    if (!isGeneral) {
      const rawGroupValue = body[`group_offering_${offeringId}`] ?? body[`group_${offeringId}`];
      const parsedGroupNumber = parsePositiveIntStrict(rawGroupValue);
      if (!parsedGroupNumber || parsedGroupNumber > Number(offering.group_count || 1)) {
        return { ok: false, error: 'Select%20group' };
      }
      groupNumber = parsedGroupNumber;
    }
    selections.push({
      subject_id: parsePositiveIntStrict(offering.legacy_subject_id),
      subject_offering_id: offeringId,
      group_number: groupNumber,
    });
  }

  await db.run('DELETE FROM teacher_subjects WHERE user_id = ?', [userId]);
  for (const item of selections) {
    await db.run(
      'INSERT INTO teacher_subjects (user_id, subject_id, group_number) VALUES (?, ?, ?)',
      [userId, item.subject_id, item.group_number]
    );
  }
  const nextStatus = await upsertTeacherRequestStatus(userId, options);
  const academicAssignments = await syncTeacherAcademicAssignments(
    userId,
    selections.map((item) => ({
      subject_id: item.subject_id,
      group_number: item.group_number,
    }))
  );
  return {
    ok: true,
    status: nextStatus,
    selections,
    academicAssignments,
  };
}

async function saveTeacherSubjects(userId, body, options = {}) {
  const selectionMode = String(body && body.selection_mode || '').trim().toLowerCase();
  const offeringIds = extractTeacherOfferingSelectionIds(body);
  if (selectionMode === 'offering' || offeringIds.length) {
    return saveTeacherOfferingSelections(userId, body, options);
  }
  const catalog = await getTeacherSubjectCatalog();
  const selections = [];
  let hasAny = false;
  for (const subject of catalog) {
    const selected = body[`subject_${subject.id}`];
    if (!selected) {
      continue;
    }
    hasAny = true;
    const isGeneral = subject.is_general === true || Number(subject.is_general) === 1;
    if (isGeneral) {
      selections.push({ subject_id: subject.id, group_number: null });
      continue;
    }
    const groupVal = body[`group_${subject.id}`];
    const groupNum = Number(groupVal);
    if (!groupVal || Number.isNaN(groupNum) || groupNum < 1 || groupNum > Number(subject.group_count || 1)) {
      return { ok: false, error: 'Select%20group' };
    }
    selections.push({ subject_id: subject.id, group_number: groupNum });
  }
  if (!hasAny) {
    return { ok: false, error: 'Select%20subject' };
  }
  await db.run('DELETE FROM teacher_subjects WHERE user_id = ?', [userId]);
  for (const item of selections) {
    await db.run(
      'INSERT INTO teacher_subjects (user_id, subject_id, group_number) VALUES (?, ?, ?)',
      [userId, item.subject_id, item.group_number]
    );
  }
  const nextStatus = await upsertTeacherRequestStatus(userId, options);
  const academicAssignments = await syncTeacherAcademicAssignments(userId, selections);
  return { ok: true, status: nextStatus, selections, academicAssignments };
}

function broadcast(type, payload, options = {}) {
  const message = JSON.stringify({ type, payload });
  const targetChannels = new Set(resolveBroadcastChannels(type, options.channels));
  wss.clients.forEach((client) => {
    if (client.readyState === 1 && targetChannels.has(normalizeSocketChannel(client.studerriaChannel))) {
      client.send(message);
    }
  });
}

function sortSchedule(schedule, sortKey) {
  if (!sortKey) return schedule;
  const copy = [...schedule];
  if (sortKey === 'day') {
    const order = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday'];
    copy.sort(
      (a, b) =>
        order.indexOf(a.day_of_week) - order.indexOf(b.day_of_week) || a.class_number - b.class_number
    );
  } else if (sortKey === 'time') {
    copy.sort((a, b) => a.class_number - b.class_number);
  } else if (sortKey === 'group') {
    copy.sort((a, b) => a.group_number - b.group_number || a.day_of_week.localeCompare(b.day_of_week));
  }
  return copy;
}

function sortHomework(homework, sortKey) {
  const normalized = (Array.isArray(homework) ? homework : []).map((item) => (
    item && item.file_name
      ? { ...item, file_name: normalizeUploadedOriginalName(item.file_name) }
      : item
  ));
  if (!sortKey) return normalized;
  const copy = [...normalized];
  if (sortKey === 'created') {
    copy.sort((a, b) => (a.created_at < b.created_at ? 1 : -1));
  } else if (sortKey === 'subject') {
    copy.sort((a, b) => a.subject.localeCompare(b.subject));
  }
  return copy;
}

