async function insertSupportRequestMessage({
  requestId,
  authorUserId = null,
  authorRole = 'user',
  body = '',
}) {
  const normalizedRequestId = Number(requestId || 0);
  const normalizedAuthorUserId = Number(authorUserId || 0);
  const normalizedBody = String(body || '')
    .replace(/\r\n/g, '\n')
    .trim();
  if (!Number.isInteger(normalizedRequestId) || normalizedRequestId < 1 || !normalizedBody) {
    return false;
  }
  try {
    await db.run(
      `
        INSERT INTO support_request_messages (request_id, author_user_id, author_role, body)
        VALUES (?, ?, ?, ?)
      `,
      [
        normalizedRequestId,
        Number.isInteger(normalizedAuthorUserId) && normalizedAuthorUserId > 0 ? normalizedAuthorUserId : null,
        normalizeSupportRequestMessageRole(authorRole),
        normalizedBody,
      ]
    );
    return true;
  } catch (err) {
    if (isDbSchemaCompatibilityError(err)) {
      return false;
    }
    throw err;
  }
}

async function listSupportRequestMessages(requestId) {
  const normalizedRequestId = Number(requestId || 0);
  if (!Number.isInteger(normalizedRequestId) || normalizedRequestId < 1) {
    return [];
  }
  try {
    return await db.all(
      `
        SELECT
          srm.id,
          srm.request_id,
          srm.author_user_id,
          srm.author_role,
          srm.body,
          srm.created_at,
          COALESCE(u.full_name, CASE WHEN srm.author_role = 'admin' THEN 'Admin' ELSE 'User' END) AS author_name
        FROM support_request_messages srm
        LEFT JOIN users u ON u.id = srm.author_user_id
        WHERE srm.request_id = ?
        ORDER BY srm.created_at ASC, srm.id ASC
      `,
      [normalizedRequestId]
    );
  } catch (err) {
    if (isDbSchemaCompatibilityError(err)) {
      return [];
    }
    throw err;
  }
}

async function listSupportRequestsForUser(userId, limit = 12) {
  if (!Number.isFinite(Number(userId))) {
    return [];
  }
  const safeLimit = Math.min(Math.max(Number(limit) || 12, 1), 50);
  return db.all(
    `
      SELECT sr.*
      FROM support_requests sr
      WHERE sr.user_id = ?
      ORDER BY sr.updated_at DESC, sr.created_at DESC
      LIMIT ${safeLimit}
    `,
    [userId]
  );
}

async function listSupportRequestsForCourse(courseId, limit = 40) {
  if (!Number.isFinite(Number(courseId))) {
    return [];
  }
  const safeLimit = Math.min(Math.max(Number(limit) || 40, 1), 120);
  return db.all(
    `
      SELECT sr.*, u.full_name AS user_name
      FROM support_requests sr
      JOIN users u ON u.id = sr.user_id
      WHERE sr.course_id = ?
      ORDER BY sr.updated_at DESC, sr.created_at DESC
      LIMIT ${safeLimit}
    `,
    [courseId]
  );
}

async function getSupportRequestForUser(requestId, userId) {
  const normalizedRequestId = Number(requestId || 0);
  const normalizedUserId = Number(userId || 0);
  if (!Number.isInteger(normalizedRequestId) || normalizedRequestId < 1) {
    return null;
  }
  if (!Number.isInteger(normalizedUserId) || normalizedUserId < 1) {
    return null;
  }
  return db.get(
    `
      SELECT id, user_id, status
      FROM support_requests
      WHERE id = ?
        AND user_id = ?
      LIMIT 1
    `,
    [normalizedRequestId, normalizedUserId]
  );
}

async function getSupportRequestThreadForCourse(requestId, courseId) {
  const normalizedRequestId = Number(requestId || 0);
  const normalizedCourseId = Number(courseId || 0);
  if (!Number.isInteger(normalizedRequestId) || normalizedRequestId < 1) {
    return null;
  }
  const row = await db.get(
    `
      SELECT
        sr.*,
        u.full_name AS user_name,
        resolver.full_name AS resolved_by_name
      FROM support_requests sr
      JOIN users u ON u.id = sr.user_id
      LEFT JOIN users resolver ON resolver.id = sr.resolved_by
      WHERE sr.id = ?
        ${Number.isInteger(normalizedCourseId) && normalizedCourseId > 0 ? 'AND sr.course_id = ?' : ''}
      LIMIT 1
    `,
    Number.isInteger(normalizedCourseId) && normalizedCourseId > 0
      ? [normalizedRequestId, normalizedCourseId]
      : [normalizedRequestId]
  );
  if (!row) {
    return null;
  }
  const messages = await listSupportRequestMessages(normalizedRequestId);
  return {
    ...row,
    messages: messages.length ? messages : buildSupportRequestFallbackMessages(row),
  };
}

async function attachVisibleMessageReactions(rows, userId) {
  const items = Array.isArray(rows) ? rows : [];
  const normalizedUserId = Number(userId || 0);
  if (!items.length || !Number.isInteger(normalizedUserId) || normalizedUserId < 1) {
    return items;
  }

  const messageIds = items
    .map((row) => Number(row.id || 0))
    .filter((value) => Number.isInteger(value) && value > 0);
  if (!messageIds.length) {
    return items;
  }

  const placeholders = messageIds.map(() => '?').join(',');
  const reactionRows = await db.all(
    `
      SELECT message_id, emoji, COUNT(*) AS count
      FROM message_reactions
      WHERE message_id IN (${placeholders})
      GROUP BY message_id, emoji
    `,
    messageIds
  );
  const myReactionRows = await db.all(
    `
      SELECT message_id, emoji
      FROM message_reactions
      WHERE message_id IN (${placeholders}) AND user_id = ?
    `,
    [...messageIds, normalizedUserId]
  );

  const reactionMap = {};
  (reactionRows || []).forEach((row) => {
    if (!reactionMap[row.message_id]) reactionMap[row.message_id] = {};
    reactionMap[row.message_id][row.emoji] = Number(row.count || 0);
  });

  const reactedMap = {};
  (myReactionRows || []).forEach((row) => {
    if (!reactedMap[row.message_id]) reactedMap[row.message_id] = {};
    reactedMap[row.message_id][row.emoji] = true;
  });

  return items.map((row) => ({
    ...row,
    reactions: reactionMap[row.id] || {},
    reacted: reactedMap[row.id] || {},
  }));
}

async function listVisibleMessagesForUser({
  userId,
  courseId,
  activeSemester = null,
  subjectId = null,
  limit = 50,
  includeReactions = false,
  staleDays = 30,
  lang = 'uk',
} = {}) {
  const normalizedUserId = Number(userId || 0);
  const normalizedCourseId = Number(courseId || 0) || 1;
  const normalizedSubjectId = Number(subjectId || 0);
  const hasSubjectFilter = Number.isInteger(normalizedSubjectId) && normalizedSubjectId > 0;
  const normalizedSemesterId = Number(activeSemester && activeSemester.id ? activeSemester.id : activeSemester || 0);
  const safeLimit = Math.min(Math.max(Number(limit) || 50, 1), 50);

  if (!Number.isInteger(normalizedUserId) || normalizedUserId < 1) {
    return { messages: [], unread_count: 0 };
  }

  const groups = await db.all(
    `
      SELECT sg.subject_id, sg.group_number
      FROM student_groups sg
      JOIN subjects s ON s.id = sg.subject_id
      WHERE sg.student_id = ? AND s.course_id = ?
    `,
    [normalizedUserId, normalizedCourseId]
  );

  const conditions = ['m.target_all = 1'];
  const conditionParams = [];
  if (groups.length) {
    const groupConditions = groups.map(() => '(m.subject_id = ? AND m.group_number = ?)').join(' OR ');
    groups.forEach((groupRow) => conditionParams.push(groupRow.subject_id, groupRow.group_number));
    conditions.push(groupConditions);
  }
  conditions.push('EXISTS (SELECT 1 FROM message_targets mt WHERE mt.message_id = m.id AND mt.user_id = ?)');
  conditionParams.push(normalizedUserId);

  const baseWhere = conditions.length ? `WHERE ${conditions.map((condition) => `(${condition})`).join(' OR ')}` : '';
  const globalBroadcastScope = '(m.target_all = 1 AND m.subject_id IS NULL AND m.group_number IS NULL)';
  const courseFilter = ` AND (m.course_id = ? OR (${globalBroadcastScope} AND m.course_id IS NULL))`;
  const semesterFilter = normalizedSemesterId > 0
    ? ` AND (m.semester_id = ? OR (${globalBroadcastScope} AND m.semester_id IS NULL))`
    : '';
  const statusFilter = ` AND COALESCE(m.status, 'published') = 'published' AND ${buildScheduledAtVisibleCondition('m.scheduled_at')}`;
  const subjectFilter = hasSubjectFilter ? ' AND m.subject_id = ?' : '';

  let rows = await db.all(
    `
      SELECT
        m.*,
        s.name AS subject_name,
        u.full_name AS created_by,
        mr.id AS read_id,
        CASE
          WHEN EXISTS (
            SELECT 1
            FROM message_targets mt2
            WHERE mt2.message_id = m.id AND mt2.user_id = ?
          ) THEN 1
          ELSE 0
        END AS is_direct_target
      FROM messages m
      LEFT JOIN subjects s ON s.id = m.subject_id
      LEFT JOIN users u ON u.id = m.created_by_id
      LEFT JOIN message_reads mr ON mr.message_id = m.id AND mr.user_id = ?
      ${baseWhere}${courseFilter}${semesterFilter}${subjectFilter}${statusFilter}
      ORDER BY COALESCE(m.published_at, m.created_at) DESC, m.id DESC
      LIMIT ${safeLimit}
    `,
    [
      normalizedUserId,
      normalizedUserId,
      ...conditionParams,
      normalizedCourseId,
      ...(normalizedSemesterId > 0 ? [normalizedSemesterId] : []),
      ...(hasSubjectFilter ? [normalizedSubjectId] : []),
      new Date().toISOString(),
    ]
  );

  if ((rows || []).length) {
    try {
      const messageIds = Array.from(new Set(
        rows
          .map((row) => Number(row.id || 0))
          .filter((value) => Number.isInteger(value) && value > 0)
      ));
      if (messageIds.length) {
        const snapshotRows = await db.all(
          `
            SELECT
              rps.*,
              u.full_name AS published_by_name
            FROM rating_publication_snapshots rps
            LEFT JOIN users u ON u.id = rps.published_by
            WHERE rps.message_id = ANY(?::int[])
            ORDER BY rps.published_at DESC, rps.id DESC
          `,
          [messageIds]
        );
        const snapshotMap = new Map();
        (snapshotRows || []).forEach((row) => {
          const messageId = Number(row.message_id || 0);
          if (!messageId || snapshotMap.has(messageId)) return;
          snapshotMap.set(messageId, row);
        });
        rows = rows.map((row) => ({
          ...row,
          rating_snapshot: snapshotMap.get(Number(row.id || 0)) || null,
        }));
      }
    } catch (err) {
      if (!isDbSchemaCompatibilityError(err)) {
        throw err;
      }
    }
  }

  rows = (rows || []).map((row) => messageHelpers.buildVisibleMessagePreview(row, {
    staleDays,
    lang,
  }));
  if (includeReactions && rows.length) {
    rows = await attachVisibleMessageReactions(rows, normalizedUserId);
  }

  return {
    messages: rows,
    unread_count: rows.filter((row) => !row.read_id).length,
  };
}

