app.get('/help', requireLogin, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'help.v2.init');
  }

  try {
    const lang = getPreferredLang(req);
    const helpPage = supportHelpers.buildHelpPageExperienceContent(lang);
    const courseId = hasSessionRole(req, 'admin')
      ? getAdminCourse(req)
      : Number(req.session.user.course_id || 1);
    const activeSemester = await getActiveSemester(courseId || 1);
    const supportRows = await listSupportRequestsForUser(req.session.user.id, 12);
    const supportRequests = await Promise.all((supportRows || []).map(async (row) => {
      const messages = await listSupportRequestMessages(row.id);
      return supportHelpers.buildSupportRequestPreview(row, messages);
    }));
    const supportStats = supportHelpers.summarizeSupportRequests(supportRequests, {
      responseLabel: lang === 'uk' ? 'до 1 робочого дня' : 'within 1 business day',
    });
    let inboxFeed = [];
    let inboxSummary = null;
    if (settingsCache.allow_messages) {
      try {
        const visibleMessages = await listVisibleMessagesForUser({
          userId: req.session.user.id,
          courseId: courseId || 1,
          activeSemester,
          limit: 8,
          staleDays: 45,
          lang,
        });
        inboxFeed = (visibleMessages.messages || [])
          .filter((item) => !item.is_stale || !item.read_id)
          .slice(0, 6);
        inboxSummary = messageHelpers.summarizeVisibleMessages(visibleMessages.messages, {
          staleDays: 45,
          lang,
        });
      } catch (err) {
        if (!isDbSchemaCompatibilityError(err)) {
          throw err;
        }
      }
    }

    const decodeMessage = (value) => {
      if (!value) return '';
      try {
        return decodeURIComponent(String(value));
      } catch (_err) {
        return String(value);
      }
    };

    return res.render('help', {
      helpPage,
      supportRequests,
      supportStats,
      inboxFeed,
      inboxSummary,
      announcementFeed: inboxFeed,
      announcementSummary: inboxSummary,
      showInboxDigest: Boolean(settingsCache.allow_messages),
      showAnnouncementDigest: Boolean(settingsCache.allow_messages),
      supportCategoryOptions: SUPPORT_REQUEST_CATEGORIES,
      messages: {
        error: decodeMessage(req.query.err),
        success: decodeMessage(req.query.ok),
      },
    });
  } catch (err) {
    return handleDbError(res, err, 'help.v2');
  }
});

app.post('/help/support/:id/reply', requireLogin, writeLimiter, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'help.support.reply.init');
  }

  const lang = getPreferredLang(req);
  const requestId = Number(req.params.id || 0);
  const replyBody = String(req.body.body || '')
    .replace(/\r\n/g, '\n')
    .trim();

  if (!Number.isInteger(requestId) || requestId < 1 || replyBody.length < 2 || replyBody.length > 2000) {
    return res.redirect(`/help?err=${encodeURIComponent(lang === 'uk' ? 'Перевірте текст відповіді' : 'Check the reply text')}`);
  }

  try {
    const supportRequest = await getSupportRequestForUser(requestId, req.session.user.id);
    if (!supportRequest) {
      return res.redirect(`/help?err=${encodeURIComponent(translate(lang, 'help.flash.requestMissing'))}`);
    }

    await insertSupportRequestMessage({
      requestId,
      authorUserId: req.session.user.id,
      authorRole: 'user',
      body: replyBody,
    });
    await db.run(
      `
        UPDATE support_requests
        SET
          status = 'in_progress',
          updated_at = NOW(),
          resolved_at = NULL,
          resolved_by = NULL
        WHERE id = ?
      `,
      [requestId]
    );

    logAction(db, req, 'support_request_reply', {
      request_id: requestId,
    });
    return res.redirect(`/help?ok=${encodeURIComponent(lang === 'uk' ? 'Відповідь додано' : 'Reply sent')}`);
  } catch (err) {
    if (isDbSchemaCompatibilityError(err)) {
      return res.redirect(`/help?err=${encodeURIComponent(lang === 'uk' ? 'Потік підтримки недоступний у цій схемі БД' : 'Support thread storage is unavailable in this DB schema')}`);
    }
    return handleDbError(res, err, 'help.support.reply');
  }
});

app.post('/help/support/:id/close', requireLogin, writeLimiter, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'help.support.close.init');
  }

  const lang = getPreferredLang(req);
  const requestId = Number(req.params.id || 0);
  if (!Number.isInteger(requestId) || requestId < 1) {
    return res.redirect(`/help?err=${encodeURIComponent(translate(lang, 'help.flash.requestMissing'))}`);
  }

  try {
    const supportRequest = await getSupportRequestForUser(requestId, req.session.user.id);
    if (!supportRequest) {
      return res.redirect(`/help?err=${encodeURIComponent(translate(lang, 'help.flash.requestMissing'))}`);
    }
    if (normalizeSupportRequestStatus(supportRequest.status) === 'resolved') {
      return res.redirect(`/help?ok=${encodeURIComponent(translate(lang, 'help.flash.requestAlreadyClosed'))}`);
    }

    await db.run(
      `
        UPDATE support_requests
        SET
          status = 'resolved',
          updated_at = NOW(),
          resolved_at = NOW(),
          resolved_by = NULL
        WHERE id = ?
      `,
      [requestId]
    );

    logAction(db, req, 'support_request_close', {
      request_id: requestId,
      closed_by: 'user',
    });
    return res.redirect(`/help?ok=${encodeURIComponent(translate(lang, 'help.flash.requestClosed'))}`);
  } catch (err) {
    return handleDbError(res, err, 'help.support.close');
  }
});

app.post('/help/support', requireLogin, writeLimiter, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'help.support.init');
  }

  const lang = getPreferredLang(req);
  const category = normalizeSupportRequestCategory(req.body.topic);
  const subject = String(req.body.subject || '')
    .replace(/\s+/g, ' ')
    .trim();
  const body = String(req.body.body || '')
    .replace(/\r\n/g, '\n')
    .trim();

  if (subject.length < 4 || subject.length > 120 || body.length < 12 || body.length > 2000) {
    return res.redirect(`/help?err=${encodeURIComponent(translate(lang, 'help.flash.validationError'))}`);
  }

  try {
    const courseId = Number(req.session.user.course_id || 0);
    const createdRequest = await db.get(
      `
        INSERT INTO support_requests (user_id, course_id, category, subject, body)
        VALUES (?, ?, ?, ?, ?)
        RETURNING id
      `,
      [
        req.session.user.id,
        Number.isFinite(courseId) && courseId > 0 ? courseId : null,
        category,
        subject,
        body,
      ]
    );
    if (createdRequest && createdRequest.id) {
      await insertSupportRequestMessage({
        requestId: createdRequest.id,
        authorUserId: req.session.user.id,
        authorRole: 'user',
        body,
      });
    }
    return res.redirect(`/help?ok=${encodeURIComponent(translate(lang, 'help.flash.requestCreated'))}`);
  } catch (err) {
    return handleDbError(res, err, 'help.support.create');
  }
});

