app.post('/register', registerLimiter, async (req, res) => {
  const full_name = String(req.body.full_name || '').trim();
  const password = String(req.body.password || '');
  const confirm_password = String(req.body.confirm_password || '');
  const agreeValue = String(req.body.agree || '').trim().toLowerCase();
  const remember_me = req.body.remember_me;
  const hasConsent = agreeValue === 'on' || agreeValue === '1' || agreeValue === 'true';
  const redirectRegisterError = (code) =>
    res.redirect(`/register?error=${encodeURIComponent(String(code || 'db-error'))}`);

  if (!full_name) return redirectRegisterError('missing-name');
  if (!password) return redirectRegisterError('missing-password');
  if (password.length < 4) return redirectRegisterError('short-password');
  if (!confirm_password) return redirectRegisterError('missing-confirm-password');
  if (password !== confirm_password) return redirectRegisterError('password-mismatch');
  if (!hasConsent) return redirectRegisterError('consent-required');

  const normalizedName = full_name.replace(/\s+/g, ' ');
  const pendingUserId = Number(req.session.pendingUserId || 0);
  if (Number.isInteger(pendingUserId) && pendingUserId > 0) {
    try {
      await ensureDbReady();
      const hash = await bcrypt.hash(password, 10);
      const preferredLang = getPreferredLang(req);
      await db.run(
        `
          UPDATE users
          SET full_name = ?, password_hash = ?, language = COALESCE(language, ?)
          WHERE id = ?
        `,
        [normalizedName, hash, preferredLang, pendingUserId]
      );
      req.session.rememberMe = isRememberRequested(remember_me);
      return res.redirect('/register/course');
    } catch (err) {
      console.error('Register pending update failed', err);
      return redirectRegisterError('db-error');
    }
  }

  try {
    await ensureDbReady();
    const existing = await db.get('SELECT id FROM users WHERE LOWER(full_name) = LOWER(?)', [normalizedName]);
    if (existing) {
      return redirectRegisterError('user-exists');
    }
    const hash = await bcrypt.hash(password, 10);
    const preferredLang = getPreferredLang(req);
    const row = await db.get(
      'INSERT INTO users (full_name, role, password_hash, is_active, schedule_group, course_id, language) VALUES (?, ?, ?, ?, ?, ?, ?) RETURNING id',
      [normalizedName, 'student', hash, 1, 'A', null, preferredLang]
    );
    if (!row || !row.id) {
      return redirectRegisterError('db-error');
    }
    let registrationSignals = null;
    try {
      registrationSignals = await recordUserRegistrationEvent({
        userId: row.id,
        fullName: normalizedName,
        ip: getClientIp(req),
        userAgent: req.headers['user-agent'] || null,
        sessionId: req.sessionID || null,
        source: 'register_form',
        courseId: null,
      });
    } catch (eventErr) {
      console.error('Database error (register.registration_event)', eventErr);
    }
    try {
      const signalRisk = registrationSignals && registrationSignals.security && registrationSignals.security.risk
        ? registrationSignals.security.risk
        : null;
      const securityCase = await recomputeUserSecurityCase(row.id, {
        allowAutoQuarantine: true,
        courseId: null,
        extraScore: Number(signalRisk && signalRisk.score ? signalRisk.score : 0),
        extraReasons: Array.isArray(signalRisk && signalRisk.reasons ? signalRisk.reasons : [])
          ? signalRisk.reasons
          : [],
      });
      const isQuarantined = securityCase
        && securityCase.case
        && (securityCase.case.auto_quarantined === true || Number(securityCase.case.auto_quarantined) === 1);
      if (isQuarantined) {
        logAction(db, req, 'register_quarantined', { user_id: row.id, full_name: normalizedName });
        req.session.pendingUserId = null;
        req.session.rememberMe = false;
        return res.redirect('/login?error=Account%20pending%20review');
      }
    } catch (securityErr) {
      console.error('Database error (register.security_case)', securityErr);
    }
    req.session.pendingUserId = row.id;
    req.session.rememberMe = isRememberRequested(remember_me);
    logAction(db, req, 'register_user', { user_id: row.id, full_name: normalizedName });
    broadcast('users_updated');
    return res.redirect('/register/course');
  } catch (err) {
    console.error('Register failed', err);
    return redirectRegisterError('db-error');
  }
});

app.get('/register/course', async (req, res) => {
  if (!req.session.pendingUserId) {
    return res.redirect('/register');
  }
  try {
    await ensureDbReady();
    const [courses, pendingUser, registrationPathways] = await Promise.all([
      getCoursesCached(),
      db.get(
        'SELECT course_id, study_track, study_program_id, admission_id, study_context_id FROM users WHERE id = ?',
        [req.session.pendingUserId]
      ),
      getRegistrationPathways(),
    ]);
    if (!pendingUser) {
      req.session.pendingUserId = null;
      req.session.rememberMe = null;
      return res.redirect('/register?error=Session%20expired');
    }
    const pendingPlacement = await resolveUserAcademicPlacement(pendingUser, { lang: getPreferredLang(req) });
    const selectedCourseId = pendingPlacement && pendingPlacement.course_id ? Number(pendingPlacement.course_id) : null;
    const selectedCourse = (courses || []).find((course) => Number(course.id) === Number(selectedCourseId)) || null;
    const selectedTrack = normalizeRegistrationTrack(
      pendingPlacement && pendingPlacement.track_key ? pendingPlacement.track_key : pendingUser.study_track,
      inferRegistrationTrackFromCourse(selectedCourse)
    );
    const selectedCampus = pendingPlacement && pendingPlacement.campus_key
      ? normalizeCourseCampus(pendingPlacement.campus_key)
      : (selectedCourse ? normalizeCourseCampus(selectedCourse.location) : '');
    const selectedProgramId = Number.isFinite(Number((pendingPlacement && pendingPlacement.program_id) || pendingUser.study_program_id))
      ? Number((pendingPlacement && pendingPlacement.program_id) || pendingUser.study_program_id)
      : null;
    const selectedAdmissionId = Number.isFinite(Number((pendingPlacement && pendingPlacement.admission_id) || pendingUser.admission_id))
      ? Number((pendingPlacement && pendingPlacement.admission_id) || pendingUser.admission_id)
      : null;
    return res.render('register-course', {
      courses,
      selectedCourseId,
      selectedCampus,
      selectedTrack,
      selectedProgramId,
      selectedAdmissionId,
      registrationPathways,
      selectedStudyContextId: pendingPlacement && pendingPlacement.study_context_id ? Number(pendingPlacement.study_context_id) : null,
      pendingStudyContext: pendingPlacement,
      error: req.query.error || '',
    });
  } catch (err) {
    console.error('Register course step failed', err);
    return res.status(500).send('Database error');
  }
});

app.post('/register/course', registerLimiter, async (req, res) => {
  const userId = Number(req.session.pendingUserId || 0);
  if (!Number.isInteger(userId) || userId < 1) {
    return res.redirect('/register');
  }
  const lang = getPreferredLang(req);
  const redirectRegisterCourseError = (message) =>
    res.redirect(`/register/course?error=${encodeURIComponent(message)}`);
  const redirectRegistrationFlowIssue = (issue) => redirectRegisterCourseError(
    pathwayHelpers.buildRegistrationFlowError({ issue, lang })
  );

  const rawTrack = String(req.body.study_track || req.body.track || '').trim().toLowerCase();
  const trackFromBody = REGISTRATION_TRACK_KEYS.has(rawTrack) ? rawTrack : '';
  const requestedCampus = parseCourseCampus(req.body.campus || req.body.location);
  const requestedProgramId = Number(req.body.study_program_id || 0);
  const requestedAdmissionId = Number(req.body.admission_id || 0);
  let selectedProgramId = Number.isFinite(requestedProgramId) && requestedProgramId > 0 ? requestedProgramId : null;
  let selectedAdmissionId = Number.isFinite(requestedAdmissionId) && requestedAdmissionId > 0 ? requestedAdmissionId : null;
  let courseId = parsePositiveIntStrict(req.body.course_id);
  let studyContextId = parsePositiveIntStrict(req.body.study_context_id);

  try {
    await ensureDbReady();

    if (trackFromBody === 'teacher' && !selectedAdmissionId && selectedProgramId) {
      selectedAdmissionId = await resolveLatestRegistrationAdmissionId(selectedProgramId, {
        trackKey: 'teacher',
      });
    }

    if (!studyContextId && selectedAdmissionId && requestedCampus) {
      const resolvedContext = await resolveRegistrationStudyContext({
        admissionId: selectedAdmissionId,
        programId: selectedProgramId,
        trackKey: trackFromBody,
        campus: requestedCampus,
        stage: 1,
      });
      if (resolvedContext.contextId) {
        studyContextId = resolvedContext.contextId;
        courseId = resolvedContext.courseId || courseId;
      } else if (resolvedContext.reason && resolvedContext.reason !== 'context_not_found') {
        if (resolvedContext.reason === 'ambiguous_campus') {
          return redirectRegistrationFlowIssue('ambiguous_campus');
        }
        return redirectRegistrationFlowIssue(resolvedContext.reason || 'campus_not_available');
      }
    }

    if (!courseId && selectedAdmissionId && requestedCampus) {
      const resolvedCourse = await resolveRegistrationCourseForCampus({
        admissionId: selectedAdmissionId,
        programId: selectedProgramId,
        trackKey: trackFromBody,
        campus: requestedCampus,
      });
      if (!resolvedCourse.courseId) {
        if (resolvedCourse.reason === 'ambiguous_campus') {
          return redirectRegistrationFlowIssue('ambiguous_campus');
        }
        return redirectRegistrationFlowIssue(resolvedCourse.reason || 'campus_not_available');
      }
      courseId = resolvedCourse.courseId;
    }

    if (!courseId) {
      return redirectRegistrationFlowIssue('missing_campus');
    }

    const [pendingUser, course] = await Promise.all([
      db.get('SELECT id FROM users WHERE id = ?', [userId]),
      db.get('SELECT id, is_teacher_course FROM courses WHERE id = ?', [courseId]),
    ]);
    if (!pendingUser) {
      req.session.pendingUserId = null;
      req.session.rememberMe = null;
      return res.redirect('/register?error=Session%20expired');
    }
    if (!course) {
      return redirectRegistrationFlowIssue('invalid_course');
    }

    const teacherCourse = course.is_teacher_course === true || Number(course.is_teacher_course) === 1;
    let selectedTrack = trackFromBody || inferRegistrationTrackFromCourse(course);
    if (teacherCourse) {
      selectedTrack = 'teacher';
    }

    if (selectedTrack === 'teacher' && selectedProgramId && !selectedAdmissionId) {
      selectedAdmissionId = await resolveLatestRegistrationAdmissionId(selectedProgramId, {
        trackKey: 'teacher',
        courseId,
      });
    }

    if (selectedProgramId && selectedAdmissionId) {
      const explicitPath = await db.get(
        `
          SELECT p.track_key
          FROM study_programs p
          JOIN program_admissions a ON a.program_id = p.id
          JOIN program_admission_courses pac ON pac.admission_id = a.id
          WHERE p.id = ?
            AND a.id = ?
            AND pac.course_id = ?
            AND p.is_active = true
            AND a.is_active = true
            AND pac.is_visible = true
        `,
        [selectedProgramId, selectedAdmissionId, courseId]
      );
      if (explicitPath) {
        const explicitTrack = normalizeRegistrationTrack(explicitPath.track_key, selectedTrack);
        if (trackFromBody && explicitTrack !== selectedTrack) {
          return redirectRegistrationFlowIssue('invalid_pathway');
        }
        selectedTrack = explicitTrack;
      } else if (selectedTrack === 'teacher') {
        const teacherAdmissionId = await resolveLatestRegistrationAdmissionId(selectedProgramId, {
          trackKey: 'teacher',
          courseId,
        });
        if (teacherAdmissionId) {
          selectedAdmissionId = teacherAdmissionId;
          selectedTrack = 'teacher';
        } else if (requestedProgramId || requestedAdmissionId || requestedCampus) {
          return redirectRegistrationFlowIssue('invalid_campus_binding');
        } else {
          selectedProgramId = null;
          selectedAdmissionId = null;
        }
      } else if (requestedProgramId || requestedAdmissionId || requestedCampus) {
        return redirectRegistrationFlowIssue('invalid_campus_binding');
      } else {
        selectedProgramId = null;
        selectedAdmissionId = null;
      }
    }

    if (!selectedProgramId || !selectedAdmissionId) {
      const hasTrackFilter = REGISTRATION_TRACK_KEYS.has(selectedTrack);
      const fallbackPath = await db.get(
        `
          SELECT
            p.id AS program_id,
            a.id AS admission_id,
            p.track_key
          FROM study_programs p
          JOIN program_admissions a ON a.program_id = p.id
          JOIN program_admission_courses pac ON pac.admission_id = a.id
          WHERE pac.course_id = ?
            AND p.is_active = true
            AND a.is_active = true
            AND pac.is_visible = true
            ${hasTrackFilter ? 'AND p.track_key = ?' : ''}
          ORDER BY
            CASE p.track_key
              WHEN 'teacher' THEN 0
              WHEN 'master' THEN 1
              WHEN 'bachelor' THEN 2
              ELSE 3
            END,
            a.admission_year DESC,
            a.id DESC
          LIMIT 1
        `,
        hasTrackFilter ? [courseId, selectedTrack] : [courseId]
      );
      if (fallbackPath) {
        selectedProgramId = Number(fallbackPath.program_id || 0) || null;
        selectedAdmissionId = Number(fallbackPath.admission_id || 0) || null;
        selectedTrack = normalizeRegistrationTrack(fallbackPath.track_key, selectedTrack);
      }
    }

    selectedTrack = normalizeRegistrationTrack(selectedTrack, teacherCourse ? 'teacher' : 'bachelor');
    if (!courseMatchesRegistrationTrack(course, selectedTrack)) {
      return redirectRegistrationFlowIssue('invalid_pathway');
    }
    if (selectedProgramId && !selectedAdmissionId) {
      return redirectRegistrationFlowIssue('missing_admission');
    }
    if (!studyContextId && courseId && selectedAdmissionId) {
      studyContextId = await ensureStudyContextForLegacyPlacement({
        courseId,
        admissionId: selectedAdmissionId,
        programId: selectedProgramId,
        trackKey: selectedTrack,
        preferredCampus: requestedCampus,
        preferredStage: 1,
      });
    }

    if (!teacherCourse && selectedAdmissionId) {
      const scopedSubjects = await getRegistrationSubjects(courseId, selectedAdmissionId, {
        studyContextId,
      });
      if (!(scopedSubjects || []).length) {
        return redirectRegistrationFlowIssue('empty_subject_scope');
      }
    }

    await assignUserStudyContext(userId, studyContextId, {
      courseId,
      trackKey: selectedTrack,
      programId: selectedProgramId,
      admissionId: selectedAdmissionId,
    });
    await db.run(
      'UPDATE user_registration_events SET course_id = COALESCE(course_id, ?) WHERE user_id = ?',
      [courseId, userId]
    );

    if (teacherCourse || selectedTrack === 'teacher') {
      return res.redirect('/register/teacher-subjects');
    }
    return res.redirect('/register/subjects');
  } catch (err) {
    console.error('Register course save failed', err);
    return res.redirect('/register/course?error=Database%20error');
  }
});

app.get('/register/subjects', async (req, res) => {
  if (!req.session.pendingUserId) {
    return res.redirect('/register');
  }
  try {
    await ensureDbReady();
    const user = await db.get(
      'SELECT course_id, admission_id, study_context_id, study_program_id, study_track FROM users WHERE id = ?',
      [req.session.pendingUserId]
    );
    const placement = await resolveUserAcademicPlacement(user, { lang: getPreferredLang(req) });
    if (!placement || !placement.course_id) {
      return res.redirect('/register/course');
    }
    const course = await db.get('SELECT is_teacher_course FROM courses WHERE id = ?', [placement.course_id]);
    if (course && (course.is_teacher_course === true || Number(course.is_teacher_course) === 1)) {
      return res.redirect('/register/teacher-subjects');
    }

    const [subjects, allCourseSubjects, baseVisibleSubjects, admissionMappedCourses] = await Promise.all([
      getRegistrationSubjects(placement.course_id, placement.admission_id, {
        studyContextId: placement.study_context_id,
      }),
      getSubjectsCached(placement.course_id, { visibleOnly: false }),
      getSubjectsCached(placement.course_id, { visibleOnly: true }),
      getAdmissionRegistrationCourses(placement.admission_id),
    ]);
    const isRequired = (subject) =>
      subject && (subject.is_required === true || subject.is_required === 1 || subject.is_required === '1');
    const requiredAuto = (subjects || []).filter((subject) => isRequired(subject) && Number(subject.group_count) === 1);
    await Promise.all(
      requiredAuto.map((subject) =>
        db.run(
          `
            INSERT INTO student_groups (student_id, subject_id, group_number)
            VALUES (?, ?, 1)
            ON CONFLICT(student_id, subject_id) DO NOTHING
          `,
          [req.session.pendingUserId, subject.id]
        )
      )
    );

    const optoutRows = await db.all(
      'SELECT subject_id FROM user_subject_optouts WHERE user_id = ?',
      [req.session.pendingUserId]
    );
    const optouts = (optoutRows || []).map((row) => Number(row.subject_id));
    const selectedGroupRows = await db.all(
      'SELECT subject_id, group_number FROM student_groups WHERE student_id = ?',
      [req.session.pendingUserId]
    );
    const selectedGroups = {};
    (selectedGroupRows || []).forEach((row) => {
      const subjectId = Number(row.subject_id);
      const groupNumber = Number(row.group_number);
      if (!Number.isInteger(subjectId) || subjectId < 1) return;
      if (!Number.isInteger(groupNumber) || groupNumber < 1) return;
      selectedGroups[subjectId] = groupNumber;
    });

    const lang = getPreferredLang(req);
    const campusChoices = buildAdmissionCampusChoicesFromCourses(admissionMappedCourses);
    const readyCampusBindings = campusChoices.filter(
      (choice) => !choice.is_ambiguous && Number(choice.course_id || 0) > 0
    ).length;
    const registrationPathwayReadiness = pathwayHelpers.buildPathwayReadinessSummary({
      mappedCourses: Array.isArray(admissionMappedCourses) ? admissionMappedCourses.length : 0,
      visibleSubjects: Array.isArray(subjects) ? subjects.length : 0,
      totalSubjects: Array.isArray(allCourseSubjects) ? allCourseSubjects.length : 0,
      campusBindings: readyCampusBindings,
      pendingUsers: 0,
    });
    const pathwayRegistrationHint = pathwayHelpers.buildSubjectVisibilityCopy({
      visibleSubjects: Array.isArray(subjects) ? subjects.length : 0,
      totalSubjects: Array.isArray(allCourseSubjects) ? allCourseSubjects.length : 0,
      lang,
    });
    const registrationPathwayAlert = pathwayHelpers.buildRegistrationReadinessAlert({
      summary: registrationPathwayReadiness,
      lang,
      mappedCourses: Array.isArray(admissionMappedCourses) ? admissionMappedCourses.length : 0,
      visibleSubjects: Array.isArray(subjects) ? subjects.length : 0,
      totalSubjects: Array.isArray(allCourseSubjects) ? allCourseSubjects.length : 0,
      campusBindings: readyCampusBindings,
      ambiguousCampuses: campusChoices.filter((choice) => choice.is_ambiguous).length,
      baseHiddenSubjects: Math.max(
        0,
        Number(Array.isArray(allCourseSubjects) ? allCourseSubjects.length : 0)
          - Number(Array.isArray(baseVisibleSubjects) ? baseVisibleSubjects.length : 0)
      ),
    });
    const registrationExperienceSummary = pathwayHelpers.buildRegistrationExperienceSummary({
      summary: registrationPathwayReadiness,
      lang,
      mappedCourses: Array.isArray(admissionMappedCourses) ? admissionMappedCourses.length : 0,
      visibleSubjects: Array.isArray(subjects) ? subjects.length : 0,
      totalSubjects: Array.isArray(allCourseSubjects) ? allCourseSubjects.length : 0,
      campusBindings: readyCampusBindings,
      ambiguousCampuses: campusChoices.filter((choice) => choice.is_ambiguous).length,
      pendingUsers: 0,
      baseHiddenSubjects: Math.max(
        0,
        Number(Array.isArray(allCourseSubjects) ? allCourseSubjects.length : 0)
          - Number(Array.isArray(baseVisibleSubjects) ? baseVisibleSubjects.length : 0)
      ),
    });

    return res.render('register-subjects', {
      subjects,
      optouts,
      selectedGroups,
      studyContext: placement,
      pathwayRegistrationHint,
      registrationPathwayReadiness,
      registrationPathwayAlert,
      registrationExperienceSummary,
      error: req.query.error || '',
    });
  } catch (err) {
    console.error('Register subjects step failed', err);
    return res.status(500).send('Database error');
  }
});

app.post('/register/subjects', registerLimiter, async (req, res) => {
  const userId = Number(req.session.pendingUserId || 0);
  if (!Number.isInteger(userId) || userId < 1) {
    return res.redirect('/register');
  }

  const upsertStudentGroupSql = `
    INSERT INTO student_groups (student_id, subject_id, group_number)
    VALUES (?, ?, ?)
    ON CONFLICT(student_id, subject_id)
    DO UPDATE SET group_number = excluded.group_number
  `;

  try {
    await ensureDbReady();
    const userRow = await db.get(
      'SELECT course_id, admission_id, study_context_id, study_program_id, study_track FROM users WHERE id = ?',
      [userId]
    );
    const placement = await resolveUserAcademicPlacement(userRow, { lang: getPreferredLang(req) });
    if (!placement || !placement.course_id) {
      return res.redirect('/register/course');
    }

    const subjects = await getRegistrationSubjects(placement.course_id, placement.admission_id, {
      studyContextId: placement.study_context_id,
    });
    const isRequired = (subject) =>
      subject && (subject.is_required === true || subject.is_required === 1 || subject.is_required === '1');
    let hasMissingRequired = false;

    for (const subject of subjects || []) {
      const subjectId = Number(subject.id || 0);
      if (!Number.isFinite(subjectId) || subjectId < 1) continue;

      const groupCount = Math.max(1, Number(subject.group_count || 1));
      const selectedValue = req.body[`subject_${subjectId}`];
      const selectedGroup = Number(selectedValue);
      const optout = req.body[`optout_${subjectId}`] === '1' || req.body[`optout_${subjectId}`] === 'on';
      const requiredFlag = isRequired(subject);

      if (requiredFlag) {
        await db.run('DELETE FROM user_subject_optouts WHERE user_id = ? AND subject_id = ?', [userId, subjectId]);
        if (groupCount === 1) {
          await db.run(upsertStudentGroupSql, [userId, subjectId, 1]);
          continue;
        }
        if (!selectedValue) {
          hasMissingRequired = true;
          continue;
        }
        if (Number.isFinite(selectedGroup) && selectedGroup >= 1 && selectedGroup <= groupCount) {
          await db.run(upsertStudentGroupSql, [userId, subjectId, selectedGroup]);
        } else {
          hasMissingRequired = true;
        }
        continue;
      }

      if (optout) {
        await db.run('DELETE FROM student_groups WHERE student_id = ? AND subject_id = ?', [userId, subjectId]);
        await db.run(
          `
            INSERT INTO user_subject_optouts (user_id, subject_id)
            VALUES (?, ?)
            ON CONFLICT(user_id, subject_id) DO NOTHING
          `,
          [userId, subjectId]
        );
        continue;
      }

      await db.run('DELETE FROM user_subject_optouts WHERE user_id = ? AND subject_id = ?', [userId, subjectId]);
      if (!selectedValue) {
        if (groupCount === 1) {
          await db.run(upsertStudentGroupSql, [userId, subjectId, 1]);
        }
        continue;
      }
      if (Number.isFinite(selectedGroup) && selectedGroup >= 1 && selectedGroup <= groupCount) {
        await db.run(upsertStudentGroupSql, [userId, subjectId, selectedGroup]);
      } else {
        hasMissingRequired = true;
      }
    }

    if (hasMissingRequired) {
      return res.redirect('/register/subjects?error=missing-group');
    }

    const user = await db.get(
      'SELECT id, full_name, role, schedule_group, course_id, language FROM users WHERE id = ?',
      [userId]
    );
    if (!user) {
      return res.redirect('/login');
    }

    const remember = Boolean(req.session.rememberMe);
    await establishAuthenticatedSession(req, {
      user: {
        id: user.id,
        username: user.full_name,
        schedule_group: user.schedule_group,
        course_id: user.course_id || 1,
        language: user.language || getPreferredLang(req),
      },
      role: user.role,
      remember,
      sessionData: {
        last_seen_route: '/register/subjects',
        last_seen_at: new Date().toISOString(),
      },
    });
    req.session.pendingUserId = null;
    req.session.rememberMe = null;
    logAction(db, req, 'register_subjects', { user_id: user.id });
    broadcast('users_updated');
    await saveRequestSession(req);
    return res.redirect('/home?welcome=1');
  } catch (err) {
    console.error('Register subjects save failed', err);
    return res.redirect('/register/subjects?error=db-error');
  }
});

app.get('/register/teacher-subjects', (req, res) => {
  if (!req.session.pendingUserId) {
    return res.redirect('/register');
  }
  ensureDbReady().catch((err) => {
    console.error('DB init failed', err);
  });
  db.get(
    'SELECT id, course_id, admission_id, study_context_id, study_program_id, study_track FROM users WHERE id = ?',
    [req.session.pendingUserId],
    async (uErr, user) => {
      if (uErr || !user) {
        return res.redirect('/register/course');
      }
      try {
        const placement = await resolveUserAcademicPlacement(user, { lang: getPreferredLang(req) });
        if (!placement || !placement.course_id) {
          return res.redirect('/register/course');
        }
        const course = await db.get('SELECT is_teacher_course FROM courses WHERE id = ?', [placement.course_id]);
        if (!course) {
          return res.redirect('/register/course');
        }
        if (!(course.is_teacher_course === true || Number(course.is_teacher_course) === 1)) {
          return res.redirect('/register/subjects');
        }
        const teacherOfferingCatalog = await listTeacherOfferingCatalog();
        const selectionMode = teacherOfferingCatalog.length ? 'offering' : 'legacy';
        const subjects = selectionMode === 'offering'
          ? teacherOfferingCatalog
          : await getTeacherSubjectCatalog();
        const selections = selectionMode === 'offering'
          ? await getTeacherOfferingSelections(user.id)
          : await getTeacherSelections(user.id);
        return res.render('register-teacher-subjects', {
          subjects,
          selections,
          selectionMode,
          studyContext: placement,
          error: req.query.error || '',
          isProfileEdit: false,
        });
      } catch (err) {
        return res.status(500).send('Database error');
      }
    }
  );
});

