function buildTeacherWorkspaceUrl({
  courseId = null,
  studyContextId = null,
  semesterId = null,
  ok = '',
  error = '',
} = {}) {
  const params = new URLSearchParams();
  const normalizedCourseId = parsePositiveIntStrict(courseId);
  const normalizedStudyContextId = parsePositiveIntStrict(studyContextId);
  const normalizedSemesterId = parsePositiveIntStrict(semesterId);
  if (normalizedCourseId) {
    params.set('course', String(normalizedCourseId));
  }
  if (normalizedStudyContextId) {
    params.set('study_context_id', String(normalizedStudyContextId));
  }
  if (normalizedSemesterId) {
    params.set('semester_id', String(normalizedSemesterId));
  }
  if (ok) {
    params.set('ok', String(ok));
  }
  if (error) {
    params.set('error', String(error));
  }
  const query = params.toString();
  return query ? `/teacher/workspace?${query}` : '/teacher/workspace';
}

app.get('/teacher/workspace', requireLogin, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'teacher.workspace.init');
  }
  if (!hasSessionRole(req, 'teacher')) {
    return res.redirect('/schedule');
  }
  const { id: userId, username } = req.session.user;
  const decodeMessage = (value) => {
    if (!value) return '';
    try {
      return decodeURIComponent(String(value));
    } catch (err) {
      return String(value);
    }
  };
  try {
    const [teacherSubjects, teacherAssignedOfferings, teacherOfferingCatalog, teacherOfferingSelections] = await Promise.all([
      getTeacherAssignedSubjects(userId),
      getTeacherAssignedOfferings(userId),
      listTeacherOfferingCatalog(),
      getTeacherOfferingSelections(userId),
    ]);
    const teacherCourses = buildTeacherCourseList(teacherSubjects);
    const requestedCourseId = Number(req.query.course);
    const requestedStudyContextId = parsePositiveIntStrict(req.query.study_context_id);
    const requestedSemesterId = parsePositiveIntStrict(req.query.semester_id);
    const workspaceCourseOptions = Array.from(new Map(
      (teacherOfferingCatalog || [])
        .flatMap((offering) => Array.isArray(offering.contexts) ? offering.contexts : [])
        .map((context) => [Number(context.course_id || 0), {
          id: Number(context.course_id || 0) || null,
          name: String(context.course_name || ''),
        }])
        .filter((entry) => Number.isInteger(entry[0]) && entry[0] > 0)
    ).values()).sort((a, b) => {
      const byId = Number(a.id || 0) - Number(b.id || 0);
      if (byId !== 0) return byId;
      return String(a.name || '').localeCompare(String(b.name || ''), 'uk', { sensitivity: 'base' });
    });
    const selectedWorkspaceCourse = workspaceCourseOptions.find((course) => Number(course.id || 0) === requestedCourseId) || null;
    const selectedCourse = teacherCourses.find((course) => Number(course.id) === requestedCourseId) || null;
    let selectedCourseId = selectedWorkspaceCourse
      ? Number(selectedWorkspaceCourse.id || 0)
      : (selectedCourse
        ? Number(selectedCourse.id)
        : (teacherCourses.length === 1 ? Number(teacherCourses[0].id) : null));

    const workspaceContextOptions = Array.from(new Map(
      (teacherOfferingCatalog || [])
        .flatMap((offering) => Array.isArray(offering.contexts) ? offering.contexts : [])
        .filter((context) => !selectedCourseId || Number(context.course_id || 0) === Number(selectedCourseId || 0))
        .map((context) => [Number(context.id || 0), {
          id: Number(context.id || 0) || null,
          label: String(context.label || ''),
          course_id: Number(context.course_id || 0) || null,
          course_name: String(context.course_name || ''),
          course_location: String(context.course_location || ''),
          program_name: String(context.program_name || ''),
          program_code: String(context.program_code || ''),
          admission_year: Number(context.admission_year || 0) || null,
          stage_number: Number(context.stage_number || 0) || null,
          campus_key: String(context.campus_key || ''),
          semester_ids: Array.isArray(context.semester_ids) ? context.semester_ids.slice() : [],
          semester_numbers: Array.isArray(context.semester_numbers) ? context.semester_numbers.slice() : [],
          semester_titles: Array.isArray(context.semester_titles) ? context.semester_titles.slice() : [],
        }])
        .filter((entry) => Number.isInteger(entry[0]) && entry[0] > 0)
    ).values());
    const selectedWorkspaceContext = workspaceContextOptions.find((item) => Number(item.id || 0) === requestedStudyContextId) || null;
    const selectedWorkspaceContextId = selectedWorkspaceContext ? Number(selectedWorkspaceContext.id) : null;
    if (!selectedCourseId && selectedWorkspaceContext && selectedWorkspaceContext.course_id) {
      selectedCourseId = Number(selectedWorkspaceContext.course_id || 0) || null;
    }

    const workspaceSemesterOptions = Array.from(new Map(
      (selectedWorkspaceContext
        ? (selectedWorkspaceContext.semester_ids || []).map((semesterId, index) => ({
            id: Number(semesterId || 0) || null,
            title: String((selectedWorkspaceContext.semester_titles || [])[index] || `Semester ${(selectedWorkspaceContext.semester_numbers || [])[index] || index + 1}`),
            semester_number: Number((selectedWorkspaceContext.semester_numbers || [])[index] || 0) || null,
          }))
        : (teacherOfferingCatalog || []).flatMap((offering) => (
            Array.isArray(offering.contexts)
              ? offering.contexts.flatMap((context) => (
                  (context.semester_ids || []).map((semesterId, index) => ({
                    id: Number(semesterId || 0) || null,
                    title: String((context.semester_titles || [])[index] || `Semester ${(context.semester_numbers || [])[index] || index + 1}`),
                    semester_number: Number((context.semester_numbers || [])[index] || 0) || null,
                  }))
                ))
              : []
          )))
        .filter((item) => Number.isInteger(Number(item.id || 0)) && Number(item.id || 0) > 0)
        .map((item) => [Number(item.id || 0), item])
    ).values()).sort((a, b) => {
      const numberDiff = Number(a.semester_number || 0) - Number(b.semester_number || 0);
      if (numberDiff !== 0) return numberDiff;
      return String(a.title || '').localeCompare(String(b.title || ''));
    });
    const selectedWorkspaceSemesterId = workspaceSemesterOptions.find((item) => Number(item.id || 0) === requestedSemesterId)
      ? Number(requestedSemesterId || 0)
      : null;

    const matchesWorkspaceScope = (offering) => {
      const contexts = Array.isArray(offering.contexts) ? offering.contexts : [];
      const courseMatch = !selectedCourseId
        || contexts.some((context) => Number(context.course_id || 0) === Number(selectedCourseId || 0));
      if (!courseMatch) {
        return false;
      }
      const contextMatch = !selectedWorkspaceContextId
        || contexts.some((context) => Number(context.id || 0) === Number(selectedWorkspaceContextId || 0));
      if (!contextMatch) {
        return false;
      }
      const semesterMatch = !selectedWorkspaceSemesterId
        || contexts.some((context) => (context.semester_ids || []).some((semesterId) => Number(semesterId || 0) === Number(selectedWorkspaceSemesterId || 0)));
      if (!semesterMatch) {
        return false;
      }
      return true;
    };
    const scopedTeacherOfferings = (teacherAssignedOfferings || []).filter(matchesWorkspaceScope);
    const workspaceCatalogOfferings = (teacherOfferingCatalog || []).filter(matchesWorkspaceScope);
    const workspaceAssignedOfferingDetails = new Map(
      (teacherAssignedOfferings || [])
        .map((offering) => [Number(offering.id || 0), offering])
        .filter((entry) => Number.isInteger(entry[0]) && entry[0] > 0)
    );

    const [templates, assets, recentHomework] = await Promise.all([
      getTeacherHomeworkTemplates(userId, {
        courseId: selectedCourseId,
        limit: 300,
      }),
      listTeacherAssets(userId, { courseId: selectedCourseId }),
      db.all(
        `
          SELECT
            h.id,
            h.description,
            h.class_date,
            h.custom_due_date,
            h.subject_id,
            h.group_number,
            s.name AS subject_name
          FROM homework h
          LEFT JOIN subjects s ON s.id = h.subject_id
          WHERE h.created_by_id = ?
            AND COALESCE(h.is_teacher_homework, 0) = 1
            ${selectedCourseId ? 'AND h.course_id = ?' : ''}
          ORDER BY COALESCE(NULLIF(TRIM(CAST(h.custom_due_date AS TEXT)), ''), NULLIF(TRIM(CAST(h.class_date AS TEXT)), '')) DESC NULLS LAST, CAST(h.created_at AS TEXT) DESC
          LIMIT 8
        `,
        selectedCourseId ? [userId, selectedCourseId] : [userId]
      ),
    ]);

    const subjectMap = new Map();
    teacherSubjects.forEach((subject) => {
      const subjectId = Number(subject.subject_id);
      if (!Number.isFinite(subjectId) || subjectId < 1 || subjectMap.has(subjectId)) return;
      subjectMap.set(subjectId, {
        id: subjectId,
        name: String(subject.subject_name || '').trim(),
        course_id: Number(subject.course_id),
        course_name: String(subject.course_name || ''),
      });
    });
    const allTeacherSubjects = Array.from(subjectMap.values()).sort((a, b) => {
      const byCourse = Number(a.course_id) - Number(b.course_id);
      if (byCourse !== 0) return byCourse;
      return String(a.name || '').localeCompare(String(b.name || ''), 'uk', { sensitivity: 'base' });
    });
    const scopedTeacherSubjects = selectedCourseId
      ? allTeacherSubjects.filter((subject) => Number(subject.course_id) === Number(selectedCourseId))
      : allTeacherSubjects;

    return res.render('teacher-workspace', {
      role: 'teacher',
      username,
      settings: settingsCache,
      teacherCourses,
      workspaceCourseOptions,
      selectedCourseId,
      workspaceContextOptions,
      selectedWorkspaceContextId,
      workspaceSemesterOptions,
      selectedWorkspaceSemesterId,
      teacherOfferings: scopedTeacherOfferings,
      workspaceCatalogOfferings,
      workspaceOfferingSelections: teacherOfferingSelections,
      workspaceAssignedOfferingDetails,
      teacherSubjects: scopedTeacherSubjects,
      teacherSubjectsAll: allTeacherSubjects,
      templates,
      assets,
      recentHomework,
      error: decodeMessage(req.query.error),
      success: decodeMessage(req.query.ok),
    });
  } catch (err) {
    return handleDbError(res, err, 'teacher.workspace');
  }
});

app.post('/teacher/workspace/offerings', requireLogin, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'teacher.workspace.offerings.save.init');
  }
  if (!hasSessionRole(req, 'teacher')) {
    return res.redirect('/schedule');
  }
  const userId = Number(req.session.user.id || 0);
  const redirectState = {
    courseId: parsePositiveIntStrict(req.body.course),
    studyContextId: parsePositiveIntStrict(req.body.study_context_id),
    semesterId: parsePositiveIntStrict(req.body.semester_id),
  };
  try {
    const result = await saveTeacherWorkspaceOfferingAssignments(userId, req.body);
    if (!result.ok) {
      return res.redirect(buildTeacherWorkspaceUrl({
        ...redirectState,
        error: result.error || 'Database error',
      }));
    }
    logAction(db, req, 'teacher_workspace_offering_assignments_save', {
      user_id: userId,
      course_id: redirectState.courseId || null,
      study_context_id: redirectState.studyContextId || null,
      semester_id: redirectState.semesterId || null,
      scope_count: Number(result.scope_count || 0),
      assignment_count: Number(result.assignment_count || 0),
      template_count: Number(result.template_count || 0),
      templates_synced: result.templates_synced ? 1 : 0,
    });
    broadcast('users_updated');
    const okMessage = result.templates_synced
      ? 'Assignments and recurring templates updated'
      : 'Live assignments updated';
    return res.redirect(buildTeacherWorkspaceUrl({
      ...redirectState,
      ok: okMessage,
    }));
  } catch (err) {
    console.error('Teacher workspace offering save failed', err);
    return res.redirect(buildTeacherWorkspaceUrl({
      ...redirectState,
      error: 'Database error',
    }));
  }
});

app.post('/teacher/workspace/assets', requireLogin, uploadLimiter, upload.single('asset'), async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'teacher.workspace.assets.create.init');
  }
  if (!hasSessionRole(req, 'teacher')) {
    if (req.file) fs.unlink(req.file.path, () => {});
    return res.redirect('/schedule');
  }
  const userId = Number(req.session.user.id || 0);
  const requestedCourseId = Number(req.body.course_id || req.session.user.course_id || 0);
  const courseQuery = Number.isInteger(requestedCourseId) && requestedCourseId > 0 ? `?course=${requestedCourseId}` : '';
  if (!req.file) {
    return res.redirect(`/teacher/workspace${courseQuery}${courseQuery ? '&' : '?'}error=Select%20a%20file`);
  }
  try {
    const assetId = await createAssetFromUpload({
      file: req.file,
      userId,
      courseId: requestedCourseId || null,
      name: req.body.name,
      kind: 'template_attachment',
    });
    if (!assetId) {
      if (req.file) fs.unlink(req.file.path, () => {});
      return res.redirect(`/teacher/workspace${courseQuery}${courseQuery ? '&' : '?'}error=Asset%20storage%20is%20unavailable`);
    }
    logAction(db, req, 'teacher_workspace_asset_create', {
      asset_id: assetId,
      course_id: requestedCourseId || null,
      original_name: req.file.originalname ? String(req.file.originalname) : '',
    });
    return res.redirect(`/teacher/workspace${courseQuery}${courseQuery ? '&' : '?'}ok=Asset%20uploaded`);
  } catch (err) {
    if (req.file) fs.unlink(req.file.path, () => {});
    return res.redirect(`/teacher/workspace${courseQuery}${courseQuery ? '&' : '?'}error=Database%20error`);
  }
});

app.post('/teacher/workspace/assets/:id/delete', requireLogin, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'teacher.workspace.assets.delete.init');
  }
  if (!hasSessionRole(req, 'teacher')) {
    return res.redirect('/schedule');
  }
  const assetId = Number(req.params.id);
  const requestedCourseId = Number(req.body.course_id || req.session.user.course_id || 0);
  const courseQuery = Number.isInteger(requestedCourseId) && requestedCourseId > 0 ? `?course=${requestedCourseId}` : '';
  if (!Number.isInteger(assetId) || assetId < 1) {
    return res.redirect(`/teacher/workspace${courseQuery}${courseQuery ? '&' : '?'}error=Invalid%20asset`);
  }
  try {
    const asset = await db.get(
      'SELECT id, user_id, file_path, original_name FROM assets WHERE id = ? LIMIT 1',
      [assetId]
    );
    if (!asset || Number(asset.user_id) !== Number(req.session.user.id)) {
      return res.redirect(`/teacher/workspace${courseQuery}${courseQuery ? '&' : '?'}error=Asset%20not%20found`);
    }
    const usage = await db.get(
      `
        SELECT
          (SELECT COUNT(*) FROM teacher_template_asset_map WHERE asset_id = ?) AS template_count,
          (SELECT COUNT(*) FROM homework_asset_map WHERE asset_id = ?) AS homework_count
      `,
      [assetId, assetId]
    );
    if (Number(usage?.template_count || 0) > 0 || Number(usage?.homework_count || 0) > 0) {
      return res.redirect(`/teacher/workspace${courseQuery}${courseQuery ? '&' : '?'}error=Asset%20is%20still%20linked%20to%20templates%20or%20homework`);
    }
    await db.run('DELETE FROM assets WHERE id = ?', [assetId]);
    logAction(db, req, 'teacher_workspace_asset_delete', {
      asset_id: assetId,
      original_name: asset.original_name ? String(asset.original_name) : '',
    });
    return res.redirect(`/teacher/workspace${courseQuery}${courseQuery ? '&' : '?'}ok=Asset%20deleted`);
  } catch (err) {
    return res.redirect(`/teacher/workspace${courseQuery}${courseQuery ? '&' : '?'}error=Database%20error`);
  }
});

app.post('/teacher/workspace/templates', requireLogin, uploadLimiter, upload.array('template_files', 8), async (req, res) => {
  const uploadedFiles = Array.isArray(req.files) ? req.files : [];
  try {
    await ensureDbReady();
  } catch (err) {
    unlinkUploadedFiles(uploadedFiles);
    return handleDbError(res, err, 'teacher.workspace.templates.create.init');
  }
  if (!hasSessionRole(req, 'teacher')) {
    unlinkUploadedFiles(uploadedFiles);
    return res.redirect('/schedule');
  }
  const { id: userId, course_id: fallbackCourseId } = req.session.user;
  const title = String(req.body.title || '').trim();
  const description = String(req.body.description || '').trim();
  const requestedCourseId = Number(req.body.course_id);
  const requestedSubjectId = Number(req.body.subject_id);
  const isControl = ['1', 'true', 'on', 'yes'].includes(String(req.body.is_control || '').toLowerCase()) ? 1 : 0;
  const isCredit = ['1', 'true', 'on', 'yes'].includes(String(req.body.is_credit || '').toLowerCase()) ? 1 : 0;
  const tags = normalizeTemplateTagsInput(req.body.tags).join(', ');
  const assetIds = teacherTemplateHelpers.normalizeTemplateAssetIds(req.body.asset_ids, 48);
  const linkUrl = normalizeExternalUrl(req.body.link_url) || null;
  const meetingUrl = normalizeExternalUrl(req.body.meeting_url) || null;
  const fallbackCourseQuery = Number.isInteger(requestedCourseId) && requestedCourseId > 0
    ? `&course=${requestedCourseId}`
    : (Number.isInteger(Number(fallbackCourseId)) && Number(fallbackCourseId) > 0 ? `&course=${Number(fallbackCourseId)}` : '');

  if (!title || !description) {
    unlinkUploadedFiles(uploadedFiles);
    return res.redirect(`/teacher/workspace?error=Title%20and%20description%20are%20required${fallbackCourseQuery}`);
  }

  let uploadedAssetIds = [];
  try {
    const resolvedScope = await resolveTeacherTemplateScope(userId, requestedCourseId, requestedSubjectId);
    if (!resolvedScope.ok) {
      unlinkUploadedFiles(uploadedFiles);
      return res.redirect(`/teacher/workspace?error=${resolvedScope.error || 'Invalid%20template%20scope'}${fallbackCourseQuery}`);
    }
    const { courseId, subjectId, validatedCourseId } = resolvedScope;
    uploadedAssetIds = await createAssetsFromUploads({
      files: uploadedFiles,
      userId,
      courseId: courseId || validatedCourseId || fallbackCourseId || null,
      kind: 'template_attachment',
    });
    const combinedAssetIds = teacherTemplateHelpers.buildAppliedHomeworkAssetIds({
      templateAssetIds: assetIds,
      uploadedAssetIds,
    });

    const inserted = await db.get(
      `
        INSERT INTO teacher_homework_templates
          (
            user_id,
            course_id,
            subject_id,
            title,
            description,
            link_url,
            meeting_url,
            tags,
            is_control,
            is_credit,
            created_at,
            updated_at
          )
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, NOW(), NOW())
        RETURNING id
      `,
      [
        userId,
        courseId,
        subjectId,
        title,
        description,
        linkUrl,
        meetingUrl,
        tags,
        isControl,
        isCredit,
      ]
    );
    if (inserted && inserted.id) {
      await syncTemplateAssetMap(inserted.id, userId, combinedAssetIds);
    }

    logAction(db, req, 'teacher_homework_template_create', {
      template_id: inserted && inserted.id ? Number(inserted.id) : null,
      course_id: courseId,
      subject_id: subjectId,
      title,
      tags: tags ? tags.split(',').map((item) => item.trim()).filter(Boolean) : [],
      is_control: isControl,
      is_credit: isCredit,
      asset_ids: combinedAssetIds,
      uploaded_asset_ids: uploadedAssetIds,
    });

    const redirectCourseId = courseId || (validatedCourseId || null);
    const courseQuery = Number.isInteger(redirectCourseId) && redirectCourseId > 0
      ? `&course=${redirectCourseId}`
      : '';
    return res.redirect(`/teacher/workspace?ok=Template%20saved${courseQuery}`);
  } catch (err) {
    console.error('Teacher workspace template create failed', err);
    await cleanupFailedUploadedAssets({
      files: uploadedFiles,
      assetIds: uploadedAssetIds.length ? uploadedAssetIds : (err && Array.isArray(err.assetIds) ? err.assetIds : []),
    });
    const errorMessage = err && err.code === 'ASSET_STORAGE_UNAVAILABLE'
      ? 'Asset%20storage%20is%20unavailable'
      : 'Database%20error';
    return res.redirect(`/teacher/workspace?error=${errorMessage}${fallbackCourseQuery}`);
  }
});

app.post('/teacher/workspace/templates/:id/update', requireLogin, uploadLimiter, upload.array('template_files', 8), async (req, res) => {
  const uploadedFiles = Array.isArray(req.files) ? req.files : [];
  try {
    await ensureDbReady();
  } catch (err) {
    unlinkUploadedFiles(uploadedFiles);
    return handleDbError(res, err, 'teacher.workspace.templates.update.init');
  }
  if (!hasSessionRole(req, 'teacher')) {
    unlinkUploadedFiles(uploadedFiles);
    return res.redirect('/schedule');
  }
  const { id: userId } = req.session.user;
  const templateId = Number(req.params.id);
  if (!Number.isInteger(templateId) || templateId < 1) {
    unlinkUploadedFiles(uploadedFiles);
    return res.redirect('/teacher/workspace?error=Invalid%20template');
  }

  const requestedCourseId = Number(req.body.course_id);
  const requestedSubjectId = Number(req.body.subject_id);
  const contextCourseId = Number(req.body.course_id_context);
  const fallbackCourseId = Number.isInteger(contextCourseId) && contextCourseId > 0
    ? contextCourseId
    : (Number.isInteger(requestedCourseId) && requestedCourseId > 0 ? requestedCourseId : null);
  const title = String(req.body.title || '').trim();
  const description = String(req.body.description || '').trim();
  const tags = normalizeTemplateTagsInput(req.body.tags).join(', ');
  const assetIds = teacherTemplateHelpers.normalizeTemplateAssetIds(req.body.asset_ids, 48);
  const linkUrl = normalizeExternalUrl(req.body.link_url) || null;
  const meetingUrl = normalizeExternalUrl(req.body.meeting_url) || null;
  const isControl = ['1', 'true', 'on', 'yes'].includes(String(req.body.is_control || '').toLowerCase()) ? 1 : 0;
  const isCredit = ['1', 'true', 'on', 'yes'].includes(String(req.body.is_credit || '').toLowerCase()) ? 1 : 0;
  const fallbackCourseQuery = fallbackCourseId ? `&course=${fallbackCourseId}` : '';

  if (!title || !description) {
    unlinkUploadedFiles(uploadedFiles);
    return res.redirect(`/teacher/workspace?error=Title%20and%20description%20are%20required${fallbackCourseQuery}`);
  }

  let uploadedAssetIds = [];
  try {
    const existing = await db.get(
      `
        SELECT id, user_id, course_id, subject_id, title
        FROM teacher_homework_templates
        WHERE id = ?
        LIMIT 1
      `,
      [templateId]
    );
    if (!existing) {
      unlinkUploadedFiles(uploadedFiles);
      return res.redirect(`/teacher/workspace?error=Template%20not%20found${fallbackCourseQuery}`);
    }
    if (Number(existing.user_id) !== Number(userId)) {
      unlinkUploadedFiles(uploadedFiles);
      return res.status(403).send('Forbidden');
    }

    const resolvedScope = await resolveTeacherTemplateScope(userId, requestedCourseId, requestedSubjectId);
    if (!resolvedScope.ok) {
      unlinkUploadedFiles(uploadedFiles);
      return res.redirect(`/teacher/workspace?error=${resolvedScope.error || 'Invalid%20template%20scope'}${fallbackCourseQuery}`);
    }
    const { courseId, subjectId, validatedCourseId } = resolvedScope;
    uploadedAssetIds = await createAssetsFromUploads({
      files: uploadedFiles,
      userId,
      courseId: courseId || validatedCourseId || fallbackCourseId || null,
      kind: 'template_attachment',
    });
    const combinedAssetIds = teacherTemplateHelpers.buildAppliedHomeworkAssetIds({
      templateAssetIds: assetIds,
      uploadedAssetIds,
    });

    await db.run(
      `
        UPDATE teacher_homework_templates
        SET
          course_id = ?,
          subject_id = ?,
          title = ?,
          description = ?,
          link_url = ?,
          meeting_url = ?,
          tags = ?,
          is_control = ?,
          is_credit = ?,
          updated_at = NOW()
        WHERE id = ?
      `,
      [
        courseId,
        subjectId,
        title,
        description,
        linkUrl,
        meetingUrl,
        tags,
        isControl,
        isCredit,
        templateId,
      ]
    );
    await syncTemplateAssetMap(templateId, userId, combinedAssetIds);

    logAction(db, req, 'teacher_homework_template_update', {
      template_id: templateId,
      previous_title: existing.title ? String(existing.title) : '',
      title,
      course_id: courseId,
      subject_id: subjectId,
      tags: tags ? tags.split(',').map((item) => item.trim()).filter(Boolean) : [],
      is_control: isControl,
      is_credit: isCredit,
      asset_ids: combinedAssetIds,
      uploaded_asset_ids: uploadedAssetIds,
    });

    const redirectCourseId = courseId || validatedCourseId || fallbackCourseId || null;
    const courseQuery = redirectCourseId ? `&course=${redirectCourseId}` : '';
    return res.redirect(`/teacher/workspace?ok=Template%20updated${courseQuery}`);
  } catch (err) {
    console.error('Teacher workspace template update failed', err);
    await cleanupFailedUploadedAssets({
      files: uploadedFiles,
      assetIds: uploadedAssetIds.length ? uploadedAssetIds : (err && Array.isArray(err.assetIds) ? err.assetIds : []),
    });
    const errorMessage = err && err.code === 'ASSET_STORAGE_UNAVAILABLE'
      ? 'Asset%20storage%20is%20unavailable'
      : 'Database%20error';
    return res.redirect(`/teacher/workspace?error=${errorMessage}${fallbackCourseQuery}`);
  }
});

app.post('/teacher/workspace/templates/:id/clone', requireLogin, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'teacher.workspace.templates.clone.init');
  }
  if (!hasSessionRole(req, 'teacher')) {
    return res.redirect('/schedule');
  }
  const { id: userId } = req.session.user;
  const templateId = Number(req.params.id);
  if (!Number.isInteger(templateId) || templateId < 1) {
    return res.redirect('/teacher/workspace?error=Invalid%20template');
  }
  const contextCourseId = Number(req.body.course_id_context);
  const fallbackCourseId = Number.isInteger(contextCourseId) && contextCourseId > 0 ? contextCourseId : null;
  const fallbackCourseQuery = fallbackCourseId ? `&course=${fallbackCourseId}` : '';
  const rawTargetSubjectIds = req.body.target_subject_ids;
  const targetSubjectIds = Array.from(
    new Set(
      (Array.isArray(rawTargetSubjectIds) ? rawTargetSubjectIds : [rawTargetSubjectIds])
        .map((value) => Number(value))
        .filter((value) => Number.isInteger(value) && value > 0)
    )
  ).slice(0, 240);

  if (!targetSubjectIds.length) {
    return res.redirect(`/teacher/workspace?error=Select%20at%20least%20one%20subject${fallbackCourseQuery}`);
  }

  try {
    const sourceTemplate = await db.get(
      `
        SELECT
          id,
          user_id,
          course_id,
          subject_id,
          title,
          description,
          link_url,
          meeting_url,
          tags,
          is_control,
          is_credit
        FROM teacher_homework_templates
        WHERE id = ?
        LIMIT 1
      `,
      [templateId]
    );
    if (!sourceTemplate) {
      return res.redirect(`/teacher/workspace?error=Template%20not%20found${fallbackCourseQuery}`);
    }
    if (Number(sourceTemplate.user_id) !== Number(userId)) {
      return res.status(403).send('Forbidden');
    }

    const placeholders = targetSubjectIds.map(() => '?').join(', ');
    const rows = await db.all(
      `
        SELECT DISTINCT
          s.id AS subject_id,
          s.course_id,
          s.name AS subject_name,
          c.name AS course_name
        FROM teacher_subjects ts
        JOIN subjects s ON s.id = ts.subject_id
        LEFT JOIN courses c ON c.id = s.course_id
        WHERE ts.user_id = ?
          AND ts.subject_id IN (${placeholders})
      `,
      [userId, ...targetSubjectIds]
    );
    const targetMap = new Map();
    (rows || []).forEach((row) => {
      const subjectId = Number(row.subject_id);
      const courseId = Number(row.course_id);
      if (!Number.isInteger(subjectId) || subjectId < 1 || !Number.isInteger(courseId) || courseId < 1) {
        return;
      }
      if (!targetMap.has(subjectId)) {
        targetMap.set(subjectId, {
          subject_id: subjectId,
          course_id: courseId,
          subject_name: row.subject_name ? String(row.subject_name) : '',
          course_name: row.course_name ? String(row.course_name) : '',
        });
      }
    });
    if (!targetMap.size) {
      return res.redirect(`/teacher/workspace?error=Invalid%20subject%20selection${fallbackCourseQuery}`);
    }

    const sourceTitle = String(sourceTemplate.title || '').trim();
    const sourceDescription = String(sourceTemplate.description || '').trim();
    const sourceLinkUrl = sourceTemplate.link_url ? String(sourceTemplate.link_url) : null;
    const sourceMeetingUrl = sourceTemplate.meeting_url ? String(sourceTemplate.meeting_url) : null;
    const sourceTags = sourceTemplate.tags ? String(sourceTemplate.tags) : '';
    const sourceIsControl = sourceTemplate.is_control === true || Number(sourceTemplate.is_control) === 1 ? 1 : 0;
    const sourceIsCredit = sourceTemplate.is_credit === true || Number(sourceTemplate.is_credit) === 1 ? 1 : 0;

    let createdCount = 0;
    let duplicateCount = 0;
    for (const target of targetMap.values()) {
      const duplicate = await db.get(
        `
          SELECT id
          FROM teacher_homework_templates
          WHERE user_id = ?
            AND subject_id = ?
            AND COALESCE(course_id, 0) = COALESCE(?, 0)
            AND LOWER(title) = LOWER(?)
            AND COALESCE(description, '') = COALESCE(?, '')
          LIMIT 1
        `,
        [
          userId,
          Number(target.subject_id),
          Number(target.course_id),
          sourceTitle,
          sourceDescription,
        ]
      );
      if (duplicate) {
        duplicateCount += 1;
        continue;
      }

      const inserted = await db.get(
        `
          INSERT INTO teacher_homework_templates
            (user_id, course_id, subject_id, title, description, link_url, meeting_url, tags, is_control, is_credit, created_at, updated_at)
          VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, NOW(), NOW())
          RETURNING id
        `,
        [
          userId,
          Number(target.course_id),
          Number(target.subject_id),
          sourceTitle,
          sourceDescription,
          sourceLinkUrl,
          sourceMeetingUrl,
          sourceTags,
          sourceIsControl,
          sourceIsCredit,
        ]
      );
      if (inserted && inserted.id) {
        await db.run(
          `
            INSERT INTO teacher_template_asset_map (template_id, asset_id, sort_order, created_at)
            SELECT ?, asset_id, sort_order, NOW()
            FROM teacher_template_asset_map
            WHERE template_id = ?
          `,
          [Number(inserted.id), templateId]
        ).catch((err) => {
          if (!isDbSchemaCompatibilityError(err)) throw err;
        });
        createdCount += 1;
      }
    }

    const invalidCount = Math.max(0, Number(targetSubjectIds.length) - Number(targetMap.size));
    logAction(db, req, 'teacher_homework_template_clone', {
      source_template_id: templateId,
      source_subject_id: sourceTemplate.subject_id ? Number(sourceTemplate.subject_id) : null,
      source_course_id: sourceTemplate.course_id ? Number(sourceTemplate.course_id) : null,
      created_count: createdCount,
      duplicate_count: duplicateCount,
      invalid_count: invalidCount,
      target_subject_ids: Array.from(targetMap.keys()),
    });

    const suffixes = [];
    if (duplicateCount > 0) {
      suffixes.push(`${duplicateCount} duplicates skipped`);
    }
    if (invalidCount > 0) {
      suffixes.push(`${invalidCount} invalid selections skipped`);
    }
    const baseMessage = createdCount > 0
      ? `Template cloned to ${createdCount} subject${createdCount === 1 ? '' : 's'}`
      : 'No templates were cloned';
    const fullMessage = suffixes.length ? `${baseMessage} (${suffixes.join(', ')})` : baseMessage;
    const redirectCourseId = fallbackCourseId
      || (Number.isInteger(Number(sourceTemplate.course_id)) && Number(sourceTemplate.course_id) > 0
        ? Number(sourceTemplate.course_id)
        : null);
    const courseQuery = redirectCourseId ? `&course=${redirectCourseId}` : '';
    return res.redirect(`/teacher/workspace?ok=${encodeURIComponent(fullMessage)}${courseQuery}`);
  } catch (err) {
    console.error('Teacher workspace template clone failed', err);
    return res.redirect(`/teacher/workspace?error=Database%20error${fallbackCourseQuery}`);
  }
});

app.post('/teacher/workspace/templates/bulk-clone', requireLogin, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'teacher.workspace.templates.bulkClone.init');
  }
  if (!hasSessionRole(req, 'teacher')) {
    return res.redirect('/schedule');
  }
  const { id: userId } = req.session.user;
  const contextCourseId = Number(req.body.course_id_context);
  const fallbackCourseId = Number.isInteger(contextCourseId) && contextCourseId > 0 ? contextCourseId : null;
  const fallbackCourseQuery = fallbackCourseId ? `&course=${fallbackCourseId}` : '';
  const rawSourceTemplateIds = req.body.source_template_ids;
  const sourceTemplateIds = Array.from(
    new Set(
      (Array.isArray(rawSourceTemplateIds) ? rawSourceTemplateIds : [rawSourceTemplateIds])
        .map((value) => Number(value))
        .filter((value) => Number.isInteger(value) && value > 0)
    )
  ).slice(0, 120);
  const rawTargetSubjectIds = req.body.target_subject_ids;
  const targetSubjectIds = Array.from(
    new Set(
      (Array.isArray(rawTargetSubjectIds) ? rawTargetSubjectIds : [rawTargetSubjectIds])
        .map((value) => Number(value))
        .filter((value) => Number.isInteger(value) && value > 0)
    )
  ).slice(0, 240);

  if (!sourceTemplateIds.length || !targetSubjectIds.length) {
    return res.redirect(`/teacher/workspace?error=Select%20templates%20and%20subjects%20for%20bulk%20clone${fallbackCourseQuery}`);
  }

  try {
    const sourcePlaceholders = sourceTemplateIds.map(() => '?').join(', ');
    const sourceRows = await db.all(
      `
        SELECT
          id,
          user_id,
          course_id,
          subject_id,
          title,
          description,
          link_url,
          meeting_url,
          tags,
          is_control,
          is_credit
        FROM teacher_homework_templates
        WHERE user_id = ?
          AND id IN (${sourcePlaceholders})
        ORDER BY updated_at DESC, id DESC
      `,
      [userId, ...sourceTemplateIds]
    );
    if (!sourceRows.length) {
      return res.redirect(`/teacher/workspace?error=No%20source%20templates%20found${fallbackCourseQuery}`);
    }

    const targetPlaceholders = targetSubjectIds.map(() => '?').join(', ');
    const targetRows = await db.all(
      `
        SELECT DISTINCT
          s.id AS subject_id,
          s.course_id,
          s.name AS subject_name,
          c.name AS course_name
        FROM teacher_subjects ts
        JOIN subjects s ON s.id = ts.subject_id
        LEFT JOIN courses c ON c.id = s.course_id
        WHERE ts.user_id = ?
          AND ts.subject_id IN (${targetPlaceholders})
      `,
      [userId, ...targetSubjectIds]
    );
    const targetMap = new Map();
    (targetRows || []).forEach((row) => {
      const subjectId = Number(row.subject_id);
      const courseId = Number(row.course_id);
      if (!Number.isInteger(subjectId) || subjectId < 1 || !Number.isInteger(courseId) || courseId < 1) {
        return;
      }
      if (!targetMap.has(subjectId)) {
        targetMap.set(subjectId, {
          subject_id: subjectId,
          course_id: courseId,
          subject_name: row.subject_name ? String(row.subject_name) : '',
          course_name: row.course_name ? String(row.course_name) : '',
        });
      }
    });
    if (!targetMap.size) {
      return res.redirect(`/teacher/workspace?error=Invalid%20target%20subjects${fallbackCourseQuery}`);
    }

    let createdCount = 0;
    let duplicateCount = 0;
    for (const source of sourceRows) {
      const sourceTitle = String(source.title || '').trim();
      const sourceDescription = String(source.description || '').trim();
      const sourceLinkUrl = source.link_url ? String(source.link_url) : null;
      const sourceMeetingUrl = source.meeting_url ? String(source.meeting_url) : null;
      const sourceTags = source.tags ? String(source.tags) : '';
      const sourceIsControl = source.is_control === true || Number(source.is_control) === 1 ? 1 : 0;
      const sourceIsCredit = source.is_credit === true || Number(source.is_credit) === 1 ? 1 : 0;

      for (const target of targetMap.values()) {
        const duplicate = await db.get(
          `
            SELECT id
            FROM teacher_homework_templates
            WHERE user_id = ?
              AND subject_id = ?
              AND COALESCE(course_id, 0) = COALESCE(?, 0)
              AND LOWER(title) = LOWER(?)
              AND COALESCE(description, '') = COALESCE(?, '')
            LIMIT 1
          `,
          [
            userId,
            Number(target.subject_id),
            Number(target.course_id),
            sourceTitle,
            sourceDescription,
          ]
        );
        if (duplicate) {
          duplicateCount += 1;
          continue;
        }

        const inserted = await db.get(
          `
            INSERT INTO teacher_homework_templates
              (user_id, course_id, subject_id, title, description, link_url, meeting_url, tags, is_control, is_credit, created_at, updated_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, NOW(), NOW())
            RETURNING id
          `,
          [
            userId,
            Number(target.course_id),
            Number(target.subject_id),
            sourceTitle,
            sourceDescription,
            sourceLinkUrl,
            sourceMeetingUrl,
            sourceTags,
            sourceIsControl,
            sourceIsCredit,
          ]
        );
        if (inserted && inserted.id) {
          await db.run(
            `
              INSERT INTO teacher_template_asset_map (template_id, asset_id, sort_order, created_at)
              SELECT ?, asset_id, sort_order, NOW()
              FROM teacher_template_asset_map
              WHERE template_id = ?
            `,
            [Number(inserted.id), Number(source.id)]
          ).catch((err) => {
            if (!isDbSchemaCompatibilityError(err)) throw err;
          });
          createdCount += 1;
        }
      }
    }

    const invalidSourceCount = Math.max(0, sourceTemplateIds.length - sourceRows.length);
    const invalidTargetCount = Math.max(0, targetSubjectIds.length - targetMap.size);
    logAction(db, req, 'teacher_homework_template_bulk_clone', {
      source_template_ids: sourceRows.map((row) => Number(row.id)).filter((value) => Number.isInteger(value) && value > 0),
      target_subject_ids: Array.from(targetMap.keys()),
      source_count: sourceRows.length,
      target_count: targetMap.size,
      created_count: createdCount,
      duplicate_count: duplicateCount,
      invalid_source_count: invalidSourceCount,
      invalid_target_count: invalidTargetCount,
    });

    const suffixes = [];
    if (duplicateCount > 0) {
      suffixes.push(`${duplicateCount} duplicates skipped`);
    }
    if (invalidSourceCount > 0) {
      suffixes.push(`${invalidSourceCount} missing sources skipped`);
    }
    if (invalidTargetCount > 0) {
      suffixes.push(`${invalidTargetCount} invalid targets skipped`);
    }
    const baseMessage = createdCount > 0
      ? `Bulk clone created ${createdCount} template copies`
      : 'Bulk clone created no new templates';
    const scopeMessage = ` from ${sourceRows.length} source template${sourceRows.length === 1 ? '' : 's'} to ${targetMap.size} subject${targetMap.size === 1 ? '' : 's'}`;
    const fullMessage = suffixes.length
      ? `${baseMessage}${scopeMessage} (${suffixes.join(', ')})`
      : `${baseMessage}${scopeMessage}`;
    return res.redirect(`/teacher/workspace?ok=${encodeURIComponent(fullMessage)}${fallbackCourseQuery}`);
  } catch (err) {
    console.error('Teacher workspace template bulk clone failed', err);
    return res.redirect(`/teacher/workspace?error=Database%20error${fallbackCourseQuery}`);
  }
});

app.post('/teacher/workspace/templates/bulk-delete', requireLogin, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'teacher.workspace.templates.bulkDelete.init');
  }
  if (!hasSessionRole(req, 'teacher')) {
    return res.redirect('/schedule');
  }
  const { id: userId } = req.session.user;
  const contextCourseId = Number(req.body.course_id_context);
  const fallbackCourseId = Number.isInteger(contextCourseId) && contextCourseId > 0 ? contextCourseId : null;
  const fallbackCourseQuery = fallbackCourseId ? `&course=${fallbackCourseId}` : '';
  const rawSourceTemplateIds = req.body.source_template_ids;
  const sourceTemplateIds = Array.from(
    new Set(
      (Array.isArray(rawSourceTemplateIds) ? rawSourceTemplateIds : [rawSourceTemplateIds])
        .map((value) => Number(value))
        .filter((value) => Number.isInteger(value) && value > 0)
    )
  ).slice(0, 300);
  if (!sourceTemplateIds.length) {
    return res.redirect(`/teacher/workspace?error=Select%20templates%20for%20bulk%20delete${fallbackCourseQuery}`);
  }

  try {
    const sourcePlaceholders = sourceTemplateIds.map(() => '?').join(', ');
    const sourceRows = await db.all(
      `
        SELECT id, title, course_id, subject_id
        FROM teacher_homework_templates
        WHERE user_id = ?
          AND id IN (${sourcePlaceholders})
      `,
      [userId, ...sourceTemplateIds]
    );
    if (!sourceRows.length) {
      return res.redirect(`/teacher/workspace?error=No%20templates%20found%20for%20bulk%20delete${fallbackCourseQuery}`);
    }

    let deletedCount = 0;
    const deletedIds = [];
    const deletedTitles = [];
    for (const row of sourceRows) {
      const templateId = Number(row.id);
      if (!Number.isInteger(templateId) || templateId < 1) {
        continue;
      }
      await db.run(
        'DELETE FROM teacher_homework_templates WHERE user_id = ? AND id = ?',
        [userId, templateId]
      );
      deletedCount += 1;
      deletedIds.push(templateId);
      deletedTitles.push(String(row.title || '').trim());
    }

    const invalidSourceCount = Math.max(0, sourceTemplateIds.length - sourceRows.length);
    logAction(db, req, 'teacher_homework_template_bulk_delete', {
      deleted_template_ids: deletedIds,
      deleted_titles: deletedTitles.slice(0, 80),
      deleted_count: deletedCount,
      invalid_source_count: invalidSourceCount,
    });

    const suffixes = [];
    if (invalidSourceCount > 0) {
      suffixes.push(`${invalidSourceCount} missing templates skipped`);
    }
    const baseMessage = deletedCount > 0
      ? `Bulk delete removed ${deletedCount} template${deletedCount === 1 ? '' : 's'}`
      : 'Bulk delete removed no templates';
    const fullMessage = suffixes.length
      ? `${baseMessage} (${suffixes.join(', ')})`
      : baseMessage;
    return res.redirect(`/teacher/workspace?ok=${encodeURIComponent(fullMessage)}${fallbackCourseQuery}`);
  } catch (err) {
    console.error('Teacher workspace template bulk delete failed', err);
    return res.redirect(`/teacher/workspace?error=Database%20error${fallbackCourseQuery}`);
  }
});

app.post('/teacher/workspace/templates/:id/delete', requireLogin, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'teacher.workspace.templates.delete.init');
  }
  if (!hasSessionRole(req, 'teacher')) {
    return res.redirect('/schedule');
  }
  const { id: userId } = req.session.user;
  const templateId = Number(req.params.id);
  if (!Number.isInteger(templateId) || templateId < 1) {
    return res.redirect('/teacher/workspace?error=Invalid%20template');
  }
  try {
    const row = await db.get(
      'SELECT id, user_id, course_id, subject_id, title FROM teacher_homework_templates WHERE id = ?',
      [templateId]
    );
    if (!row) {
      return res.redirect('/teacher/workspace?error=Template%20not%20found');
    }
    if (Number(row.user_id) !== Number(userId)) {
      return res.status(403).send('Forbidden');
    }
    await db.run('DELETE FROM teacher_homework_templates WHERE id = ?', [templateId]);
    logAction(db, req, 'teacher_homework_template_delete', {
      template_id: templateId,
      course_id: row.course_id ? Number(row.course_id) : null,
      subject_id: row.subject_id ? Number(row.subject_id) : null,
      title: row.title ? String(row.title) : '',
    });
    const requestedCourseId = Number(req.body.course_id);
    const redirectCourseId = Number.isInteger(requestedCourseId) && requestedCourseId > 0
      ? requestedCourseId
      : (Number.isInteger(Number(row.course_id)) && Number(row.course_id) > 0 ? Number(row.course_id) : null);
    const courseQuery = redirectCourseId ? `&course=${redirectCourseId}` : '';
    return res.redirect(`/teacher/workspace?ok=Template%20deleted${courseQuery}`);
  } catch (err) {
    console.error('Teacher workspace template delete failed', err);
    return res.redirect('/teacher/workspace?error=Database%20error');
  }
});

app.get('/teacher/pending', requireLogin, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'teacher.pending.init');
  }
  try {
    const { id: userId, course_id: courseId } = req.session.user;
    const course = await db.get('SELECT is_teacher_course FROM courses WHERE id = ?', [courseId]);
    if (!course || !(course.is_teacher_course === true || Number(course.is_teacher_course) === 1)) {
      return res.redirect('/schedule');
    }
    const request = await db.get('SELECT status FROM teacher_requests WHERE user_id = ?', [userId]);
    if (request && request.status === 'approved') {
      await establishAuthenticatedSession(req, {
        user: {
          ...req.session.user,
          course_id: courseId || req.session.user.course_id || 1,
          language: req.session.user.language || getPreferredLang(req),
        },
        role: 'teacher',
        remember: Boolean(req.session.rememberMe),
        sessionData: {
          last_seen_route: '/teacher/pending',
          last_seen_at: new Date().toISOString(),
        },
      });
      await saveRequestSession(req);
      return res.redirect('/schedule');
    }
    return res.render('teacher-pending', {
      status: request ? request.status : 'pending',
    });
  } catch (err) {
    return handleDbError(res, err, 'teacher.pending');
  }
});

app.get('/profile', requireLogin, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'profile.init');
  }
  const { id, role, username } = req.session.user;
  try {
    const user = await db.get(
      'SELECT id, full_name, course_id, language, admission_id, study_program_id, study_track, study_context_id FROM users WHERE id = ?',
      [id]
    );
    if (!user) {
      return res.status(500).send('Database error');
    }
    const placement = await resolveUserAcademicPlacement(user, { lang: getPreferredLang(req) });
    let teacherStatus = null;
    let teacherCourse = false;
    if (placement && placement.course_id) {
      teacherCourse = await isTeacherCourse(placement.course_id);
      if (teacherCourse) {
        const tr = await db.get('SELECT status FROM teacher_requests WHERE user_id = ?', [id]);
        teacherStatus = tr ? tr.status : null;
      }
    }
    const activeSemester = await getActiveSemester((placement && placement.course_id) || user.course_id || 1);
    const pointsRow = await db.get(
      `
        SELECT COALESCE(SUM(${ACTIVITY_POINTS_CASE}), 0) AS points
        FROM activity_log
        WHERE user_id = ?${activeSemester ? ' AND semester_id = ?' : ''}
      `,
      activeSemester ? [id, activeSemester.id] : [id]
    );
    const activityPoints = pointsRow ? Number(pointsRow.points || 0) : 0;
    const analyticsCourseId = (placement && placement.course_id) || user.course_id || 1;
    const analyticsParams = activeSemester ? [id, analyticsCourseId, activeSemester.id] : [id, analyticsCourseId];
    const [
      homeworkCreatedRow,
      teamworkCreatedRow,
      teamworkJoinedRow,
    ] = await Promise.all([
      db.get(
        `SELECT COUNT(*) AS count
         FROM homework
         WHERE created_by_id = ? AND course_id = ?${activeSemester ? ' AND semester_id = ?' : ''}`,
        analyticsParams
      ),
      db.get(
        `SELECT COUNT(*) AS count
         FROM teamwork_tasks
         WHERE created_by = ? AND course_id = ?${activeSemester ? ' AND semester_id = ?' : ''}`,
        analyticsParams
      ),
      db.get(
        `SELECT COUNT(*) AS count
         FROM teamwork_members m
         JOIN teamwork_tasks t ON t.id = m.task_id
         WHERE m.user_id = ? AND t.course_id = ?${activeSemester ? ' AND t.semester_id = ?' : ''}`,
        analyticsParams
      ),
    ]);
    const profileStats = {
      homeworkCreated: Number(homeworkCreatedRow?.count || 0),
      teamworkCreated: Number(teamworkCreatedRow?.count || 0),
      teamworkJoined: Number(teamworkJoinedRow?.count || 0),
    };
    res.render('profile', {
      user,
      studyContext: placement,
      activityPoints,
      profileStats,
      teacherStatus,
      teacherCourse,
      error: req.query.error || '',
      success: req.query.ok || '',
      role,
      username,
    });
  } catch (err) {
    return handleDbError(res, err, 'profile');
  }
});

app.post('/profile', requireLogin, (req, res) => {
  const { full_name, password, confirm_password, language } = req.body;
  const { id } = req.session.user;
  if (!full_name) {
    return res.redirect('/profile?error=Full%20name%20required');
  }
  if ((password || confirm_password) && password !== confirm_password) {
    return res.redirect('/profile?error=Passwords%20do%20not%20match');
  }

  const updates = [];
  const params = [];
  updates.push('full_name = ?');
  params.push(full_name.trim());

  if (password) {
    const hash = bcrypt.hashSync(password, 10);
    updates.push('password_hash = ?');
    params.push(hash);
  }

  if (language && ['uk', 'en'].includes(language)) {
    updates.push('language = ?');
    params.push(language);
  }

  params.push(id);
  db.run(`UPDATE users SET ${updates.join(', ')} WHERE id = ?`, params, (err) => {
    if (err) {
      return res.redirect('/profile?error=Name%20already%20exists');
    }
    req.session.user.username = full_name.trim();
    if (language && ['uk', 'en'].includes(language)) {
      req.session.user.language = language;
      req.session.lang = language;
    }
    logAction(db, req, 'update_profile', { user_id: id });
    broadcast('users_updated');
    return res.redirect('/profile?ok=Profile%20updated');
  });
});

app.post('/profile/reset-subjects', requireLogin, async (req, res) => {
  const { id } = req.session.user;
  try {
    await db.run('DELETE FROM student_groups WHERE student_id = ?', [id]);
    await db.run('DELETE FROM user_subject_optouts WHERE user_id = ?', [id]);
    req.session.pendingUserId = id;
    logAction(db, req, 'reset_subjects', { user_id: id });
    broadcast('users_updated');
    return req.session.save(() => res.redirect('/register/subjects'));
  } catch (err) {
    console.error('Failed to reset subjects', err);
    return res.redirect('/profile?error=Database%20error');
  }
});

async function getMyDayReviewSubjects({ userId, courseId, roleKeys = [] }) {
  const normalizedRoles = normalizeRoleList(roleKeys);
  const hasFullAccess = normalizedRoles.some((roleKey) => roleKey === 'admin' || roleKey === 'deanery');
  if (hasFullAccess) {
    const courseScope = await getCourseSharedStorageScope(courseId, { visibleOnly: true });
    return (courseScope.subjects || []).map((row) => {
      const groupCount = Math.max(1, Number(row.group_count || 1));
      return {
        subject_id: Number(row.id || 0),
        subject_name: row.name || 'Предмет',
        owner_course_id: Number(row.owner_course_id || row.course_id || courseId || 0) || null,
        has_all_groups: true,
        group_numbers: Array.from({ length: groupCount }, (_v, index) => index + 1),
      };
    });
  }

  if (!normalizedRoles.includes('teacher')) {
    return [];
  }

  const rows = (await getTeacherAssignedSubjects(userId))
    .filter((row) => Number(row.course_id || 0) === Number(courseId || 0));
  if (!rows || !rows.length) {
    return [];
  }
  const bySubject = new Map();
  (rows || []).forEach((row) => {
    const subjectId = Number(row.subject_id || 0);
    if (!Number.isFinite(subjectId) || subjectId < 1) return;
    if (!bySubject.has(subjectId)) {
      bySubject.set(subjectId, {
        subject_id: subjectId,
        subject_name: row.subject_name || 'Предмет',
        group_count: Math.max(1, Number(row.group_count || 1)),
        owner_course_id: Number(row.owner_course_id || row.course_id || courseId || 0) || null,
        has_all_groups: false,
        group_numbers_set: new Set(),
      });
    }
    const item = bySubject.get(subjectId);
    if (row.group_number === null || typeof row.group_number === 'undefined') {
      item.has_all_groups = true;
      return;
    }
    const groupNumber = Number(row.group_number);
    if (Number.isInteger(groupNumber) && groupNumber > 0) {
      item.group_numbers_set.add(groupNumber);
    }
  });
  return Array.from(bySubject.values()).map((item) => {
    const groupNumbers = item.has_all_groups
      ? Array.from({ length: item.group_count }, (_v, index) => index + 1)
      : Array.from(item.group_numbers_set).sort((a, b) => a - b);
    return {
      subject_id: item.subject_id,
      subject_name: item.subject_name,
      owner_course_id: item.owner_course_id,
      has_all_groups: item.has_all_groups,
      group_numbers: groupNumbers,
    };
  });
}

async function buildMyDayReviewQueue({
  userId,
  courseId,
  semesterId,
  roleKeys = [],
  now = new Date(),
}) {
  const subjectOptions = await getMyDayReviewSubjects({ userId, courseId, roleKeys });
  const emptyResult = {
    enabled: true,
    overdue_threshold_hours: REVIEW_QUEUE_OVERDUE_HOURS,
    counts: { overdue: 0, new: 0, no_comment: 0 },
    total: 0,
    items: [],
    truncated: false,
    templates: REVIEW_QUEUE_FEEDBACK_TEMPLATES,
  };
  if (!subjectOptions.length) {
    return emptyResult;
  }

  const priorityByType = {
    overdue: 0,
    new: 1,
    no_comment: 2,
  };
  const nowMs = now.getTime();
  const byCellKey = new Map();

  for (const subject of subjectOptions) {
    const subjectId = Number(subject.subject_id || 0);
    if (!Number.isFinite(subjectId) || subjectId < 1) continue;
    const allowedGroups = Array.isArray(subject.group_numbers)
      ? subject.group_numbers.filter((value) => Number.isInteger(Number(value)) && Number(value) > 0).map((value) => Number(value))
      : [];
    const groupFilterSet = subject.has_all_groups || !allowedGroups.length ? null : new Set(allowedGroups);
    const matrix = await buildJournalMatrix({
      subjectId,
      courseId,
      semesterId,
      actorUserId: userId,
      groupFilterSet,
    });
    const columns = Array.isArray(matrix?.columns) ? matrix.columns : [];
    const rows = Array.isArray(matrix?.rows) ? matrix.rows : [];
    rows.forEach((row) => {
      const student = row?.student || {};
      const studentId = Number(student.id || 0);
      if (!Number.isFinite(studentId) || studentId < 1) return;
      const studentName = String(student.full_name || '').trim() || 'Студент';
      const studentGroup = Number(student.group_number || 0);
      const cells = Array.isArray(row?.cells) ? row.cells : [];
      cells.forEach((cell, index) => {
        const column = columns[index] || null;
        if (!column) return;
        const columnId = Number(column.id || 0);
        if (!Number.isFinite(columnId) || columnId < 1) return;
        if (Number(column.is_locked || 0) === 1) return;
        if (!Number(column.source_homework_id || 0)) return;
        const submission = cell?.submission || null;
        const submittedAt = submission && submission.submitted_at ? String(submission.submitted_at) : '';
        if (!submittedAt) return;

        const parsedSubmittedAt = new Date(submittedAt);
        const submittedAtMs = parsedSubmittedAt.getTime();
        const hasValidSubmittedAt = Number.isFinite(submittedAtMs);
        const hasScore = Number.isFinite(Number(cell?.score));
        const hasComment = Boolean(String(cell?.teacher_comment || '').trim());
        if (hasScore && hasComment) return;

        let queueType = 'new';
        if (!hasScore) {
          const ageHours = hasValidSubmittedAt ? ((nowMs - submittedAtMs) / (60 * 60 * 1000)) : 0;
          queueType = ageHours >= REVIEW_QUEUE_OVERDUE_HOURS ? 'overdue' : 'new';
        } else if (!hasComment) {
          queueType = 'no_comment';
        }

        const dueDate = toDateOnly(column.custom_due_date || column.class_date);
        const queueKey = `${columnId}|${studentId}`;
        const reviewHref = `/journal?subject_id=${encodeURIComponent(String(subjectId))}&open_column_id=${encodeURIComponent(String(columnId))}&open_student_id=${encodeURIComponent(String(studentId))}`;
        const item = {
          queue_key: queueKey,
          queue_type: queueType,
          subject_id: subjectId,
          subject_name: subject.subject_name || 'Предмет',
          student_id: studentId,
          student_name: studentName,
          student_group: Number.isInteger(studentGroup) && studentGroup > 0 ? studentGroup : null,
          column_id: columnId,
          column_title: String(column.title || 'Колонка'),
          max_points: Number(column.max_points || 0),
          score: hasScore ? Number(cell.score) : null,
          teacher_comment: String(cell.teacher_comment || ''),
          submission_status: String(cell.status || 'missing'),
          submitted_at: submittedAt,
          submitted_at_ts: hasValidSubmittedAt ? submittedAtMs : Number.MAX_SAFE_INTEGER,
          due_date: dueDate || null,
          review_href: reviewHref,
        };
        const existing = byCellKey.get(queueKey);
        if (!existing) {
          byCellKey.set(queueKey, item);
          return;
        }
        const currentPriority = Number(priorityByType[item.queue_type] ?? 99);
        const existingPriority = Number(priorityByType[existing.queue_type] ?? 99);
        if (currentPriority < existingPriority) {
          byCellKey.set(queueKey, item);
          return;
        }
        if (currentPriority === existingPriority && item.submitted_at_ts < existing.submitted_at_ts) {
          byCellKey.set(queueKey, item);
        }
      });
    });
  }

  const allItems = Array.from(byCellKey.values()).sort((a, b) => {
    const priorityA = Number(priorityByType[a.queue_type] ?? 99);
    const priorityB = Number(priorityByType[b.queue_type] ?? 99);
    if (priorityA !== priorityB) return priorityA - priorityB;
    if (a.submitted_at_ts !== b.submitted_at_ts) return a.submitted_at_ts - b.submitted_at_ts;
    const subjectCompare = String(a.subject_name || '').localeCompare(String(b.subject_name || ''));
    if (subjectCompare !== 0) return subjectCompare;
    return String(a.student_name || '').localeCompare(String(b.student_name || ''));
  });

  const counts = { overdue: 0, new: 0, no_comment: 0 };
  allItems.forEach((item) => {
    if (Object.prototype.hasOwnProperty.call(counts, item.queue_type)) {
      counts[item.queue_type] += 1;
    }
  });

  const limitedItems = allItems.slice(0, REVIEW_QUEUE_ITEM_LIMIT).map((item) => {
    const normalized = { ...item };
    delete normalized.submitted_at_ts;
    return normalized;
  });
  return {
    enabled: true,
    overdue_threshold_hours: REVIEW_QUEUE_OVERDUE_HOURS,
    counts,
    total: allItems.length,
    items: limitedItems,
    truncated: allItems.length > REVIEW_QUEUE_ITEM_LIMIT,
    templates: REVIEW_QUEUE_FEEDBACK_TEMPLATES,
  };
}

async function buildAdminHomeworkReviewSla({
  userId,
  courseId,
  semesterId = null,
  roleKeys = [],
  now = new Date(),
}) {
  const subjectOptions = await getMyDayReviewSubjects({
    userId,
    courseId,
    roleKeys,
  });
  const subjectIds = Array.from(
    new Set(
      (subjectOptions || [])
        .map((item) => Number(item?.subject_id || 0))
        .filter((id) => Number.isFinite(id) && id > 0)
    )
  );
  const emptyResult = {
    enabled: true,
    threshold_hours: REVIEW_QUEUE_OVERDUE_HOURS,
    submissions_total: 0,
    ungraded_total: 0,
    overdue_ungraded_total: 0,
    subjects_at_risk: 0,
    subjects_with_ungraded: 0,
    max_wait_hours: 0,
    by_subject: [],
  };
  if (!subjectIds.length) {
    return emptyResult;
  }

  const reviewScope = await buildSubjectOptionStorageScope(subjectOptions, {
    fallbackCourseId: courseId,
    fallbackSemesterId: semesterId,
  });
  const semesterClause = reviewScope.owner_semester_ids.length
    ? 'AND (h.semester_id = ANY(?::int[]) OR h.semester_id IS NULL)'
    : 'AND h.semester_id IS NULL';
  const params = [
    now.toISOString(),
    REVIEW_QUEUE_OVERDUE_HOURS,
    reviewScope.subject_ids,
    reviewScope.owner_course_ids,
    ...(reviewScope.owner_semester_ids.length ? [reviewScope.owner_semester_ids] : []),
    courseId,
  ];

  const rows = await db.all(
    `
      SELECT
        h.subject_id,
        COALESCE(s.name, 'Предмет') AS subject_name,
        COUNT(*)::int AS submissions_total,
        COUNT(*) FILTER (WHERE jg.id IS NULL)::int AS ungraded_total,
        COUNT(*) FILTER (
          WHERE jg.id IS NULL
            AND hs.submitted_at <= (?::timestamptz - (? * INTERVAL '1 hour'))
        )::int AS overdue_ungraded_total,
        MIN(hs.submitted_at) FILTER (WHERE jg.id IS NULL) AS oldest_ungraded_at
      FROM homework_submissions hs
      JOIN users u ON u.id = hs.student_id
      JOIN homework h ON h.id = hs.homework_id
      JOIN subjects s ON s.id = h.subject_id
      LEFT JOIN journal_columns jc
        ON jc.source_homework_id = h.id
       AND COALESCE(jc.is_archived, 0) = 0
      LEFT JOIN journal_grades jg
        ON jg.column_id = jc.id
       AND jg.student_id = hs.student_id
       AND jg.deleted_at IS NULL
      WHERE h.subject_id = ANY(?::int[])
        AND h.course_id = ANY(?::int[])
        ${semesterClause}
        AND u.course_id = ?
        AND COALESCE(h.is_teacher_homework, 0) = 1
      GROUP BY h.subject_id, s.name
      ORDER BY overdue_ungraded_total DESC, ungraded_total DESC, subject_name ASC
    `,
    params
  );

  const nowMs = now.getTime();
  const bySubject = (rows || []).map((row) => {
    const oldestUngradedAt = row.oldest_ungraded_at ? String(row.oldest_ungraded_at) : null;
    const oldestMs = oldestUngradedAt ? new Date(oldestUngradedAt).getTime() : Number.NaN;
    const waitHours = Number.isFinite(oldestMs)
      ? Math.max(0, Math.floor((nowMs - oldestMs) / (60 * 60 * 1000)))
      : 0;
    return {
      subject_id: Number(row.subject_id || 0),
      subject_name: String(row.subject_name || 'Предмет'),
      submissions_total: Number(row.submissions_total || 0),
      ungraded_total: Number(row.ungraded_total || 0),
      overdue_ungraded_total: Number(row.overdue_ungraded_total || 0),
      oldest_ungraded_at: oldestUngradedAt,
      oldest_wait_hours: waitHours,
    };
  });

  const summary = bySubject.reduce((acc, row) => {
    acc.submissions_total += Number(row.submissions_total || 0);
    acc.ungraded_total += Number(row.ungraded_total || 0);
    acc.overdue_ungraded_total += Number(row.overdue_ungraded_total || 0);
    if (Number(row.overdue_ungraded_total || 0) > 0) {
      acc.subjects_at_risk += 1;
    }
    if (Number(row.ungraded_total || 0) > 0) {
      acc.subjects_with_ungraded += 1;
    }
    acc.max_wait_hours = Math.max(acc.max_wait_hours, Number(row.oldest_wait_hours || 0));
    return acc;
  }, {
    submissions_total: 0,
    ungraded_total: 0,
    overdue_ungraded_total: 0,
    subjects_at_risk: 0,
    subjects_with_ungraded: 0,
    max_wait_hours: 0,
  });

  return {
    enabled: true,
    threshold_hours: REVIEW_QUEUE_OVERDUE_HOURS,
    submissions_total: summary.submissions_total,
    ungraded_total: summary.ungraded_total,
    overdue_ungraded_total: summary.overdue_ungraded_total,
    subjects_at_risk: summary.subjects_at_risk,
    subjects_with_ungraded: summary.subjects_with_ungraded,
    max_wait_hours: summary.max_wait_hours,
    by_subject: bySubject
      .filter((item) => Number(item.ungraded_total || 0) > 0 || Number(item.overdue_ungraded_total || 0) > 0)
      .slice(0, HOMEWORK_REVIEW_SLA_SUBJECT_LIMIT),
  };
}

const normalizeDataQualitySeverity = (value) => {
  const normalized = String(value || '').trim().toLowerCase();
  if (normalized === 'critical') return 'critical';
  if (normalized === 'warning') return 'warning';
  return 'info';
};

const buildEmptyDataQualitySummary = () => ({
  checks_total: 0,
  checks_with_issues: 0,
  total_issues: 0,
  affected_subjects: 0,
  severity_rows: {
    critical: 0,
    warning: 0,
    info: 0,
  },
  severity_checks: {
    critical: 0,
    warning: 0,
    info: 0,
  },
});

const parseDbIntegerArray = (value) => {
  if (Array.isArray(value)) {
    return value
      .map((item) => Number(item))
      .filter((item) => Number.isInteger(item) && item > 0);
  }
  if (typeof value === 'string') {
    const trimmed = value.trim();
    if (!trimmed) return [];
    const body = trimmed.startsWith('{') && trimmed.endsWith('}')
      ? trimmed.slice(1, -1)
      : trimmed;
    if (!body) return [];
    return body
      .split(',')
      .map((item) => Number(String(item).replace(/^"+|"+$/g, '').trim()))
      .filter((item) => Number.isInteger(item) && item > 0);
  }
  return [];
};

const isDbSchemaCompatibilityError = (err) => {
  const code = String(err && err.code ? err.code : '').trim().toUpperCase();
  if (
    code === '42P01' // undefined_table
    || code === '42703' // undefined_column
    || code === '42P10' // invalid_column_reference (e.g. ON CONFLICT without matching unique index)
    || code === '42883' // undefined_function/operator (often bool vs int comparisons)
    || code === '42804' // datatype_mismatch
    || code === '22P02' // invalid_text_representation
  ) {
    return true;
  }
  // Treat SQLSTATE class 42/22 as schema/data-shape compatibility issues for legacy DB variants.
  if (code.startsWith('42') || code.startsWith('22')) {
    return true;
  }
  const message = String(err && err.message ? err.message : err || '').toLowerCase();
  if (!message) return false;
  return (
    message.includes('does not exist')
    || message.includes('no such table')
    || message.includes('no such column')
    || message.includes('undefined table')
    || message.includes('undefined column')
    || message.includes('operator does not exist')
    || message.includes('cannot cast type')
    || message.includes('invalid input syntax for type')
  );
};

const isDataQualityCompatibilityError = (err) => isDbSchemaCompatibilityError(err);

const tableColumnCache = new Map();

async function getTableColumnSet(tableName, options = {}) {
  const normalizedTableName = String(tableName || '').trim().toLowerCase();
  if (!normalizedTableName) {
    return new Set();
  }
  if (!options.refresh && tableColumnCache.has(normalizedTableName)) {
    return tableColumnCache.get(normalizedTableName);
  }
  const result = await pool.query(
    `
      SELECT column_name
      FROM information_schema.columns
      WHERE table_schema = 'public' AND table_name = $1
    `,
    [normalizedTableName]
  );
  const columns = new Set((result.rows || []).map((row) => String(row.column_name || '').trim()).filter(Boolean));
  tableColumnCache.set(normalizedTableName, columns);
  return columns;
}

