const renderViewToResponse = (res, view, payload) => new Promise((resolve, reject) => {
  res.render(view, payload, (err, html) => {
    if (err) {
      err.isViewRenderError = true;
      err.viewName = view;
      return reject(err);
    }
    if (!res.headersSent) {
      res.send(html);
    }
    return resolve();
  });
});

