const isCurrentOwnerSemesterRow = async (ownerCourseId, semesterId) => {
  const normalizedSemesterId = Number(semesterId || 0);
  if (!Number.isInteger(normalizedSemesterId) || normalizedSemesterId < 1) {
    return true;
  }
  const normalizedOwnerCourseId = Number(ownerCourseId || 0);
  if (!Number.isInteger(normalizedOwnerCourseId) || normalizedOwnerCourseId < 1) {
    return false;
  }
  try {
    const activeSemester = await getActiveSemester(normalizedOwnerCourseId);
    return Boolean(activeSemester && Number(activeSemester.id || 0) === normalizedSemesterId);
  } catch (_err) {
    return false;
  }
};

const hasCourseHomeworkAudienceAccess = async ({ courseId, activeSemester, homework, groupNumbers = [] }) => {
  const normalizedCourseId = Number(courseId || homework?.course_id || 1);
  const subjectId = Number(homework?.subject_id || 0);
  const normalizedGroupNumbers = Array.from(new Set(
    (Array.isArray(groupNumbers) ? groupNumbers : [groupNumbers])
      .map((value) => Number(value || 0))
      .filter((value) => Number.isInteger(value) && value > 0)
  ));
  const targetGroupNumber = Number(homework?.group_number || 0);
  if (!normalizedGroupNumbers.length) return false;
  if (!Number.isFinite(subjectId) || subjectId < 1) return false;

  if (Number.isInteger(targetGroupNumber) && targetGroupNumber > 0 && normalizedGroupNumbers.includes(targetGroupNumber)) {
    return true;
  }

  let canUseSharedAudience = false;
  const subjectMeta = await resolveSubjectCourseContext(subjectId, normalizedCourseId, { includeHidden: true });
  if (subjectMeta && (subjectMeta.is_general === true || Number(subjectMeta.is_general) === 1)) {
    canUseSharedAudience = true;
  }

  const dayOfWeek = normalizeWeekdayName(homework?.day_of_week);
  const classNumber = Number(homework?.class_number || 0);
  if (!canUseSharedAudience && dayOfWeek && Number.isInteger(classNumber) && classNumber > 0) {
    const storageCourseId = Number(
      (subjectMeta && (subjectMeta.owner_course_id || subjectMeta.course_id))
      || homework?.course_id
      || normalizedCourseId
      || 0
    ) || normalizedCourseId;
    const homeworkSemesterId = Number(homework?.semester_id || 0);
    let storageSemester = null;
    if (homeworkSemesterId > 0) {
      storageSemester = await db.get(
        'SELECT id, start_date FROM semesters WHERE id = ? LIMIT 1',
        [homeworkSemesterId]
      );
    }
    if (!storageSemester && storageCourseId > 0) {
      try {
        storageSemester = await getActiveSemester(storageCourseId);
      } catch (_err) {
        storageSemester = null;
      }
    }
    const params = [subjectId, storageCourseId, dayOfWeek, classNumber];
    let sql = `
      SELECT 1
      FROM schedule_entries se
      WHERE se.subject_id = ?
        AND se.course_id = ?
        AND se.day_of_week = ?
        AND se.class_number = ?
        AND COALESCE(se.lesson_type, '') = 'lecture'
    `;
    const resolvedSemesterId = Number(storageSemester && storageSemester.id ? storageSemester.id : 0);
    if (resolvedSemesterId > 0) {
      sql += ' AND (se.semester_id = ? OR se.semester_id IS NULL)';
      params.push(resolvedSemesterId);
    } else if (activeSemester && activeSemester.id) {
      sql += ' AND (se.semester_id = ? OR se.semester_id IS NULL)';
      params.push(activeSemester.id);
    }
    const classDateRaw = String(homework?.class_date || '').slice(0, 10);
    const weekSemester = storageSemester && storageSemester.start_date ? storageSemester : activeSemester;
    if (/^\d{4}-\d{2}-\d{2}$/.test(classDateRaw) && weekSemester && weekSemester.start_date) {
      const classWeek = getAcademicWeekForSemester(new Date(`${classDateRaw}T12:00:00`), weekSemester);
      if (Number.isFinite(classWeek) && classWeek > 0) {
        sql += ' AND (se.week_number = ? OR se.week_number IS NULL OR se.week_number = 0)';
        params.push(classWeek);
      }
    }
    sql += ' LIMIT 1';
    const lectureSlot = await db.get(sql, params);
    if (lectureSlot) {
      canUseSharedAudience = true;
    }
  }

  return canUseSharedAudience;
};

const hasStudentHomeworkAccess = async ({ userId, courseId, activeSemester, homework }) => {
  const normalizedUserId = Number(userId);
  const normalizedCourseId = Number(courseId || homework?.course_id || 1);
  const subjectId = Number(homework?.subject_id || 0);
  if (!Number.isFinite(normalizedUserId) || normalizedUserId < 1) return false;
  if (!Number.isFinite(subjectId) || subjectId < 1) return false;

  const subjectEnrollmentRows = await db.all(
    `
      SELECT group_number
      FROM student_groups
      WHERE student_id = ? AND subject_id = ?
    `,
    [normalizedUserId, subjectId]
  );
  const subjectGroupNumbers = Array.from(new Set(
    (subjectEnrollmentRows || [])
      .map((row) => Number(row.group_number || 0))
      .filter((value) => Number.isInteger(value) && value > 0)
  ));
  if (!subjectGroupNumbers.length) {
    return false;
  }

  return hasCourseHomeworkAudienceAccess({
    courseId: normalizedCourseId,
    activeSemester,
    homework,
    groupNumbers: subjectGroupNumbers,
  });
};

const getAdminViewAsHomeworkGroups = async (req, subjectId) => {
  const normalizedSubjectId = Number(subjectId || 0);
  const fallbackGroupNumber = Number(req?.session?.viewAsGroupNumber || req?.session?.user?.schedule_group || 1);
  if (!Number.isInteger(normalizedSubjectId) || normalizedSubjectId < 1) {
    return Number.isInteger(fallbackGroupNumber) && fallbackGroupNumber > 0 ? [fallbackGroupNumber] : [1];
  }
  const viewAsMode = String(req?.session?.viewAsMode || 'manual').trim().toLowerCase();
  if (viewAsMode !== 'self') {
    return Number.isInteger(fallbackGroupNumber) && fallbackGroupNumber > 0 ? [fallbackGroupNumber] : [1];
  }
  const userId = Number(req?.session?.user?.id || 0);
  const rows = await db.all(
    `
      SELECT group_number
      FROM student_groups
      WHERE student_id = ? AND subject_id = ?
    `,
    [userId, normalizedSubjectId]
  );
  const directGroups = Array.from(new Set(
    (rows || [])
      .map((row) => Number(row.group_number || 0))
      .filter((value) => Number.isInteger(value) && value > 0)
  ));
  if (directGroups.length) {
    return directGroups;
  }
  return Number.isInteger(fallbackGroupNumber) && fallbackGroupNumber > 0 ? [fallbackGroupNumber] : [1];
};

async function getHomeworkReactionAccess(req, homeworkId) {
  const normalizedHomeworkId = Number(homeworkId || 0);
  const userId = Number(req?.session?.user?.id || 0);
  if (!Number.isInteger(normalizedHomeworkId) || normalizedHomeworkId < 1 || !Number.isInteger(userId) || userId < 1) {
    return { status: 'invalid', homework: null };
  }
  const nowIso = new Date().toISOString();
  const homework = await db.get(
    `
      SELECT
        h.id,
        h.subject_id,
        h.group_number,
        h.day_of_week,
        h.class_number,
        h.class_date,
        h.course_id,
        h.semester_id
      FROM homework h
      WHERE h.id = ?
        AND COALESCE(h.status, 'published') = 'published'
        AND ${buildScheduledAtVisibleCondition('h.scheduled_at')}
      LIMIT 1
    `,
    [normalizedHomeworkId, nowIso]
  );
  if (!homework) {
    return { status: 'not_found', homework: null };
  }
  const storageCourseId = Number(homework.course_id || 0);
  if (!(await isCurrentOwnerSemesterRow(storageCourseId, homework.semester_id))) {
    return { status: 'not_found', homework: null };
  }

  const isAdminViewAsStudent = hasSessionRole(req, 'admin') && String(req?.session?.viewAs || '') === 'student';
  const isTeacherMode = hasSessionRole(req, 'teacher') && !isAdminViewAsStudent;
  if (isTeacherMode) {
    const teacherRows = await db.all(
      `
        SELECT ts.group_number, s.group_count
        FROM teacher_subjects ts
        JOIN subjects s ON s.id = ts.subject_id
        WHERE ts.user_id = ? AND ts.subject_id = ?
      `,
      [userId, homework.subject_id]
    );
    if (!teacherRows || !teacherRows.length) {
      return { status: 'forbidden', homework: null };
    }
    const teacherAccess = buildTeacherSubjectAccess(teacherRows, Number(teacherRows[0].group_count || 1));
    const targetGroupNumber = Number(homework.group_number || 0);
    if (Number.isInteger(targetGroupNumber) && targetGroupNumber > 0 && !teacherAccess.allowAll && !teacherAccess.groups.has(targetGroupNumber)) {
      return { status: 'forbidden', homework: null };
    }
    return { status: 'ok', homework };
  }

  const courseId = isAdminViewAsStudent
    ? Number(req?.session?.viewAsCourseId || req?.session?.user?.course_id || 1)
    : Number(req?.session?.user?.course_id || 1);
  if (!Number.isInteger(courseId) || courseId < 1) {
    return { status: 'forbidden', homework: null };
  }
  const subjectRow = await getSubjectForCourse(homework.subject_id, courseId, { includeHidden: true });
  if (!subjectRow) {
    return { status: 'not_found', homework: null };
  }
  const activeSemester = await getActiveSemester(courseId);
  if (isAdminViewAsStudent) {
    const groupNumbers = await getAdminViewAsHomeworkGroups(req, homework.subject_id);
    const access = await hasCourseHomeworkAudienceAccess({
      courseId,
      activeSemester,
      homework,
      groupNumbers,
    });
    return access ? { status: 'ok', homework } : { status: 'forbidden', homework: null };
  }
  const access = await hasStudentHomeworkAccess({
    userId,
    courseId,
    activeSemester,
    homework,
  });
  return access ? { status: 'ok', homework } : { status: 'forbidden', homework: null };
}

app.post('/api/homework/:id/complete', requireLogin, writeLimiter, async (req, res) => {
  const homeworkId = Number(req.params.id);
  if (Number.isNaN(homeworkId)) {
    return res.status(400).json({ error: 'Invalid homework' });
  }
  const { id: userId, course_id: courseId } = req.session.user;
  const activeSemester = await getActiveSemester(courseId || 1);
  const nowIso = new Date().toISOString();
  try {
    const homework = await getHomeworkForCourse(homeworkId, courseId || 1, {
      selectClause: 'h.id, h.subject_id, h.group_number, h.day_of_week, h.class_number, h.class_date, h.course_id, h.semester_id',
      extraWhere: `COALESCE(h.status, 'published') = 'published' AND ${buildScheduledAtVisibleCondition('h.scheduled_at')}`,
      extraParams: [nowIso],
    });
    if (!homework) {
      return res.status(404).json({ error: 'Not found' });
    }
    const access = await hasStudentHomeworkAccess({
      userId,
      courseId,
      activeSemester,
      homework,
    });
    if (!access) {
      return res.status(403).json({ error: 'Forbidden' });
    }
    const existing = await db.get(
      'SELECT id FROM homework_completions WHERE homework_id = ? AND user_id = ?',
      [homeworkId, userId]
    );
    if (existing) {
      await db.run('DELETE FROM homework_completions WHERE id = ?', [existing.id]);
      return res.json({ completed: false });
    }
    await db.run(
      'INSERT INTO homework_completions (user_id, homework_id, done_at) VALUES (?, ?, ?)',
      [userId, homeworkId, new Date().toISOString()]
    );
    return res.json({ completed: true });
  } catch (err) {
    return res.status(500).json({ error: 'Database error' });
  }
});

app.post('/homework/:id/submit', requireLogin, uploadLimiter, upload.single('submission_attachment'), async (req, res) => {
  const homeworkId = Number(req.params.id);
  const requestedRedirect = typeof req.body.redirect_to === 'string' ? String(req.body.redirect_to).trim() : '';
  const redirectBase = (requestedRedirect.startsWith('/my-day') || requestedRedirect.startsWith('/home'))
    ? '/home'
    : '/schedule';
  const redirectWith = (kind, message) => `${redirectBase}?${kind}=${encodeURIComponent(String(message || ''))}`;
  if (!Number.isFinite(homeworkId) || homeworkId < 1) {
    if (req.file) fs.unlink(req.file.path, () => {});
    return res.redirect(redirectWith('err', 'Invalid homework'));
  }

  const userId = Number(req.session.user.id);
  const courseId = Number(req.session.user.course_id || 1);
  const activeSemester = await getActiveSemester(courseId);
  const nowIso = new Date().toISOString();
  const submissionText = String(req.body.submission_text || '').trim();
  const rawLinkUrl = String(req.body.link_url || '').trim();
  const linkUrl = normalizeExternalUrl(rawLinkUrl);
  const filePath = req.file ? `/uploads/${req.file.filename}` : null;
  const fileName = req.file ? req.file.originalname : null;

  if (submissionText.length > 4000) {
    if (req.file) fs.unlink(req.file.path, () => {});
    return res.redirect(redirectWith('err', 'Submission text is too long'));
  }
  if (rawLinkUrl && !linkUrl) {
    if (req.file) fs.unlink(req.file.path, () => {});
    return res.redirect(redirectWith('err', 'Invalid link URL'));
  }
  if (!submissionText && !linkUrl && !req.file) {
    if (req.file) fs.unlink(req.file.path, () => {});
    return res.redirect(redirectWith('err', 'Add text, link or file'));
  }

  try {
    const homework = await getHomeworkForCourse(homeworkId, courseId, {
      selectClause: 'h.id, h.subject_id, h.group_number, h.day_of_week, h.class_number, h.course_id, h.semester_id, h.custom_due_date, h.class_date',
      extraWhere: `COALESCE(h.status, 'published') = 'published' AND ${buildScheduledAtVisibleCondition('h.scheduled_at')}`,
      extraParams: [nowIso],
    });
    if (!homework) {
      if (req.file) fs.unlink(req.file.path, () => {});
      return res.redirect(redirectWith('err', 'Homework not found'));
    }

    const studentAccess = await hasStudentHomeworkAccess({
      userId,
      courseId,
      activeSemester,
      homework,
    });
    if (!studentAccess) {
      if (req.file) fs.unlink(req.file.path, () => {});
      return res.status(403).send('Forbidden (homework submit)');
    }

    const existing = await db.get(
      `
        SELECT id, file_path
        FROM homework_submissions
        WHERE homework_id = ? AND student_id = ?
        LIMIT 1
      `,
      [homeworkId, userId]
    );
    const wasFirstSubmission = !existing;
    if (existing) {
      await db.run(
        `
          UPDATE homework_submissions
          SET submission_text = ?,
              link_url = ?,
              file_path = ?,
              file_name = ?,
              submitted_at = ?,
              updated_at = ?
          WHERE id = ?
        `,
        [
          submissionText || null,
          linkUrl || null,
          filePath || existing.file_path || null,
          fileName || null,
          nowIso,
          nowIso,
          existing.id,
        ]
      );
      if (filePath && existing.file_path && existing.file_path !== filePath) {
        const relativePath = String(existing.file_path).replace(/^\/+/, '');
        const absolutePath = path.join(__dirname, relativePath);
        fs.unlink(absolutePath, () => {});
      }
    } else {
      await db.run(
        `
          INSERT INTO homework_submissions
            (homework_id, student_id, submission_text, link_url, file_path, file_name, submitted_at, updated_at)
          VALUES (?, ?, ?, ?, ?, ?, ?, ?)
        `,
        [
          homeworkId,
          userId,
          submissionText || null,
          linkUrl || null,
          filePath,
          fileName,
          nowIso,
          nowIso,
        ]
      );
    }

    await db.run(
      `
        INSERT INTO homework_completions (user_id, homework_id, done_at)
        VALUES (?, ?, ?)
        ON CONFLICT (user_id, homework_id)
        DO UPDATE SET done_at = EXCLUDED.done_at
      `,
      [userId, homeworkId, nowIso]
    );

    if (wasFirstSubmission) {
      const deadlineDate = String(homework.custom_due_date || homework.class_date || '').trim() || null;
      const submittedDateOnly = formatLocalDate(new Date(nowIso));
      const autoScore = (deadlineDate && submittedDateOnly > deadlineDate) ? 0 : 1;
      const autoSourceRef = `homework:${homeworkId}:student:${userId}`;
      await db.run(
        `
          INSERT INTO competency_evaluations
            (
              course_id,
              semester_id,
              subject_id,
              column_id,
              student_id,
              competency_key,
              score,
              note,
              source_type,
              source_ref,
              created_by,
              created_at,
              updated_at
            )
          VALUES (?, ?, ?, NULL, ?, ?, ?, NULL, 'auto_homework_on_time', ?, NULL, NOW(), NOW())
          ON CONFLICT DO NOTHING
        `,
        [
          Number(homework.course_id || courseId) || null,
          homework.semester_id ? Number(homework.semester_id) : null,
          Number(homework.subject_id || 0),
          userId,
          'self_organization',
          autoScore,
          autoSourceRef,
        ]
      );
    }

    logActivity(
      db,
      req,
      'homework_submit',
      'homework',
      homeworkId,
      {
        subject_id: Number(homework.subject_id),
        group_number: Number(homework.group_number),
        has_text: Boolean(submissionText),
        has_link: Boolean(linkUrl),
        has_file: Boolean(filePath),
      },
      Number(homework.course_id || courseId),
      homework.semester_id ? Number(homework.semester_id) : null
    );
    return res.redirect(redirectWith('ok', 'ДЗ здано'));
  } catch (err) {
    if (req.file) fs.unlink(req.file.path, () => {});
    return res.redirect(redirectWith('err', 'Database error'));
  }
});

function detectSessionHomeworkType(description) {
  const text = String(description || '').trim().toLowerCase();
  if (!text.startsWith('[сесія]')) return null;
  if (text.includes('консультац')) return 'consultation';
  if (text.includes('залік')) return 'credit';
  if (text.includes('екзам')) return 'exam';
  return 'session';
}

function applySessionMetaFlags(target, sessionType) {
  if (!target || !sessionType) return;
  target.session_count = Number(target.session_count || 0) + 1;
  const currentKind = String(target.session_kind || '');
  if (!currentKind || currentKind === sessionType) {
    target.session_kind = sessionType;
    return;
  }
  target.session_kind = 'mixed';
}

app.get('/schedule', requireLogin, async (req, res) => {
  const { id: userId, schedule_group: group, username, course_id: courseId } = req.session.user;
  const canCreateHomework = canSessionCreateHomework(req);
  const scheduleViewRole = hasSessionRole(req, 'teacher')
    ? 'teacher'
    : (req.session.viewAs || req.session.role || '');
  const canUseCustomDeadlinesUi = canRenderCustomDeadlinesUi(req, scheduleViewRole);
  let teacherHomeworkTemplates = [];
  if (hasSessionRole(req, 'teacher')) {
    try {
      await ensureDbReady();
      const teacherSubjects = await getTeacherAssignedSubjects(userId);
      const teacherCourses = buildTeacherCourseList(teacherSubjects);
      teacherHomeworkTemplates = await getTeacherHomeworkTemplates(userId, { limit: 300 });
      const courseFilter = req.query.course ? Number(req.query.course) : null;
      const selectedCourse = teacherCourses.find((c) => Number(c.id) === Number(courseFilter)) || null;
      const courseIds = selectedCourse ? [selectedCourse.id] : teacherCourses.map((c) => c.id);
      const semesterMap = new Map();
      for (const cid of courseIds) {
        semesterMap.set(cid, await getActiveSemester(cid));
      }
      const courseWeekTime = new Map();
      for (const cid of courseIds) {
        const sem = semesterMap.get(cid);
        if (sem && sem.id) {
          courseWeekTime.set(cid, await getCourseWeekTimeMap(cid, sem.id));
        }
      }
      const ownerSemesterMap = new Map();
      for (const row of teacherSubjects) {
        const ownerCourseId = Number(row.owner_course_id || row.course_id || 0);
        if (!ownerCourseId || ownerSemesterMap.has(ownerCourseId)) continue;
        ownerSemesterMap.set(ownerCourseId, await getActiveSemester(ownerCourseId));
      }
      const primaryCourseId = selectedCourse ? selectedCourse.id : (courseIds[0] || null);
      const primarySemester = primaryCourseId ? semesterMap.get(primaryCourseId) : null;
      const totalWeeks = primarySemester && primarySemester.weeks_count ? Number(primarySemester.weeks_count) : 15;
      let selectedWeek = parseInt(req.query.week, 10);
      if (Number.isNaN(selectedWeek)) {
        selectedWeek = getAcademicWeekForSemester(new Date(), primarySemester);
      }
      if (selectedWeek < 1) selectedWeek = 1;
      if (selectedWeek > totalWeeks) selectedWeek = totalWeeks;

      let activeDaysSet = new Set();
      if (primaryCourseId) {
        if (selectedCourse) {
          const studyDays = await getCourseStudyDays(primaryCourseId);
          (studyDays || []).filter((d) => d.is_active).forEach((d) => {
            if (d.day_name) activeDaysSet.add(d.day_name);
          });
        } else {
          for (const cid of courseIds) {
            const studyDays = await getCourseStudyDays(cid);
            (studyDays || []).filter((d) => d.is_active).forEach((d) => {
              if (d.day_name) activeDaysSet.add(d.day_name);
            });
          }
        }
      }
      let activeDays = fullWeekDays.filter((day) => activeDaysSet.has(day));
      if (!activeDays.length) {
        activeDays = [...daysOfWeek];
      }
      const weekDates = fullWeekDays.map((_, idx) =>
        getDateForWeekIndex(selectedWeek, idx, primarySemester ? primarySemester.start_date : null)
      );
      const weekStartDate = weekDates[0];
      const weekEndDate = weekDates[6];
      const dayDates = {};
      activeDays.forEach((day) => {
        const idx = fullWeekDays.indexOf(day);
        dayDates[day] = idx >= 0 ? weekDates[idx] : null;
      });
      const scheduleByDay = {};
      activeDays.forEach((day) => {
        scheduleByDay[day] = [];
      });

      const selectionMap = new Map();
      teacherSubjects.forEach((row) => {
        const existing = selectionMap.get(row.subject_id) || {
          general: false,
          groups: new Set(),
          course_id: row.course_id,
          course_name: row.course_name,
          subject_name: row.subject_name,
        };
        if (row.group_number === null || typeof row.group_number === 'undefined') {
          existing.general = true;
        } else {
          existing.groups.add(Number(row.group_number));
        }
        selectionMap.set(row.subject_id, existing);
      });

      const courseNameMap = new Map(teacherCourses.map((c) => [Number(c.id), c.name]));
      const groupedMap = new Map();
      const scheduleRows = [];

      for (const cid of courseIds) {
        const scopedTeacherRows = teacherSubjects.filter((s) => Number(s.course_id) === Number(cid));
        const subjectIds = Array.from(new Set(scopedTeacherRows.map((s) => Number(s.subject_id || 0)).filter((value) => value > 0)));
        if (!subjectIds.length) continue;
        const sem = semesterMap.get(cid);
        const weekTimeMap = courseWeekTime.get(cid);
        const useLocalTime = weekTimeMap ? weekTimeMap.get(selectedWeek) === true : false;
        const placeholders = subjectIds.map(() => '?').join(',');
        const ownerCourseIds = Array.from(new Set(
          scopedTeacherRows
            .map((row) => Number(row.owner_course_id || row.course_id || 0))
            .filter((value) => Number.isInteger(value) && value > 0)
        ));
        const ownerSemesterIds = Array.from(new Set(
          ownerCourseIds
            .map((ownerCourseId) => {
              const ownerSemester = ownerSemesterMap.get(ownerCourseId);
              return ownerSemester && ownerSemester.id ? Number(ownerSemester.id) : null;
            })
            .filter((value) => Number.isInteger(value) && value > 0)
        ));
        const params = [selectedWeek];
        let sql = `
          SELECT
            se.*,
            s.name AS subject_name,
            r.label AS room_name,
            r.code AS room_code,
            r.building AS room_building
          FROM schedule_entries se
          JOIN subjects s ON s.id = se.subject_id
          LEFT JOIN rooms r ON r.id = se.room_id
          WHERE se.week_number = ?
        `;
        if (ownerCourseIds.length) {
          sql += ' AND se.course_id = ANY(?::int[])';
          params.push(ownerCourseIds);
        }
        if (ownerSemesterIds.length) {
          sql += ' AND (se.semester_id IS NULL OR se.semester_id = ANY(?::int[]))';
          params.push(ownerSemesterIds);
        }
        sql += ` AND se.subject_id IN (${placeholders})`;
        params.push(...subjectIds);
        const rows = await db.all(sql, params);
        rows.forEach((row) => {
          const selection = selectionMap.get(row.subject_id);
          if (!selection) return;
          if (!selection.general && !selection.groups.has(Number(row.group_number))) return;
          row.course_id = cid;
          row.course_name = courseNameMap.get(Number(cid)) || '';
          row.class_date = getDateForWeekDay(selectedWeek, row.day_of_week, sem ? sem.start_date : null);
          row.use_local_time = useLocalTime;
          row.room_label = row.room_id ? roomHelpers.buildRoomLabel({
            label: row.room_name,
            code: row.room_code,
            building: row.room_building,
          }) : '';
          scheduleRows.push(row);
        });
      }

      scheduleRows.forEach((row) => {
        const key = `${row.course_id}|${row.subject_id}|${row.day_of_week}|${row.class_number}|${row.room_id || 0}`;
        if (!groupedMap.has(key)) {
          groupedMap.set(key, {
            ...row,
            group_numbers: new Set(),
          });
        }
        groupedMap.get(key).group_numbers.add(Number(row.group_number));
      });

      const teacherTargets = [];
      const targetSeen = new Set();
      teacherSubjects.forEach((row) => {
        const dataCourseId = Number(row.owner_course_id || row.course_id || 0);
        const sem = ownerSemesterMap.get(dataCourseId);
        const semId = sem ? sem.id : 0;
        if (row.group_number === null || typeof row.group_number === 'undefined') {
          const maxGroups = Number(row.group_count || 1);
          for (let g = 1; g <= maxGroups; g += 1) {
            const key = `${row.subject_id}|${g}|${dataCourseId}|${semId}`;
            if (targetSeen.has(key)) continue;
            targetSeen.add(key);
            teacherTargets.push({
              subject_id: row.subject_id,
              group_number: g,
              course_id: dataCourseId,
              semester_id: semId,
            });
          }
          return;
        }
        const groupNum = Number(row.group_number);
        const key = `${row.subject_id}|${groupNum}|${dataCourseId}|${semId}`;
        if (targetSeen.has(key)) return;
        targetSeen.add(key);
        teacherTargets.push({
          subject_id: row.subject_id,
          group_number: groupNum,
          course_id: dataCourseId,
          semester_id: semId,
        });
      });
      groupedMap.forEach((entry) => {
        const groups = Array.from(entry.group_numbers).sort((a, b) => a - b);
        const selection = selectionMap.get(entry.subject_id);
        const lessonType = String(entry.lesson_type || '').toLowerCase();
        const isSeminarLike = lessonType === 'seminar' || lessonType === 'lab' || lessonType === 'practice';
        let groupLabel = '';
        if (isSeminarLike && groups.length === 1) {
          groupLabel = `Група ${groups[0]}`;
        } else if (isSeminarLike && groups.length > 1) {
          groupLabel = `Групи: ${groups.join(', ')}`;
        } else if (selection && selection.general) {
          groupLabel = 'Усі групи';
        } else if (groups.length === 1) {
          groupLabel = `Група ${groups[0]}`;
        } else {
          groupLabel = `Групи: ${groups.join(', ')}`;
        }
        const normalized = {
          ...entry,
          group_numbers: groups,
          group_number: groups[0] || null,
          group_label: groupLabel,
          is_general: selection ? selection.general : false,
        };
        if (scheduleByDay[entry.day_of_week]) {
          scheduleByDay[entry.day_of_week].push(normalized);
        }
      });

      activeDays.forEach((day) => {
        scheduleByDay[day].sort((a, b) => a.class_number - b.class_number);
      });

      const nowIso = new Date().toISOString();
      const homeworkMeta = {};
      const homeworkMetaAll = {};
      let homework = [];
      let homeworkTags = [];

      if (teacherTargets.length) {
        const hwConditions = teacherTargets
          .map(() => '(h.subject_id = ? AND h.group_number = ? AND h.course_id = ? AND COALESCE(h.semester_id, 0) = ?)')
          .join(' OR ');
        const hwParams = [];
        teacherTargets.forEach((t) => {
          hwParams.push(t.subject_id, t.group_number, t.course_id, t.semester_id);
        });
        const hwRows = await db.all(
          `
            SELECT h.*, subj.name AS subject_name, s.id AS subgroup_id, s.name AS subgroup_name, m.member_username AS subgroup_member
            FROM homework h
            JOIN subjects subj ON subj.id = h.subject_id
            LEFT JOIN subgroups s ON s.homework_id = h.id
            LEFT JOIN subgroup_members m ON m.subgroup_id = s.id
            WHERE (${hwConditions})
              AND COALESCE(h.status, 'published') = 'published'
              AND ${buildScheduledAtVisibleCondition('h.scheduled_at')}
              AND (h.is_custom_deadline IS NULL OR h.is_custom_deadline = 0)
            ORDER BY h.created_at DESC
          `,
          [...hwParams, nowIso]
        );
        const homeworkMap = new Map();
        (hwRows || []).forEach((row) => {
          if (!homeworkMap.has(row.id)) {
            const sessionType = detectSessionHomeworkType(row.description);
            homeworkMap.set(row.id, {
              id: row.id,
              group_number: row.group_number,
              subject_id: row.subject_id,
              subject: row.subject_name,
              day: normalizeWeekdayName(row.day_of_week) || String(row.day_of_week || ''),
              class_number: row.class_number,
              description: row.description,
              class_date: toDateOnly(row.class_date),
              meeting_url: row.meeting_url,
              link_url: row.link_url,
              file_path: row.file_path,
              file_name: normalizeUploadedOriginalName(row.file_name),
              created_by: row.created_by,
              created_at: row.created_at,
              is_control: Number(row.is_control || 0),
              is_teacher_homework: Number(row.is_teacher_homework || 0),
              is_credit: Number(row.is_credit || 0),
              session_type: sessionType,
              is_session: Boolean(sessionType),
              course_id: row.course_id,
              subgroups: {},
            });
          }
          if (row.subgroup_id) {
            const hw = homeworkMap.get(row.id);
            if (!hw.subgroups[row.subgroup_id]) {
              hw.subgroups[row.subgroup_id] = {
                id: row.subgroup_id,
                name: row.subgroup_name,
                members: [],
              };
            }
            if (row.subgroup_member) {
              hw.subgroups[row.subgroup_id].members.push(row.subgroup_member);
            }
          }
        });
        homework = dedupeTeacherHomeworkItems(
          Array.from(homeworkMap.values()).map((hw) => ({
            ...hw,
            subgroups: Object.values(hw.subgroups),
          }))
        );
        homework.forEach((hw) => {
          const hwDay = normalizeWeekdayName(hw.day) || String(hw.day || '');
          const hwDate = toDateOnly(hw.class_date);
          const legacyKey = `${hw.subject_id}|${hw.group_number}|${hwDay}|${hw.class_number}`;
          const key = hwDate ? `${legacyKey}|${hwDate}` : legacyKey;
          if (!homeworkMeta[key]) {
            homeworkMeta[key] = {
              count: 0,
              preview: [],
              control: false,
              teacher_homework: false,
              credit: false,
              session_kind: '',
              session_count: 0,
              meet: false,
              meet_link: '',
            };
          }
          homeworkMeta[key].count += 1;
          if (hw.is_control) {
            homeworkMeta[key].control = true;
          }
          if (hw.is_teacher_homework) {
            homeworkMeta[key].teacher_homework = true;
          }
          if (hw.is_credit) {
            homeworkMeta[key].credit = true;
          }
          applySessionMetaFlags(homeworkMeta[key], hw.session_type);
          if (hw.meeting_url) {
            homeworkMeta[key].meet = true;
            if (!homeworkMeta[key].meet_link) {
              homeworkMeta[key].meet_link = String(hw.meeting_url);
            }
          }
          if (hw.description && homeworkMeta[key].preview.length < 2) {
            homeworkMeta[key].preview.push(hw.description);
          }
          const allKey = hwDate
            ? `${hw.subject_id}|${hwDay}|${hw.class_number}|${hwDate}`
            : `${hw.subject_id}|${hwDay}|${hw.class_number}`;
          if (!homeworkMetaAll[allKey]) {
            homeworkMetaAll[allKey] = {
              count: 0,
              preview: [],
              control: false,
              teacher_homework: false,
              credit: false,
              session_kind: '',
              session_count: 0,
              meet: false,
              meet_link: '',
            };
          }
          homeworkMetaAll[allKey].count += 1;
          if (hw.is_control) {
            homeworkMetaAll[allKey].control = true;
          }
          if (hw.is_teacher_homework) {
            homeworkMetaAll[allKey].teacher_homework = true;
          }
          if (hw.is_credit) {
            homeworkMetaAll[allKey].credit = true;
          }
          applySessionMetaFlags(homeworkMetaAll[allKey], hw.session_type);
          if (hw.meeting_url) {
            homeworkMetaAll[allKey].meet = true;
            if (!homeworkMetaAll[allKey].meet_link) {
              homeworkMetaAll[allKey].meet_link = String(hw.meeting_url);
            }
          }
          if (hw.description && homeworkMetaAll[allKey].preview.length < 2) {
            homeworkMetaAll[allKey].preview.push(hw.description);
          }
        });
        const homeworkIds = homework.map((h) => h.id);
        if (homeworkIds.length) {
          const placeholders = homeworkIds.map(() => '?').join(',');
          const tagRows = await db.all(
            `SELECT ht.homework_id, t.name
             FROM homework_tag_map ht
             JOIN homework_tags t ON t.id = ht.tag_id
             WHERE ht.homework_id IN (${placeholders})`,
            homeworkIds
          );
          if (tagRows && tagRows.length) {
            const tagMap = {};
            tagRows.forEach((row) => {
              if (!tagMap[row.homework_id]) tagMap[row.homework_id] = [];
              tagMap[row.homework_id].push(row.name);
            });
            homework.forEach((hw) => {
              hw.tags = tagMap[hw.id] || [];
            });
          }
          const tagList = await db.all('SELECT name FROM homework_tags ORDER BY name');
          homeworkTags = (tagList || []).map((row) => row.name);
          const reactRows = await db.all(
            `SELECT homework_id, emoji, COUNT(*) AS count
             FROM homework_reactions
             WHERE homework_id IN (${placeholders})
             GROUP BY homework_id, emoji`,
            homeworkIds
          );
          const reactionMap = {};
          (reactRows || []).forEach((row) => {
            if (!reactionMap[row.homework_id]) reactionMap[row.homework_id] = {};
            reactionMap[row.homework_id][row.emoji] = Number(row.count || 0);
          });
          const myRows = await db.all(
            `SELECT homework_id, emoji
             FROM homework_reactions
             WHERE homework_id IN (${placeholders}) AND user_id = ?`,
            [...homeworkIds, userId]
          );
          const reactedMap = {};
          (myRows || []).forEach((row) => {
            if (!reactedMap[row.homework_id]) reactedMap[row.homework_id] = {};
            reactedMap[row.homework_id][row.emoji] = true;
          });
          homework.forEach((hw) => {
            hw.reactions = reactionMap[hw.id] || {};
            hw.reacted = reactedMap[hw.id] || {};
          });
        }
      }

      let customDeadlinesByDate = {};
      let weekendDeadlineCards = [];
      let customDeadlineItems = [];
      if (canUseCustomDeadlinesUi && teacherTargets.length && weekStartDate && weekEndDate) {
        const cdConditions = teacherTargets
          .map(() => '(h.subject_id = ? AND h.group_number = ? AND h.course_id = ? AND COALESCE(h.semester_id, 0) = ?)')
          .join(' OR ');
        const cdParams = [];
        teacherTargets.forEach((t) => {
          cdParams.push(t.subject_id, t.group_number, t.course_id, t.semester_id);
        });
        const cdRows = await db.all(
          `
            SELECT h.*, subj.name AS subject_name, c.name AS course_name
            FROM homework h
            JOIN subjects subj ON subj.id = h.subject_id
            JOIN courses c ON c.id = h.course_id
            WHERE (${cdConditions})
              AND COALESCE(h.status, 'published') = 'published'
              AND ${buildScheduledAtVisibleCondition('h.scheduled_at')}
              AND h.is_custom_deadline = 1
              AND h.custom_due_date IS NOT NULL
              AND h.custom_due_date >= ?
              AND h.custom_due_date <= ?
            ORDER BY h.custom_due_date ASC, h.created_at DESC
          `,
          [...cdParams, nowIso, weekStartDate, weekEndDate]
        );
        customDeadlineItems = dedupeTeacherHomeworkItems(cdRows || []);
        const ids = customDeadlineItems.map((row) => row.id);
        const byDate = {};
        customDeadlineItems.forEach((row) => {
          const key = row.custom_due_date;
          if (!byDate[key]) byDate[key] = [];
          byDate[key].push(row);
        });
        const weekendCards = [];
        ['Saturday', 'Sunday'].forEach((day) => {
          const idx = fullWeekDays.indexOf(day);
          const date = idx >= 0 ? weekDates[idx] : null;
          if (!date) return;
          const items = byDate[date] || [];
          if (items.length) {
            weekendCards.push({ day, date, items });
          }
        });
        customDeadlinesByDate = byDate;
        weekendDeadlineCards = weekendCards;
        if (ids.length) {
          const placeholders = ids.map(() => '?').join(',');
          const reactRows = await db.all(
            `SELECT homework_id, emoji, COUNT(*) AS count
             FROM homework_reactions
             WHERE homework_id IN (${placeholders})
             GROUP BY homework_id, emoji`,
            ids
          );
          const reactionMap = {};
          (reactRows || []).forEach((row) => {
            if (!reactionMap[row.homework_id]) reactionMap[row.homework_id] = {};
            reactionMap[row.homework_id][row.emoji] = Number(row.count || 0);
          });
          const myRows = await db.all(
            `SELECT homework_id, emoji
             FROM homework_reactions
             WHERE homework_id IN (${placeholders}) AND user_id = ?`,
            [...ids, userId]
          );
          const reactedMap = {};
          (myRows || []).forEach((row) => {
            if (!reactedMap[row.homework_id]) reactedMap[row.homework_id] = {};
            reactedMap[row.homework_id][row.emoji] = true;
          });
          customDeadlineItems.forEach((row) => {
            row.reactions = reactionMap[row.id] || {};
            row.reacted = reactedMap[row.id] || {};
          });
        }
      }

      let customDeadlineSubjects = [];
      if (canUseCustomDeadlinesUi) {
        const seenCustom = new Set();
        teacherSubjects.forEach((row) => {
          const key = `${row.subject_id}|${row.group_number || 'all'}`;
          if (seenCustom.has(key)) return;
          seenCustom.add(key);
          const generalFlag = row.is_general === false || Number(row.is_general) === 0 ? 0 : 1;
          customDeadlineSubjects.push({
            id: row.subject_id,
            name: row.subject_name,
            course_id: row.course_id,
            course_name: row.course_name,
            group_number: row.group_number,
            is_general: generalFlag,
            group_count: row.group_count,
          });
        });
      }

      return res.render('schedule', {
        scheduleByDay,
        daysOfWeek: activeDays,
        dayDates,
        currentWeek: selectedWeek,
        totalWeeks,
        semester: primarySemester,
        bellSchedule,
        group: group || 'A',
        username,
        homework,
        homeworkMeta,
        homeworkMetaAll,
        homeworkTags,
        customDeadlinesByDate,
        weekendDeadlineCards,
        customDeadlineItems,
        customDeadlineSubjects,
        subgroupError: req.query.sg || null,
        role: 'teacher',
        viewAs: req.session.viewAs || null,
        viewAsCourse: null,
        viewAsGroupNumber: null,
        messageSubjects: [],
        userId,
        teacherCourses,
        selectedCourseId: selectedCourse ? selectedCourse.id : null,
        teacherHomeworkTemplates,
        canCreateHomework,
        canUseCustomDeadlinesUi,
      });
    } catch (err) {
      return handleDbError(res, err, 'teacher.schedule');
    }
  }
  const isAdminViewAs = hasSessionRole(req, 'admin') && req.session.viewAs === 'student';
  const viewAsMode = isAdminViewAs ? (req.session.viewAsMode || 'manual') : null;
  let viewAsCourseId = isAdminViewAs ? Number(req.session.viewAsCourseId) : null;
  let viewAsGroupNumber = isAdminViewAs ? Number(req.session.viewAsGroupNumber) : null;
  if (isAdminViewAs) {
    if (viewAsMode === 'self') {
      viewAsCourseId = Number.isFinite(Number(courseId)) ? Number(courseId) : 1;
      req.session.viewAsCourseId = viewAsCourseId;
      viewAsGroupNumber = null;
      req.session.viewAsGroupNumber = null;
    } else if (!Number.isFinite(viewAsCourseId)) {
      viewAsCourseId = Number.isFinite(Number(courseId)) ? Number(courseId) : 1;
      req.session.viewAsCourseId = viewAsCourseId;
    }
    if (viewAsMode !== 'self' && (!Number.isFinite(viewAsGroupNumber) || viewAsGroupNumber < 1)) {
      viewAsGroupNumber = 1;
      req.session.viewAsGroupNumber = viewAsGroupNumber;
    }
  }
  const scheduleCourseId = isAdminViewAs && Number.isFinite(viewAsCourseId)
    ? viewAsCourseId
    : (courseId || 1);
  const viewAsCourse = isAdminViewAs ? await getCourseById(scheduleCourseId) : null;
  const parsePreferredGroupNumber = (rawValue) => {
    const parsed = Number(rawValue);
    if (!Number.isInteger(parsed) || parsed < 1) return null;
    return parsed;
  };
  const selfFallbackGroupNumber = (isAdminViewAs && viewAsMode === 'self')
    ? (
      parsePreferredGroupNumber(req.query.group_number)
      || parsePreferredGroupNumber(req.query.group)
      || parsePreferredGroupNumber(req.session.viewAsGroupNumber)
      || parsePreferredGroupNumber(req.session.user && req.session.user.schedule_group)
      || 1
    )
    : null;
  const adminFallbackGroupNumber = (!isAdminViewAs && hasSessionRole(req, 'admin'))
    ? (
      parsePreferredGroupNumber(req.query.group_number)
      || parsePreferredGroupNumber(req.query.group)
      || parsePreferredGroupNumber(req.session.user && req.session.user.schedule_group)
      || 1
    )
    : null;
  const effectiveViewAsGroupNumber = isAdminViewAs
    ? (viewAsMode === 'self' ? selfFallbackGroupNumber : (parsePreferredGroupNumber(viewAsGroupNumber) || 1))
    : null;
  const viewAsLabel = isAdminViewAs
    ? (viewAsMode === 'self' ? 'Ваші групи' : `Група ${effectiveViewAsGroupNumber || 1}`)
    : null;

  const activeSemester = await getActiveSemester(scheduleCourseId);
  const totalWeeks = activeSemester && activeSemester.weeks_count ? Number(activeSemester.weeks_count) : 15;
  let selectedWeek = parseInt(req.query.week, 10);
  if (Number.isNaN(selectedWeek)) {
    selectedWeek = getAcademicWeekForSemester(new Date(), activeSemester);
  }
  if (selectedWeek < 1) selectedWeek = 1;
  if (selectedWeek < 1) selectedWeek = 1;
  if (selectedWeek > totalWeeks) selectedWeek = totalWeeks;
  const weekTimeMap = activeSemester && activeSemester.id
    ? await getCourseWeekTimeMap(scheduleCourseId, activeSemester.id)
    : new Map();
  const useLocalTime = weekTimeMap.get(selectedWeek) === true;
  const studyDays = await getCourseStudyDays(scheduleCourseId);
  let activeDays = studyDays
    .filter((day) => day.is_active)
    .map((day) => fullWeekDays[day.weekday - 1])
    .filter(Boolean);
  if (!activeDays.length) {
    activeDays = [...daysOfWeek];
  }
  const weekDates = fullWeekDays.map((_, idx) =>
    getDateForWeekIndex(selectedWeek, idx, activeSemester ? activeSemester.start_date : null)
  );
  const weekStartDate = weekDates[0];
  const weekEndDate = weekDates[6];
  const nowIso = new Date().toISOString();

  const expandSubjectGroupsForCourse = (subjects = []) => {
    const groups = [];
    (subjects || []).forEach((subject) => {
      const subjectId = Number(subject.subject_id);
      const groupCount = Math.max(1, Number(subject.group_count || 1));
      const ownerCourseId = Number(subject.owner_course_id || subject.course_id || scheduleCourseId || 0) || null;
      for (let groupNumber = 1; groupNumber <= groupCount; groupNumber += 1) {
        groups.push({
          subject_id: subjectId,
          group_number: groupNumber,
          subject_name: subject.subject_name,
          owner_course_id: ownerCourseId,
        });
      }
    });
    return groups;
  };

  const loadAllCourseSubjectGroups = (cb) => {
    (async () => {
      try {
        const subjects = await getSubjectsCached(scheduleCourseId, { visibleOnly: true });
        const rows = (subjects || []).map((subject) => ({
          subject_id: Number(subject.id || 0),
          subject_name: subject.name,
          group_count: subject.group_count,
          owner_course_id: Number(subject.owner_course_id || subject.course_id || 0) || null,
        }));
        return cb(null, expandSubjectGroupsForCourse(rows));
      } catch (err) {
        return cb(err);
      }
    })();
  };

  const loadCourseSubjectGroupsForSingleGroup = (requestedGroupNumber, cb) => {
    (async () => {
      try {
        const subjects = await getSubjectsCached(scheduleCourseId, { visibleOnly: true });
        const fallbackGroup = parsePreferredGroupNumber(requestedGroupNumber) || 1;
        const groups = (subjects || []).map((subject) => {
          const maxGroups = Math.max(1, Number(subject.group_count || 1));
          return {
            subject_id: Number(subject.id || 0),
            group_number: Math.min(fallbackGroup, maxGroups),
            subject_name: subject.name,
            owner_course_id: Number(subject.owner_course_id || subject.course_id || 0) || null,
          };
        });
        return cb(null, groups);
      } catch (err) {
        return cb(err);
      }
    })();
  };

  const loadStudentGroups = (cb) => {
    if (!isAdminViewAs) {
      if (hasSessionRole(req, 'admin')) {
        return loadCourseSubjectGroupsForSingleGroup(adminFallbackGroupNumber, cb);
      }
      return db.all(
        `
          SELECT sg.subject_id, sg.group_number, s.name AS subject_name, s.course_id AS owner_course_id
          FROM student_groups sg
          JOIN subjects s ON s.id = sg.subject_id
          JOIN subject_course_bindings scb ON scb.subject_id = s.id
          WHERE sg.student_id = ?
            AND scb.course_id = ?
            AND s.visible = 1
        `,
        [userId, scheduleCourseId],
        cb
      );
    }
    if (viewAsMode === 'self') {
      return db.all(
        `
          SELECT sg.subject_id, sg.group_number, s.name AS subject_name, s.course_id AS owner_course_id
          FROM student_groups sg
          JOIN subjects s ON s.id = sg.subject_id
          JOIN subject_course_bindings scb ON scb.subject_id = s.id
          WHERE sg.student_id = ?
            AND scb.course_id = ?
            AND s.visible = 1
        `,
        [userId, scheduleCourseId],
        (err, rows) => {
          if (err) {
            return cb(err);
          }
          if (Array.isArray(rows) && rows.length) {
            return cb(null, rows);
          }
          return loadCourseSubjectGroupsForSingleGroup(selfFallbackGroupNumber, cb);
        }
      );
    }
    db.all(
      `
        SELECT s.id AS subject_id, s.name AS subject_name, s.group_count, s.course_id AS owner_course_id
        FROM subjects s
        JOIN subject_course_bindings scb ON scb.subject_id = s.id
        WHERE scb.course_id = ? AND s.visible = 1
        ORDER BY name
      `,
      [scheduleCourseId],
      (err, subjects) => {
        if (err) {
          return cb(err);
        }
        const groupNumber = Number.isFinite(viewAsGroupNumber) ? viewAsGroupNumber : 1;
        const groups = (subjects || [])
          .filter((s) => Number(s.group_count || 1) >= groupNumber)
          .map((s) => ({
            subject_id: s.subject_id,
            group_number: groupNumber,
            subject_name: s.subject_name,
            owner_course_id: Number(s.owner_course_id || 0) || null,
          }));
        return cb(null, groups);
      }
    );
  };

  loadStudentGroups(async (groupErr, studentGroups) => {
      if (groupErr) {
        return res.status(500).send('Database error');
      }

      const scheduleByDay = {};
      activeDays.forEach((day) => {
        scheduleByDay[day] = [];
      });
      const dayDates = {};
      activeDays.forEach((day) => {
        const idx = fullWeekDays.indexOf(day);
        dayDates[day] = idx >= 0 ? weekDates[idx] : null;
      });
      const customDeadlineSubjects = [];
      if (canUseCustomDeadlinesUi) {
        const subjectSeen = new Set();
        studentGroups.forEach((sg) => {
          if (!subjectSeen.has(sg.subject_id)) {
            subjectSeen.add(sg.subject_id);
            customDeadlineSubjects.push({ id: sg.subject_id, name: sg.subject_name });
          }
        });
      }

      const ownerSemesterMap = new Map();
      for (const row of (studentGroups || [])) {
        const ownerCourseId = Number(row.owner_course_id || 0);
        if (!ownerCourseId || ownerSemesterMap.has(ownerCourseId)) continue;
        ownerSemesterMap.set(ownerCourseId, await getActiveSemester(ownerCourseId));
      }

      const buildHomeworkTargets = (baseGroups = [], scheduleRows = []) => {
        const map = new Map();
        const baseGroupsBySubject = new Map();
        (baseGroups || []).forEach((item) => {
          const subjectId = Number(item.subject_id);
          const groupNumber = Number(item.group_number);
          if (!Number.isFinite(subjectId) || !Number.isFinite(groupNumber)) return;
          if (!baseGroupsBySubject.has(subjectId)) {
            baseGroupsBySubject.set(subjectId, new Set());
          }
          baseGroupsBySubject.get(subjectId).add(groupNumber);
          const key = `${subjectId}|${groupNumber}`;
          if (!map.has(key)) {
            map.set(key, {
              subject_id: subjectId,
              group_number: groupNumber,
              subject_name: item.subject_name || '',
              owner_course_id: Number(item.owner_course_id || 0) || null,
              semester_id: Number((ownerSemesterMap.get(Number(item.owner_course_id || 0)) || {}).id || 0),
            });
          }
        });
        (scheduleRows || []).forEach((row) => {
          const subjectId = Number(row.subject_id);
          const groupNumber = Number(row.group_number);
          if (!Number.isFinite(subjectId) || !Number.isFinite(groupNumber) || groupNumber < 1) return;
          const isLectureSlot = String(row.lesson_type || '').toLowerCase() === 'lecture';
          if (baseGroupsBySubject.size) {
            const allowedGroups = baseGroupsBySubject.get(subjectId);
            if (!isLectureSlot && (!allowedGroups || !allowedGroups.has(groupNumber))) {
              return;
            }
          }
          const key = `${subjectId}|${groupNumber}`;
          if (!map.has(key)) {
            map.set(key, {
              subject_id: subjectId,
              group_number: groupNumber,
              subject_name: row.subject_name || '',
              owner_course_id: Number(row.owner_course_id || 0) || null,
              semester_id: Number((ownerSemesterMap.get(Number(row.owner_course_id || 0)) || {}).id || 0),
            });
          }
        });
        return Array.from(map.values());
      };

      const loadCustomDeadlines = (homeworkTargets, cb) => {
        if (!canUseCustomDeadlinesUi) {
          return cb({}, [], []);
        }
        if (!homeworkTargets.length || !weekStartDate || !weekEndDate) {
          return cb({}, [], []);
        }
        const conditions = homeworkTargets
          .map(() => '(h.subject_id = ? AND h.group_number = ? AND h.course_id = ? AND COALESCE(h.semester_id, 0) = ?)')
          .join(' OR ');
        const params = [];
        homeworkTargets.forEach((sg) => {
          params.push(sg.subject_id, sg.group_number, sg.owner_course_id || scheduleCourseId, sg.semester_id || 0);
        });
        const sql = `
          SELECT h.*, subj.name AS subject_name
          FROM homework h
          JOIN subjects subj ON subj.id = h.subject_id
          WHERE (${conditions})
            AND COALESCE(h.status, 'published') = 'published'
            AND ${buildScheduledAtVisibleCondition('h.scheduled_at')}
            AND h.is_custom_deadline = 1
            AND h.custom_due_date IS NOT NULL
            AND h.custom_due_date >= ?
            AND h.custom_due_date <= ?
          ORDER BY h.custom_due_date ASC, h.created_at DESC
        `;
        db.all(sql, [...params, nowIso, weekStartDate, weekEndDate], (err, rows) => {
          if (err) {
            return cb({}, [], []);
          }
          const rowsList = rows || [];
          const ids = rowsList.map((row) => row.id);
          const byDate = {};
          rowsList.forEach((row) => {
            const key = row.custom_due_date;
            if (!byDate[key]) byDate[key] = [];
            byDate[key].push(row);
          });
          const weekendCards = [];
          ['Saturday', 'Sunday'].forEach((day) => {
            const idx = fullWeekDays.indexOf(day);
            const date = idx >= 0 ? weekDates[idx] : null;
            if (!date) return;
            const items = byDate[date] || [];
            if (items.length) {
              weekendCards.push({ day, date, items });
            }
          });
          if (!ids.length) {
            return cb(byDate, weekendCards, rowsList);
          }
          const placeholders = ids.map(() => '?').join(',');
          db.all(
            `SELECT homework_id, emoji, COUNT(*) AS count
             FROM homework_reactions
             WHERE homework_id IN (${placeholders})
             GROUP BY homework_id, emoji`,
            ids,
            (reactErr, reactRows) => {
              const reactionMap = {};
              if (!reactErr && reactRows) {
                reactRows.forEach((row) => {
                  if (!reactionMap[row.homework_id]) reactionMap[row.homework_id] = {};
                  reactionMap[row.homework_id][row.emoji] = Number(row.count || 0);
                });
              }
              db.all(
                `SELECT homework_id, emoji
                 FROM homework_reactions
                 WHERE homework_id IN (${placeholders}) AND user_id = ?`,
                [...ids, userId],
                (myErr, myRows) => {
                  const reactedMap = {};
                  if (!myErr && myRows) {
                    myRows.forEach((row) => {
                      if (!reactedMap[row.homework_id]) reactedMap[row.homework_id] = {};
                      reactedMap[row.homework_id][row.emoji] = true;
                    });
                  }
                  rowsList.forEach((row) => {
                    row.reactions = reactionMap[row.id] || {};
                    row.reacted = reactedMap[row.id] || {};
                  });
                  return cb(byDate, weekendCards, rowsList);
                }
              );
            }
          );
        });
      };

      const loadHomework = (homeworkTargets) => {
        if (!homeworkTargets.length) {
          return loadCustomDeadlines(homeworkTargets, (customDeadlinesByDate, weekendDeadlineCards, customDeadlineItems) =>
            res.render('schedule', {
            scheduleByDay,
            daysOfWeek: activeDays,
            dayDates,
              currentWeek: selectedWeek,
              totalWeeks,
              semester: activeSemester,
              bellSchedule,
              group: isAdminViewAs ? `Група ${effectiveViewAsGroupNumber || 1}` : (group || 'A'),
              username,
              homework: [],
              homeworkMeta: {},
              homeworkMetaAll: {},
              homeworkTags: [],
              customDeadlinesByDate,
              weekendDeadlineCards,
              customDeadlineItems,
              customDeadlineSubjects,
              subgroupError: req.query.sg || null,
              role: req.session.role,
              viewAs: req.session.viewAs || null,
              viewAsCourse,
              viewAsGroupNumber: isAdminViewAs ? effectiveViewAsGroupNumber : null,
              viewAsLabel,
              messageSubjects: studentGroups || [],
              userId,
              selectedCourseId: scheduleCourseId,
              teacherHomeworkTemplates,
              canCreateHomework,
              canUseCustomDeadlinesUi,
            })
          );
        }

        const hwConditions = homeworkTargets
          .map(() => '(h.subject_id = ? AND h.group_number = ? AND h.course_id = ? AND COALESCE(h.semester_id, 0) = ?)')
          .join(' OR ');
        const hwParams = [];
        homeworkTargets.forEach((sg) => {
          hwParams.push(sg.subject_id, sg.group_number, sg.owner_course_id || scheduleCourseId, sg.semester_id || 0);
        });

        db.all(
          `
            SELECT
              h.*,
              subj.name AS subject_name,
              r.label AS room_name,
              r.code AS room_code,
              r.building AS room_building,
              hs.submitted_at AS submission_submitted_at,
              s.id AS subgroup_id,
              s.name AS subgroup_name,
              m.member_username AS subgroup_member
            FROM homework h
            JOIN subjects subj ON subj.id = h.subject_id
            LEFT JOIN rooms r ON r.id = h.room_id
            LEFT JOIN homework_submissions hs ON hs.homework_id = h.id AND hs.student_id = ?
            LEFT JOIN subgroups s ON s.homework_id = h.id
            LEFT JOIN subgroup_members m ON m.subgroup_id = s.id
            WHERE (${hwConditions})
              AND COALESCE(h.status, 'published') = 'published'
              AND ${buildScheduledAtVisibleCondition('h.scheduled_at')}
              AND (h.is_custom_deadline IS NULL OR h.is_custom_deadline = 0)
            ORDER BY h.created_at DESC
          `,
          [userId, ...hwParams, nowIso],
          (err, rows) => {
            if (err) {
              return res.status(500).send('Database error');
            }

            const homeworkMap = new Map();
            rows.forEach((row) => {
              if (!homeworkMap.has(row.id)) {
                const sessionType = detectSessionHomeworkType(row.description);
                homeworkMap.set(row.id, {
                  id: row.id,
                  group_number: row.group_number,
                  subject_id: row.subject_id,
                  subject: row.subject_name,
                  day: normalizeWeekdayName(row.day_of_week) || String(row.day_of_week || ''),
                  class_number: row.class_number,
                  description: row.description,
                  class_date: toDateOnly(row.class_date),
                  meeting_url: row.meeting_url,
                  link_url: row.link_url,
                  file_path: row.file_path,
                  file_name: normalizeUploadedOriginalName(row.file_name),
                  room_label: row.room_id ? roomHelpers.buildRoomLabel({
                    label: row.room_name,
                    code: row.room_code,
                    building: row.room_building,
                  }) : '',
                  created_by: row.created_by,
                  created_at: row.created_at,
                  submitted_at: row.submission_submitted_at || null,
                  is_control: Number(row.is_control || 0),
                  is_teacher_homework: Number(row.is_teacher_homework || 0),
                  is_credit: Number(row.is_credit || 0),
                  session_type: sessionType,
                  is_session: Boolean(sessionType),
                  course_id: row.course_id,
                  subgroups: {},
                });
              }
              if (row.subgroup_id) {
                const hw = homeworkMap.get(row.id);
                if (!hw.subgroups[row.subgroup_id]) {
                  hw.subgroups[row.subgroup_id] = {
                    id: row.subgroup_id,
                    name: row.subgroup_name,
                    members: [],
                  };
                }
                if (row.subgroup_member) {
                  hw.subgroups[row.subgroup_id].members.push(row.subgroup_member);
                }
              }
            });

            const homework = Array.from(homeworkMap.values()).map((hw) => ({
              ...hw,
              subgroups: Object.values(hw.subgroups),
            }));
            const homeworkMeta = {};
            const homeworkMetaAll = {};
            homework.forEach((hw) => {
              const hwDay = normalizeWeekdayName(hw.day) || String(hw.day || '');
              const hwDate = toDateOnly(hw.class_date);
              const legacyKey = `${hw.subject_id}|${hw.group_number}|${hwDay}|${hw.class_number}`;
              const key = hwDate ? `${legacyKey}|${hwDate}` : legacyKey;
              if (!homeworkMeta[key]) {
                homeworkMeta[key] = {
                  count: 0,
                  preview: [],
                  control: false,
                  teacher_homework: false,
                  credit: false,
                  session_kind: '',
                  session_count: 0,
                  meet: false,
                  meet_link: '',
                };
              }
              homeworkMeta[key].count += 1;
              if (hw.is_control) {
                homeworkMeta[key].control = true;
              }
              if (hw.is_teacher_homework) {
                homeworkMeta[key].teacher_homework = true;
              }
              if (hw.is_credit) {
                homeworkMeta[key].credit = true;
              }
              applySessionMetaFlags(homeworkMeta[key], hw.session_type);
              if (hw.meeting_url) {
                homeworkMeta[key].meet = true;
                if (!homeworkMeta[key].meet_link) {
                  homeworkMeta[key].meet_link = String(hw.meeting_url);
                }
              }
              if (hw.description && homeworkMeta[key].preview.length < 2) {
                homeworkMeta[key].preview.push(hw.description);
              }
              const allKey = hwDate
                ? `${hw.subject_id}|${hwDay}|${hw.class_number}|${hwDate}`
                : `${hw.subject_id}|${hwDay}|${hw.class_number}`;
              if (!homeworkMetaAll[allKey]) {
                homeworkMetaAll[allKey] = {
                  count: 0,
                  preview: [],
                  control: false,
                  teacher_homework: false,
                  credit: false,
                  session_kind: '',
                  session_count: 0,
                  meet: false,
                  meet_link: '',
                };
              }
              homeworkMetaAll[allKey].count += 1;
              if (hw.is_control) {
                homeworkMetaAll[allKey].control = true;
              }
              if (hw.is_teacher_homework) {
                homeworkMetaAll[allKey].teacher_homework = true;
              }
              if (hw.is_credit) {
                homeworkMetaAll[allKey].credit = true;
              }
              applySessionMetaFlags(homeworkMetaAll[allKey], hw.session_type);
              if (hw.meeting_url) {
                homeworkMetaAll[allKey].meet = true;
                if (!homeworkMetaAll[allKey].meet_link) {
                  homeworkMetaAll[allKey].meet_link = String(hw.meeting_url);
                }
              }
              if (hw.description && homeworkMetaAll[allKey].preview.length < 2) {
                homeworkMetaAll[allKey].preview.push(hw.description);
              }
            });

            const homeworkIds = homework.map((h) => h.id);
            const finalizeRender = (tagOptions = [], customDeadlinesByDate = {}, weekendDeadlineCards = [], customDeadlineItems = []) => {
              res.render('schedule', {
                scheduleByDay,
                daysOfWeek: activeDays,
                dayDates,
                currentWeek: selectedWeek,
                totalWeeks,
                semester: activeSemester,
                bellSchedule,
                group: isAdminViewAs ? `Група ${effectiveViewAsGroupNumber || 1}` : (group || 'A'),
                username,
                homework,
                homeworkMeta,
                homeworkMetaAll,
                homeworkTags: tagOptions,
                customDeadlinesByDate,
                weekendDeadlineCards,
                customDeadlineItems,
                customDeadlineSubjects,
                subgroupError: req.query.sg || null,
                role: req.session.role,
                viewAs: req.session.viewAs || null,
                viewAsCourse,
                viewAsGroupNumber: isAdminViewAs ? effectiveViewAsGroupNumber : null,
                viewAsLabel,
                messageSubjects: studentGroups || [],
                userId,
                selectedCourseId: scheduleCourseId,
                teacherHomeworkTemplates,
                canCreateHomework,
                canUseCustomDeadlinesUi,
              });
            };

            if (!homeworkIds.length) {
              return loadCustomDeadlines(homeworkTargets, (customDeadlinesByDate, weekendDeadlineCards, customDeadlineItems) =>
                finalizeRender([], customDeadlinesByDate, weekendDeadlineCards, customDeadlineItems)
              );
            }
            const placeholders = homeworkIds.map(() => '?').join(',');
            db.all(
              `SELECT ht.homework_id, t.name
               FROM homework_tag_map ht
               JOIN homework_tags t ON t.id = ht.tag_id
               WHERE ht.homework_id IN (${placeholders})`,
              homeworkIds,
              (tagErr, tagRows) => {
                if (!tagErr && tagRows) {
                  const tagMap = {};
                  tagRows.forEach((row) => {
                    if (!tagMap[row.homework_id]) tagMap[row.homework_id] = [];
                    tagMap[row.homework_id].push(row.name);
                  });
                  homework.forEach((hw) => {
                    hw.tags = tagMap[hw.id] || [];
                  });
                }
                db.all('SELECT name FROM homework_tags ORDER BY name', (tagListErr, tagList) => {
                  const tagOptions = !tagListErr && tagList ? tagList.map((t) => t.name) : [];
                  db.all(
                    `SELECT homework_id, emoji, COUNT(*) AS count
                     FROM homework_reactions
                     WHERE homework_id IN (${placeholders})
                     GROUP BY homework_id, emoji`,
                    homeworkIds,
                    (reactErr, reactRows) => {
                      const reactionMap = {};
                      if (!reactErr && reactRows) {
                        reactRows.forEach((row) => {
                          if (!reactionMap[row.homework_id]) reactionMap[row.homework_id] = {};
                          reactionMap[row.homework_id][row.emoji] = Number(row.count || 0);
                        });
                      }
                      db.all(
                        `SELECT homework_id, emoji
                         FROM homework_reactions
                         WHERE homework_id IN (${placeholders}) AND user_id = ?`,
                        [...homeworkIds, userId],
                        (myErr, myRows) => {
                          const reactedMap = {};
                          if (!myErr && myRows) {
                            myRows.forEach((row) => {
                              if (!reactedMap[row.homework_id]) reactedMap[row.homework_id] = {};
                              reactedMap[row.homework_id][row.emoji] = true;
                            });
                          }
                          homework.forEach((hw) => {
                            hw.reactions = reactionMap[hw.id] || {};
                            hw.reacted = reactedMap[hw.id] || {};
                          });
                          listHomeworkAssetsByHomeworkIds(homeworkIds)
                            .then((homeworkAssetMap) => {
                              homework.forEach((hw) => {
                                hw.assets = homeworkAssetMap.get(hw.id) || [];
                              });
                            })
                            .catch((err) => {
                              if (!isDbSchemaCompatibilityError(err)) {
                                console.error('Homework asset map load failed', err);
                              }
                            })
                            .finally(() => {
                              loadCustomDeadlines(homeworkTargets, (customDeadlinesByDate, weekendDeadlineCards, customDeadlineItems) =>
                                finalizeRender(tagOptions, customDeadlinesByDate, weekendDeadlineCards, customDeadlineItems)
                              );
                            });
                        }
                      );
                    }
                  );
                });
              }
            );
          }
        );
      };

      const conditionParts = [];
      const ownerCourseIds = Array.from(new Set(
        (studentGroups || [])
          .map((row) => Number(row.owner_course_id || 0))
          .filter((value) => Number.isInteger(value) && value > 0)
      ));
      const ownerSemesterIds = Array.from(new Set(
        ownerCourseIds
          .map((ownerCourseId) => {
            const ownerSemester = ownerSemesterMap.get(ownerCourseId);
            return ownerSemester && ownerSemester.id ? Number(ownerSemester.id) : null;
          })
          .filter((value) => Number.isInteger(value) && value > 0)
      ));
      const params = [selectedWeek];
      const scopeParams = [];
      if (studentGroups.length) {
        conditionParts.push(
          studentGroups.map(() => "(se.subject_id = ? AND (se.group_number = ? OR COALESCE(se.lesson_type, '') = 'lecture'))").join(' OR ')
        );
        studentGroups.forEach((sg) => {
          scopeParams.push(sg.subject_id, sg.group_number);
        });
      }

        let sql = `
          SELECT
            se.*,
            s.name AS subject_name,
            r.label AS room_name,
            r.code AS room_code,
            r.building AS room_building
          FROM schedule_entries se
          JOIN subjects s ON s.id = se.subject_id
          LEFT JOIN rooms r ON r.id = se.room_id
          WHERE se.week_number = ? AND s.visible = 1
      `;
      if (ownerCourseIds.length) {
        sql += ' AND se.course_id = ANY(?::int[])';
        params.push(ownerCourseIds);
      }
      if (ownerSemesterIds.length) {
        sql += ' AND (se.semester_id IS NULL OR se.semester_id = ANY(?::int[]))';
        params.push(ownerSemesterIds);
      }
      if (conditionParts.length) {
        sql += ` AND (${conditionParts.join(' OR ')})`;
        params.push(...scopeParams);
      }

      db.all(sql, params, (scheduleErr, rows) => {
        if (scheduleErr) {
          return res.status(500).send('Database error');
        }
        rows.forEach((row) => {
          row.owner_course_id = Number(row.course_id || 0) || null;
          row.class_date = getDateForWeekDay(selectedWeek, row.day_of_week, activeSemester ? activeSemester.start_date : null);
          row.use_local_time = useLocalTime;
          row.room_label = row.room_id ? roomHelpers.buildRoomLabel({
            label: row.room_name,
            code: row.room_code,
            building: row.room_building,
          }) : '';
          if (scheduleByDay[row.day_of_week]) {
            scheduleByDay[row.day_of_week].push(row);
          }
        });
        activeDays.forEach((day) => {
          scheduleByDay[day].sort((a, b) => a.class_number - b.class_number);
        });
        const homeworkTargets = buildHomeworkTargets(studentGroups, rows || []);
        return loadHomework(homeworkTargets);
      });
    }
  );
});

const normalizeTeamworkLessonScope = (value) => {
  return String(value || '').toLowerCase() === 'seminar' ? 'seminar' : 'lecture';
};

const parseTeamworkGroupNumbers = (rawValue, maxGroupCount = 1) => {
  const safeMaxGroupCount = Math.max(1, Number(maxGroupCount) || 1);
  if (rawValue === null || typeof rawValue === 'undefined') {
    return { all: true, groups: [] };
  }

  const rawTokens = Array.isArray(rawValue) ? rawValue : String(rawValue).split(',');
  const groups = new Set();
  let all = false;

  rawTokens.forEach((tokenValue) => {
    const token = String(tokenValue || '').trim().toLowerCase();
    if (!token) return;
    if (token === 'all') {
      all = true;
      return;
    }
    const groupNum = Number(token);
    if (Number.isInteger(groupNum) && groupNum >= 1 && groupNum <= safeMaxGroupCount) {
      groups.add(groupNum);
    }
  });

  return {
    all,
    groups: Array.from(groups).sort((a, b) => a - b),
  };
};

const serializeTeamworkGroupNumbers = (groupNumbers) => {
  if (!Array.isArray(groupNumbers) || !groupNumbers.length) {
    return null;
  }
  return groupNumbers.join(',');
};

const buildTeamworkRandomDistribution = ({
  students = [],
  bucketCount = 1,
  limitsEnabled = false,
  minMembers = null,
  maxMembers = null,
}) => {
  const normalizedBucketCount = Math.max(1, Number(bucketCount) || 1);
  const shuffled = [...students];
  for (let index = shuffled.length - 1; index > 0; index -= 1) {
    const randomIndex = Math.floor(Math.random() * (index + 1));
    const current = shuffled[index];
    shuffled[index] = shuffled[randomIndex];
    shuffled[randomIndex] = current;
  }

  const distribution = Array.from({ length: normalizedBucketCount }, () => []);
  let cursor = 0;
  if (limitsEnabled && Number(minMembers) > 0) {
    for (let groupIndex = 0; groupIndex < normalizedBucketCount; groupIndex += 1) {
      for (let memberIndex = 0; memberIndex < Number(minMembers); memberIndex += 1) {
        if (cursor >= shuffled.length) break;
        distribution[groupIndex].push(shuffled[cursor]);
        cursor += 1;
      }
    }
  }

  while (cursor < shuffled.length) {
    const groupOrder = distribution
      .map((bucket, groupIndex) => ({ groupIndex, size: bucket.length }))
      .sort((a, b) => a.size - b.size || a.groupIndex - b.groupIndex);
    let placed = false;
    for (const group of groupOrder) {
      if (limitsEnabled && maxMembers && distribution[group.groupIndex].length >= Number(maxMembers)) continue;
      distribution[group.groupIndex].push(shuffled[cursor]);
      cursor += 1;
      placed = true;
      break;
    }
    if (!placed) return null;
  }

  return distribution;
};

const buildTeacherSubjectAccess = (rows, maxGroupCount = 1) => {
  const safeMaxGroupCount = Math.max(1, Number(maxGroupCount) || 1);
  const hasRows = Array.isArray(rows) && rows.length > 0;
  if (!hasRows) {
    return { hasRows: false, allowAll: false, groups: new Set() };
  }

  const allowAll = rows.some((row) => row.group_number === null || typeof row.group_number === 'undefined');
  if (allowAll) {
    return {
      hasRows: true,
      allowAll: true,
      groups: new Set(Array.from({ length: safeMaxGroupCount }, (_v, index) => index + 1)),
    };
  }

  const groups = new Set();
  rows.forEach((row) => {
    const groupNum = Number(row.group_number);
    if (Number.isInteger(groupNum) && groupNum >= 1 && groupNum <= safeMaxGroupCount) {
      groups.add(groupNum);
    }
  });

  return {
    hasRows: true,
    allowAll: false,
    groups,
  };
};

const buildTeamworkTaskAudience = (task, teacherAccess, maxGroupCount = 1) => {
  const safeMaxGroupCount = Math.max(1, Number(maxGroupCount) || 1);
  const allGroups = Array.from({ length: safeMaxGroupCount }, (_value, index) => index + 1);
  const baseAccess = teacherAccess && teacherAccess.hasRows
    ? teacherAccess
    : { hasRows: false, allowAll: true, groups: new Set(allGroups) };

  const lessonScope = normalizeTeamworkLessonScope(task.lesson_scope);
  const baseGroups = baseAccess.allowAll
    ? [...allGroups]
    : Array.from(baseAccess.groups || []).filter((groupNum) => groupNum >= 1 && groupNum <= safeMaxGroupCount).sort((a, b) => a - b);

  if (lessonScope !== 'seminar') {
    const lectureAllowAll = baseAccess.allowAll || baseGroups.length === safeMaxGroupCount;
    return {
      lessonScope,
      allowAll: lectureAllowAll,
      groups: new Set(lectureAllowAll ? allGroups : baseGroups),
      label: lectureAllowAll ? 'Усі групи' : `Групи ${baseGroups.join(', ')}`,
    };
  }

  const parsedSeminarGroups = parseTeamworkGroupNumbers(task.seminar_group_numbers, safeMaxGroupCount);
  const requestedSeminarGroups = parsedSeminarGroups.all || !parsedSeminarGroups.groups.length
    ? [...allGroups]
    : parsedSeminarGroups.groups;
  const finalGroups = requestedSeminarGroups.filter((groupNum) => baseAccess.allowAll || baseGroups.includes(groupNum));
  const seminarAllowAll = finalGroups.length === safeMaxGroupCount;

  return {
    lessonScope,
    allowAll: seminarAllowAll,
    groups: new Set(finalGroups),
    label: seminarAllowAll ? 'Усі групи' : (finalGroups.length ? `Групи ${finalGroups.join(', ')}` : 'Немає груп'),
  };
};

const SUBJECT_MATERIAL_TYPES = new Set(['lecture', 'file', 'link', 'mixed']);

const normalizeSubjectMaterialType = (rawValue) => {
  const normalized = String(rawValue || '').trim().toLowerCase();
  return SUBJECT_MATERIAL_TYPES.has(normalized) ? normalized : 'lecture';
};

const parseSubjectMaterialInputType = (rawValue) => {
  const normalized = String(rawValue || '').trim().toLowerCase();
  if (normalized === 'syllabus') {
    return { materialType: 'lecture', isSyllabus: 1 };
  }
  return {
    materialType: normalizeSubjectMaterialType(normalized),
    isSyllabus: 0,
  };
};

const normalizeExternalUrl = (rawValue) => {
  const value = String(rawValue || '').trim();
  if (!value) return '';
  try {
    const parsed = new URL(value);
    if (!['http:', 'https:'].includes(parsed.protocol)) {
      return '';
    }
    return parsed.toString();
  } catch (err) {
    return '';
  }
};

