app.post('/admin/session-generator/draft/save', requireScheduleGeneratorSectionAccess, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return res.status(500).json({ ok: false, error: 'db_init_failed' });
  }
  try {
    const body = req.body || {};
    const userId = Number(req.session && req.session.user ? req.session.user.id : 0);
    if (!Number.isFinite(userId) || userId < 1) {
      return res.status(401).json({ ok: false, error: 'unauthorized' });
    }
    const location = normalizeGeneratorLocation(body.location || 'kyiv');
    const courseId = parseSessionGeneratorInt(body.course_id, null, 1, Number.MAX_SAFE_INTEGER);
    const semesterId = parseSessionGeneratorInt(body.semester_id, null, 1, Number.MAX_SAFE_INTEGER);
    const draftId = parseSessionGeneratorInt(body.draft_id, null, 1, Number.MAX_SAFE_INTEGER);
    const formPayload = normalizeSessionGeneratorDraftForm(body.form_json, {});
    formPayload.location = location;
    formPayload.course_id = courseId;
    formPayload.semester_id = semesterId;
    const assignmentsPayload = normalizeSessionGeneratorDraftAssignments(body.manual_assignments_json);

    let draftRecord = null;
    if (draftId) {
      draftRecord = await saveSessionGeneratorDraftRecord(userId, draftId, {
        form: formPayload,
        assignments: assignmentsPayload,
      });
    }
    if (!draftRecord) {
      draftRecord = await createSessionGeneratorDraftRecord(userId, formPayload, assignmentsPayload);
    }
    if (!draftRecord) {
      return res.status(500).json({ ok: false, error: 'draft_save_failed' });
    }
    return res.json({
      ok: true,
      draft_id: Number(draftRecord.id),
      updated_at: draftRecord.updated_at || null,
      assignments_count: assignmentsPayload.length,
    });
  } catch (err) {
    return res.status(500).json({ ok: false, error: 'draft_save_failed' });
  }
});

app.post('/admin/session-generator/conflicts/live', requireScheduleGeneratorSectionAccess, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return res.status(500).json({ ok: false, error: 'db_init_failed' });
  }
  try {
    const body = req.body || {};
    const selectedCourseId = parseSessionGeneratorInt(body.course_id, null, 1, Number.MAX_SAFE_INTEGER);
    const selectedSemesterId = parseSessionGeneratorInt(body.semester_id, null, 1, Number.MAX_SAFE_INTEGER);
    if (!selectedCourseId) {
      return res.status(400).json({ ok: false, error: 'course_required' });
    }

    const manualAssignments = parseSessionManualAssignments(body.manual_assignments_json);
    const explicitDates = parseIsoDateList(body.explicit_dates_json);
    const explicitDateSet = new Set(explicitDates);
    const subjects = await getSubjectsCached(selectedCourseId, { visibleOnly: true });
    const subjectById = new Map((subjects || []).map((subject) => [Number(subject.id), subject]));
    const outOfWindowRows = [];

    const assessments = manualAssignments
      .map((item) => {
        const subject = subjectById.get(Number(item.subject_id));
        if (!subject) return null;
        const groupCount = Math.max(1, Number(subject.group_count || 1));
        const groupNumberRaw = Number(item.group_number || 0);
        const hasExplicitGroup = Number.isFinite(groupNumberRaw) && groupNumberRaw > 0;
        if (hasExplicitGroup && groupNumberRaw > groupCount) return null;
        const safeGroupNumber = hasExplicitGroup ? Math.floor(groupNumberRaw) : null;
        const date = toDateOnly(item.date);
        if (!date || !isValidDateString(date)) return null;
        if (explicitDateSet.size && !explicitDateSet.has(date)) {
          outOfWindowRows.push({
            subject_id: Number(subject.id),
            subject_name: subject.name || '',
            date,
            class_number: Number(item.class_number || 0),
          });
          return null;
        }
        const classNumber = Number(item.class_number || 0);
        if (!Number.isFinite(classNumber) || classNumber < 1 || classNumber > 7) return null;
        const dayName = normalizeWeekdayName(getDayNameFromDate(date));
        if (!dayName) return null;
        return {
          kind: 'assessment',
          type: item.type === 'credit'
            ? 'credit'
            : (item.type === 'consultation' ? 'consultation' : 'exam'),
          subject_id: Number(subject.id),
          subject_name: subject.name || '',
          date,
          day_name: dayName,
          class_number: classNumber,
          group_number: safeGroupNumber,
          room_id: Number(item.room_id || 0) || null,
          note: item.note || '',
          marks: [item.type === 'credit' ? 'CR' : 'EX'],
        };
      })
      .filter(Boolean);

    const expandedAssignments = buildSessionExpandedAssignments(assessments, subjectById);
    const conflictReport = expandedAssignments.length
      ? await buildSessionTeacherConflictReport({
          expandedAssignments,
          selectedCourseId,
        })
      : { conflicts: [], unresolvedRows: [], checkedRows: 0 };
    const roomConflictState = expandedAssignments.length
      ? await buildSessionRoomConflictState({
          selectedCourseId,
          selectedSemesterId,
          assessments: expandedAssignments,
        })
      : { conflicts: [], checkedRows: 0 };
    const combinedReport = {
      conflicts: [
        ...(Array.isArray(conflictReport.conflicts) ? conflictReport.conflicts : []),
        ...(Array.isArray(roomConflictState.conflicts) ? roomConflictState.conflicts : []),
      ],
      unresolvedRows: Array.isArray(conflictReport.unresolvedRows) ? conflictReport.unresolvedRows : [],
      checkedRows: Number(conflictReport.checkedRows || 0) + Number(roomConflictState.checkedRows || 0),
    };
    const slotConflicts = buildSessionConflictSlotMapV2(combinedReport);
    const summary = formatSessionConflictSummary(combinedReport);

    return res.json({
      ok: true,
      summary,
      checked_rows: Number(combinedReport.checkedRows || 0),
      conflicts_total: (combinedReport.conflicts || []).length,
      unresolved_total: (combinedReport.unresolvedRows || []).length,
      out_of_window_total: outOfWindowRows.length,
      out_of_window_samples: outOfWindowRows.slice(0, 6),
      slot_conflicts: slotConflicts,
      conflicts: (combinedReport.conflicts || []).slice(0, 30),
      semester_id: selectedSemesterId || null,
    });
  } catch (err) {
    return res.status(500).json({ ok: false, error: 'conflict_check_failed' });
  }
});

app.post('/admin/session-generator/publish', requireScheduleGeneratorSectionAccess, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'admin.sessionGenerator.publish.init');
  }
  try {
    const body = req.body || {};
    const publishAction = normalizeSessionPublishAction(body.publish_action);
    let { activeLocation, selectedCourseId, selectedSemesterRaw, draftId, form } = parseSessionGeneratorActionPayload(body);
    const userId = Number(req.session && req.session.user ? req.session.user.id : 0);
    const redirectToGenerator = (messageKind, messageText) => {
      return res.redirect(buildSessionGeneratorReturnHref({
        ...form,
        location: activeLocation,
        course_id: selectedCourseId,
        semester_id: form.semester_id || selectedSemesterRaw,
        draft_id: draftId,
      }, messageKind, messageText));
    };

    if (!selectedCourseId) {
      return redirectToGenerator('err', 'Оберіть курс для публікації сесії.');
    }

    const semesters = await getSemestersCached(selectedCourseId);
    let activeSemester = null;
    if (selectedSemesterRaw) {
      activeSemester = (semesters || []).find((row) => Number(row.id) === Number(selectedSemesterRaw)) || null;
    }
    if (!activeSemester) {
      activeSemester = await getActiveSemester(selectedCourseId);
    }
    if (!activeSemester && semesters && semesters.length) {
      activeSemester = semesters[0];
    }
    if (!activeSemester) {
      return redirectToGenerator('err', 'Активний семестр не знайдено.');
    }

    const selectedSemesterId = Number(activeSemester.id);
    form.semester_id = selectedSemesterId;
    if (!isValidDateString(body.start_date)) {
      form.start_date = buildSessionGeneratorDefaultStartDate(activeSemester);
    }

    const subjects = await getSubjectsCached(selectedCourseId, { visibleOnly: true });
    if (!subjects || !subjects.length) {
      return redirectToGenerator('err', 'Немає предметів для генерації сесії.');
    }
    let courseStudyDays = [];
    try {
      courseStudyDays = await getCourseStudyDays(selectedCourseId);
    } catch (err) {
      courseStudyDays = [];
    }
    const activeStudyDayNames = (courseStudyDays || [])
      .filter((row) => row.is_active)
      .map((row) => row.day_name)
      .filter(Boolean);
    const windowDates = resolveSessionGeneratorWindowDates({
      form,
      semester: activeSemester,
      activeStudyDayNames,
      explicitDates: body.explicit_dates_json,
    });
    const explicitSessionDates = windowDates.explicitSessionDates;
    form.window_mode = windowDates.window_mode;
    form.session_weeks_set = windowDates.sessionWeeksSet;

    const subjectById = new Map((subjects || []).map((subject) => [Number(subject.id), subject]));
    const rawManualAssignments = parseSessionManualAssignments(body.manual_assignments_json);
    if (draftId && Number.isFinite(userId) && userId > 0) {
      try {
        await saveSessionGeneratorDraftRecord(userId, draftId, {
          form,
          assignments: rawManualAssignments,
        });
      } catch (_err) {
        // Non-blocking: publish must not fail because draft autosave failed.
      }
    }
    if (!rawManualAssignments.length) {
      return redirectToGenerator('err', 'Ручний план порожній. Додайте екзамени/заліки у слотах розкладу.');
    }
    const allowedDateSet = new Set(explicitSessionDates || []);
    const outOfWindowRows = [];
    const assessments = rawManualAssignments
      .map((item) => {
        const subject = subjectById.get(Number(item.subject_id));
        if (!subject) return null;
        const groupCount = Math.max(1, Number(subject.group_count || 1));
        const groupNumber = Number(item.group_number || 0);
        const hasExplicitGroup = Number.isFinite(groupNumber) && groupNumber > 0;
        if (hasExplicitGroup && groupNumber > groupCount) return null;
        const safeGroupNumber = hasExplicitGroup ? groupNumber : null;
        const date = toDateOnly(item.date);
        if (allowedDateSet.size && !allowedDateSet.has(date)) {
          outOfWindowRows.push({
            subject_name: subject.name || '',
            date,
            class_number: Number(item.class_number || 0),
          });
          return null;
        }
        const dayName = normalizeWeekdayName(getDayNameFromDate(date));
        if (!dayName) return null;
        return {
          kind: 'assessment',
          type: item.type === 'credit'
            ? 'credit'
            : (item.type === 'consultation' ? 'consultation' : 'exam'),
          subject_id: Number(subject.id),
          subject_name: subject.name || '',
          date,
          day_name: dayName,
          class_number: Number(item.class_number),
          group_number: safeGroupNumber,
          room_id: Number(item.room_id || 0) || null,
          group_label: safeGroupNumber ? `Група ${safeGroupNumber}` : (groupCount > 1 ? `Всі групи (${groupCount})` : 'Всі'),
          note: item.note || '',
          marks: [item.type === 'credit' ? 'CR' : 'EX'],
        };
      })
      .filter(Boolean)
      .sort((a, b) => {
        const typeOrder = { exam: 1, consultation: 2, credit: 3 };
        const byDate = String(a.date || '').localeCompare(String(b.date || ''));
        if (byDate !== 0) return byDate;
        if (a.type !== b.type) return Number(typeOrder[a.type] || 9) - Number(typeOrder[b.type] || 9);
        const byClass = Number(a.class_number || 0) - Number(b.class_number || 0);
        if (byClass !== 0) return byClass;
        const bySubject = String(a.subject_name || '').localeCompare(String(b.subject_name || ''), 'uk');
        if (bySubject !== 0) return bySubject;
        return Number(a.group_number || 0) - Number(b.group_number || 0);
      });
    if (outOfWindowRows.length) {
      return redirectToGenerator(
        'err',
        `Частина подій поза вікном сесії (${outOfWindowRows.length}). Перевірте тижні сесії та слоти.`
      );
    }
    if (!assessments.length) {
      return redirectToGenerator('err', 'Немає коректних подій для публікації.');
    }
    const expandedAssignments = buildSessionExpandedAssignments(assessments, subjectById);
    if (!expandedAssignments.length) {
      return redirectToGenerator('err', 'Немає коректних призначень у ручному плані.');
    }
    const conflictReport = await buildSessionTeacherConflictReport({
      expandedAssignments,
      selectedCourseId,
    });
    const roomConflictState = await buildSessionRoomConflictState({
      selectedCourseId,
      selectedSemesterId,
      assessments: expandedAssignments,
    });
    const combinedReport = {
      conflicts: [
        ...(Array.isArray(conflictReport.conflicts) ? conflictReport.conflicts : []),
        ...(Array.isArray(roomConflictState.conflicts) ? roomConflictState.conflicts : []),
      ],
      unresolvedRows: Array.isArray(conflictReport.unresolvedRows) ? conflictReport.unresolvedRows : [],
      checkedRows: Number(conflictReport.checkedRows || 0) + Number(roomConflictState.checkedRows || 0),
    };
    const conflictSummary = formatSessionConflictSummary(combinedReport);
    if (publishAction === 'check_conflicts') {
      return redirectToGenerator(combinedReport.conflicts.length ? 'err' : 'ok', conflictSummary);
    }
    if (combinedReport.conflicts.length) {
      return redirectToGenerator('err', conflictSummary);
    }
    const username = String(req.session.user?.username || '');
    const authorId = Number(req.session.user?.id || 0);
    const createdAt = new Date().toISOString();
    let createdCount = 0;
    let skippedCount = 0;
    const touchedSubjectIds = new Set();

    for (const assignment of expandedAssignments) {
      const subjectId = Number(assignment.subject_id);
      const groupNumber = Number(assignment.group_number);
      const classNumber = Number(assignment.class_number);
      const assessmentDate = toDateOnly(assignment.date);
      const dayName = normalizeWeekdayName(assignment.day_name);
      const roomId = Number(assignment.room_id || 0) || null;
      if (
        !Number.isFinite(subjectId) || subjectId < 1
        || !Number.isFinite(groupNumber) || groupNumber < 1
        || !Number.isFinite(classNumber) || classNumber < 1 || classNumber > 7
        || !isValidDateString(assessmentDate)
        || !dayName
      ) {
        continue;
      }
      const subject = subjectById.get(subjectId);
      if (!subject) continue;
      const isConsultation = assignment.type === 'consultation';
      const isCredit = assignment.type === 'credit' ? 1 : 0;
      if (!isConsultation) {
        touchedSubjectIds.add(subjectId);
      }
      const typeLabel = isConsultation ? 'Консультація' : (isCredit ? 'Залік' : 'Екзамен');
      const descriptionBase = `[Сесія] ${typeLabel} · ${subject.name || assignment.subject_name || ''}`.trim();
      const description = assignment.note
        ? `${descriptionBase} · ${String(assignment.note).trim().slice(0, 120)}`
        : descriptionBase;
      const slot = bellSchedule[classNumber] || null;
      const timeLabel = slot ? `${slot.start}-${slot.end}` : `Пара ${classNumber}`;
      const isControlFlag = isConsultation ? 0 : 1;

      let existingSql = `
        SELECT id
        FROM homework
        WHERE subject_id = ?
          AND group_number = ?
          AND course_id = ?
          AND class_date = ?
          AND class_number = ?
          AND COALESCE(is_teacher_homework, 0) = 1
          AND COALESCE(is_custom_deadline, 0) = 0
          AND COALESCE(status, 'published') IN ('draft', 'scheduled', 'published')
      `;
      const existingParams = [subjectId, groupNumber, selectedCourseId, assessmentDate, classNumber];
      if (isConsultation) {
        existingSql += " AND COALESCE(is_control, 0) = 0 AND COALESCE(is_credit, 0) = 0 AND LOWER(TRIM(COALESCE(description, ''))) LIKE '[сесія] консультація%'";
      } else {
        existingSql += ' AND COALESCE(is_control, 0) = 1 AND COALESCE(is_credit, 0) = ?';
        existingParams.push(isCredit);
      }
      if (selectedSemesterId) {
        existingSql += ' AND (semester_id = ? OR semester_id IS NULL)';
        existingParams.push(selectedSemesterId);
      } else {
        existingSql += ' AND semester_id IS NULL';
      }
      existingSql += ' LIMIT 1';
      const existing = await db.get(existingSql, existingParams);
      if (existing && Number(existing.id) > 0) {
        skippedCount += 1;
        continue;
      }

      await db.run(
        `
          INSERT INTO homework
            (
              group_name, subject, day, time, class_number, subject_id, group_number, day_of_week,
              created_by_id, description, class_date, meeting_url, link_url, file_path, file_name,
              created_by, created_at, course_id, semester_id, status, scheduled_at, published_at,
              is_control, is_teacher_homework, is_credit, room_id
            )
          VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'published', NULL, ?, ?, 1, ?, ?)
        `,
        [
          `Група ${groupNumber}`,
          subject.name || assignment.subject_name || '',
          dayName,
          timeLabel,
          classNumber,
          subjectId,
          groupNumber,
          dayName,
          authorId || null,
          description,
          assessmentDate,
          null,
          null,
          null,
          null,
          username || null,
          createdAt,
          selectedCourseId,
          selectedSemesterId || null,
          createdAt,
          isControlFlag,
          isCredit,
          roomId,
        ]
      );
      createdCount += 1;
    }

    let syncedSubjects = 0;
    for (const subjectId of touchedSubjectIds) {
      try {
        const gradingSettings = await ensureSubjectGradingSettings(
          Number(subjectId),
          selectedCourseId,
          selectedSemesterId,
          authorId || null
        );
        await syncJournalColumnsFromHomework(
          Number(subjectId),
          selectedCourseId,
          selectedSemesterId,
          gradingSettings,
          authorId || null
        );
        syncedSubjects += 1;
      } catch (err) {
        if (!isDbSchemaCompatibilityError(err)) {
          throw err;
        }
      }
    }

    const unresolvedSuffix = combinedReport.unresolvedRows.length
      ? ` Перевірка конфліктів неповна: для ${conflictReport.unresolvedRows.length} подій не знайдено привʼязаного викладача (teacher_subjects).`
      : '';
    const message = createdCount > 0
      ? `Опубліковано ${createdCount} подій сесії. Пропущено дублікатів: ${skippedCount}. Синхронізовано предметів у журналі: ${syncedSubjects}.${unresolvedSuffix}`
      : `Нових подій не створено (дублікатів: ${skippedCount}).${unresolvedSuffix}`;
    return redirectToGenerator('ok', message.trim());
  } catch (err) {
    return handleDbError(res, err, 'admin.sessionGenerator.publish');
  }
});

app.post('/admin/session-generator/delete', requireScheduleGeneratorSectionAccess, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'admin.sessionGenerator.delete.init');
  }
  try {
    const body = req.body || {};
    let { activeLocation, selectedCourseId, selectedSemesterRaw, draftId, form } = parseSessionGeneratorActionPayload(body);
    const redirectToGenerator = (messageKind, messageText) => {
      return res.redirect(buildSessionGeneratorReturnHref({
        ...form,
        location: activeLocation,
        course_id: selectedCourseId,
        semester_id: form.semester_id || selectedSemesterRaw,
        draft_id: draftId,
      }, messageKind, messageText));
    };

    if (!selectedCourseId) {
      return redirectToGenerator('err', 'Оберіть курс для видалення сесії.');
    }

    const semesters = await getSemestersCached(selectedCourseId);
    let activeSemester = null;
    if (selectedSemesterRaw) {
      activeSemester = (semesters || []).find((row) => Number(row.id) === Number(selectedSemesterRaw)) || null;
    }
    if (!activeSemester) {
      activeSemester = await getActiveSemester(selectedCourseId);
    }
    if (!activeSemester && semesters && semesters.length) {
      activeSemester = semesters[0];
    }
    if (!activeSemester) {
      return redirectToGenerator('err', 'Активний семестр не знайдено.');
    }
    const selectedSemesterId = Number(activeSemester.id);
    form.semester_id = selectedSemesterId;

    let courseStudyDays = [];
    try {
      courseStudyDays = await getCourseStudyDays(selectedCourseId);
    } catch (_err) {
      courseStudyDays = [];
    }
    const activeStudyDayNames = (courseStudyDays || [])
      .filter((row) => row.is_active)
      .map((row) => row.day_name)
      .filter(Boolean);

    const windowDates = resolveSessionGeneratorWindowDates({
      form,
      semester: activeSemester,
      activeStudyDayNames,
      explicitDates: body.explicit_dates_json,
    });
    form.window_mode = windowDates.window_mode;
    form.session_weeks_set = windowDates.sessionWeeksSet;
    const explicitSessionDates = windowDates.explicitSessionDates;
    const targetDates = Array.from(new Set((explicitSessionDates || []).filter((date) => isValidDateString(date)))).sort();
    if (!targetDates.length) {
      return redirectToGenerator('err', 'Немає дат сесії для видалення. Перевірте тижні сесії.');
    }

    const actorUserId = Number(req.session.user?.id || 0) || null;
    const cleanupResult = await purgeSessionGeneratorHomework({
      courseId: selectedCourseId,
      semesterId: selectedSemesterId,
      targetDates,
      actorUserId,
      purgeResidualSessionColumns: false,
    });
    let draftCleanup = {
      removedAssignmentsCount: 0,
      remainingAssignmentsCount: 0,
      updated: false,
    };
    if (actorUserId && draftId) {
      const currentDraftAssignments = parseSessionManualAssignments(body.manual_assignments_json);
      try {
        draftCleanup = await syncSessionGeneratorDraftAfterCleanup({
          userId: actorUserId,
          draftId,
          form,
          targetDates,
          currentAssignments: currentDraftAssignments,
        });
      } catch (_err) {
        draftCleanup = {
          removedAssignmentsCount: 0,
          remainingAssignmentsCount: 0,
          updated: false,
        };
      }
    }
    if (!Number(cleanupResult.deletedHomeworkCount || 0)) {
      const draftSuffix = draftCleanup.removedAssignmentsCount
        ? ` З чернетки прибрано призначень: ${draftCleanup.removedAssignmentsCount}.`
        : '';
      return redirectToGenerator('ok', `У вибраному вікні сесії немає подій для видалення.${draftSuffix}`.trim());
    }
    const draftSuffix = draftCleanup.removedAssignmentsCount
      ? ` З чернетки прибрано призначень: ${draftCleanup.removedAssignmentsCount}.`
      : '';
    return redirectToGenerator(
      'ok',
      `Видалено ${cleanupResult.deletedHomeworkCount} подій сесії у вибраному вікні. Очищено колонок журналу: ${cleanupResult.deletedJournalColumnsCount}. Синхронізовано предметів у журналі: ${cleanupResult.syncedSubjects}.${draftSuffix}`.trim()
    );
  } catch (err) {
    return handleDbError(res, err, 'admin.sessionGenerator.delete');
  }
});

app.post('/admin/session-generator/delete-all-active', requireScheduleGeneratorSectionAccess, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'admin.sessionGenerator.deleteAll.init');
  }
  try {
    const body = req.body || {};
    let { activeLocation, selectedCourseId, selectedSemesterRaw, draftId, form } = parseSessionGeneratorActionPayload(body);
    const redirectToGenerator = (messageKind, messageText) => {
      return res.redirect(buildSessionGeneratorReturnHref({
        ...form,
        location: activeLocation,
        course_id: selectedCourseId,
        semester_id: form.semester_id || selectedSemesterRaw,
        draft_id: draftId,
      }, messageKind, messageText));
    };

    if (!selectedCourseId) {
      return redirectToGenerator('err', 'Оберіть курс для повного очищення сесії.');
    }

    const semesters = await getSemestersCached(selectedCourseId);
    let activeSemester = null;
    if (selectedSemesterRaw) {
      activeSemester = (semesters || []).find((row) => Number(row.id) === Number(selectedSemesterRaw)) || null;
    }
    if (!activeSemester) {
      activeSemester = await getActiveSemester(selectedCourseId);
    }
    if (!activeSemester && semesters && semesters.length) {
      activeSemester = semesters[0];
    }
    if (!activeSemester) {
      return redirectToGenerator('err', 'Активний семестр не знайдено.');
    }
    const selectedSemesterId = Number(activeSemester.id);
    form.semester_id = selectedSemesterId;

    const actorUserId = Number(req.session.user?.id || 0) || null;
    const cleanupResult = await purgeSessionGeneratorHomework({
      courseId: selectedCourseId,
      semesterId: selectedSemesterId,
      actorUserId,
      purgeResidualSessionColumns: true,
    });
    const deletedHomeworkCount = Number(cleanupResult.deletedHomeworkCount || 0);
    const deletedJournalColumnsCount = Number(cleanupResult.deletedJournalColumnsCount || 0);
    let draftCleanup = {
      removedAssignmentsCount: 0,
      remainingAssignmentsCount: 0,
      updated: false,
    };
    if (actorUserId && draftId) {
      const currentDraftAssignments = parseSessionManualAssignments(body.manual_assignments_json);
      try {
        draftCleanup = await syncSessionGeneratorDraftAfterCleanup({
          userId: actorUserId,
          draftId,
          form,
          currentAssignments: currentDraftAssignments,
          clearAll: true,
        });
      } catch (_err) {
        draftCleanup = {
          removedAssignmentsCount: 0,
          remainingAssignmentsCount: 0,
          updated: false,
        };
      }
    }
    if (!deletedHomeworkCount && !deletedJournalColumnsCount) {
      const draftSuffix = draftCleanup.removedAssignmentsCount
        ? ` Чернетку очищено: ${draftCleanup.removedAssignmentsCount} призначень прибрано.`
        : '';
      return redirectToGenerator('ok', `Активних сесій для очищення не знайдено.${draftSuffix}`.trim());
    }
    const draftSuffix = draftCleanup.removedAssignmentsCount
      ? ` Чернетку очищено: ${draftCleanup.removedAssignmentsCount} призначень прибрано.`
      : '';

    return redirectToGenerator(
      'ok',
      `Повністю очищено активну сесію: подій ${deletedHomeworkCount}, колонок журналу ${deletedJournalColumnsCount}. Синхронізовано предметів у журналі: ${cleanupResult.syncedSubjects}.${draftSuffix}`.trim()
    );
  } catch (err) {
    return handleDbError(res, err, 'admin.sessionGenerator.deleteAll');
  }
});

app.get('/admin/schedule-generator', requireScheduleGeneratorSectionAccess, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'admin.scheduleGenerator.init');
  }
  const userId = req.session.user.id;
  const runId = Number(req.query.run);
  let run = null;
  try {
    if (Number.isFinite(runId) && runId > 0) {
      run = await db.get('SELECT * FROM schedule_generator_runs WHERE id = ?', [runId]);
    }
    if (!run) {
      run = await db.get(
        'SELECT * FROM schedule_generator_runs WHERE created_by_id = ? ORDER BY created_at DESC LIMIT 1',
        [userId]
      );
    }
    if (!run) {
      const insert = await db.run(
        'INSERT INTO schedule_generator_runs (status, created_by_id, config) VALUES (?, ?, ?) RETURNING id',
        ['draft', userId, serializeGeneratorConfig(DEFAULT_GENERATOR_CONFIG)]
      );
      const newId = insert.lastID;
      return res.redirect(`/admin/schedule-generator?run=${newId}`);
    }

    const parsedConfig = parseGeneratorConfig(run.config);
    const config = parsedConfig && typeof parsedConfig === 'object'
      ? { ...DEFAULT_GENERATOR_CONFIG, ...parsedConfig }
      : { ...DEFAULT_GENERATOR_CONFIG };
    const requestedLocation = String((req.body && req.body.active_location) || '');
    const activeLocation = requestedLocation.toLowerCase() === 'munich'
      ? 'munich'
      : requestedLocation
      ? 'kyiv'
      : config.active_location === 'munich'
      ? 'munich'
      : 'kyiv';
    if (activeLocation !== config.active_location) {
      config.active_location = activeLocation;
    }
    const coursesByLocation = {
      kyiv: await getCoursesByLocation('kyiv'),
      munich: await getCoursesByLocation('munich'),
    };
    const courseSemestersByLocation = { kyiv: [], munich: [] };
    const courseDaysByLocation = { kyiv: {}, munich: {} };
    const subjectsByCourse = {};
    const semestersByCourse = {};
    const selectedSemestersByLocation = { kyiv: {}, munich: {} };
    for (const location of ['kyiv', 'munich']) {
      const courses = coursesByLocation[location] || [];
      for (const course of courses) {
        const semesters = await getSemestersCached(course.id);
        semestersByCourse[course.id] = semesters || [];
        const configuredId = config.course_semesters_by_location
          ? config.course_semesters_by_location[location]?.[course.id]
            || config.course_semesters_by_location[location]?.[String(course.id)]
          : null;
        let semester = null;
        if (configuredId) {
          semester = (semesters || []).find((s) => Number(s.id) === Number(configuredId)) || null;
        }
        if (!semester) {
          semester = await getActiveSemester(course.id);
        }
        if (semester) {
          selectedSemestersByLocation[location][course.id] = semester.id;
        }
        courseSemestersByLocation[location].push({ course, semester });
        const studyDays = await getCourseStudyDays(course.id);
        const activeDays = (studyDays || [])
          .filter((d) => d.is_active)
          .map((d) => d.day_name)
          .filter(Boolean);
        courseDaysByLocation[location][course.id] = activeDays.length ? activeDays : [...daysOfWeek];
        subjectsByCourse[course.id] = await getSubjectsCached(course.id);
      }
    }

    const teachers = await db.all(
      "SELECT id, full_name FROM users WHERE role = 'teacher' ORDER BY full_name"
    );
    const items = await db.all(
      `
        SELECT sgi.*, s.name AS subject_name, s.group_count, s.is_general, u.full_name AS teacher_name
        FROM schedule_generator_items sgi
        JOIN subjects s ON s.id = sgi.subject_id
        LEFT JOIN users u ON u.id = sgi.teacher_id
        WHERE sgi.run_id = ?
        ORDER BY sgi.id DESC
      `,
      [run.id]
    );
    const courseLocationMap = {};
    Object.entries(coursesByLocation).forEach(([location, list]) => {
      (list || []).forEach((course) => {
        courseLocationMap[course.id] = location;
      });
    });
    const limitsRows = await db.all(
      'SELECT * FROM schedule_generator_teacher_limits WHERE run_id = ?',
      [run.id]
    );
    const limitsByTeacher = {};
    limitsRows.forEach((row) => {
      limitsByTeacher[row.teacher_id] = {
        allowed_weekdays: row.allowed_weekdays ? row.allowed_weekdays.split(',') : [],
        max_pairs_per_week: row.max_pairs_per_week,
      };
    });
    const lastConflicts = Array.isArray(config.last_conflicts) ? config.last_conflicts : [];
    const lastStats = config.last_stats || null;
    const allCourses = Object.values(coursesByLocation).flat();
    const courseById = {};
    allCourses.forEach((course) => {
      courseById[course.id] = course.name;
    });
    const courseMetaById = {};
    ['kyiv', 'munich'].forEach((location) => {
      (courseSemestersByLocation[location] || []).forEach((row) => {
        courseMetaById[row.course.id] = {
          weeks_count: row.semester ? Number(row.semester.weeks_count || 0) : 0,
          active_days: courseDaysByLocation[location][row.course.id] || [],
          location,
        };
      });
    });
    const itemsByLocation = { kyiv: [], munich: [] };
    const itemsById = {};
    (items || []).forEach((item) => {
      itemsById[item.id] = item;
      const location = courseLocationMap[item.course_id] || 'kyiv';
      itemsByLocation[location].push(item);
    });
    const mirrorSummaryByLocation = {
      kyiv: buildMirrorSummary(itemsByLocation.kyiv, courseById),
      munich: buildMirrorSummary(itemsByLocation.munich, courseById),
    };
    const validationByLocation = {
      kyiv: buildGeneratorValidation({
        items: itemsByLocation.kyiv,
        courseMetaById,
        teacherLimits: limitsByTeacher,
        config,
        locationLabel: 'Kyiv',
      }),
      munich: buildGeneratorValidation({
        items: itemsByLocation.munich,
        courseMetaById,
        teacherLimits: limitsByTeacher,
        config,
        locationLabel: 'Munich',
      }),
    };
    const { conflictDetails, conflictItemIds } = buildConflictContext(
      lastConflicts,
      itemsById,
      courseById,
      courseLocationMap
    );
    const problemItemLookupByLocation = { kyiv: {}, munich: {} };
    ['kyiv', 'munich'].forEach((location) => {
      const validationItems = validationByLocation[location].itemIssues || {};
      Object.entries(validationItems).forEach(([itemId, info]) => {
        problemItemLookupByLocation[location][itemId] = info.level;
      });
      conflictItemIds[location].forEach((itemId) => {
        if (!problemItemLookupByLocation[location][itemId]) {
          problemItemLookupByLocation[location][itemId] = 'warn';
        }
      });
    });
    const entryRows = await db.all(
      'SELECT course_id, day_of_week, class_number FROM schedule_generator_entries WHERE run_id = ?',
      [run.id]
    );
    const entriesByLocation = { kyiv: [], munich: [] };
    (entryRows || []).forEach((row) => {
      const location = courseLocationMap[row.course_id] || 'kyiv';
      entriesByLocation[location].push(row);
    });
    const heatmapByLocation = {
      kyiv: buildHeatmap(entriesByLocation.kyiv, fullWeekDays, [1, 2, 3, 4, 5, 6, 7]),
      munich: buildHeatmap(entriesByLocation.munich, fullWeekDays, [1, 2, 3, 4, 5, 6, 7]),
    };
    const isSeminarType = (lessonType) => {
      const raw = String(lessonType || '').toLowerCase();
      return raw.includes('seminar') || raw.includes('сем');
    };
    const autoMirrorCandidatesByLocation = { kyiv: [], munich: [] };
    const autoMirrorExclusionsByLocation = { kyiv: [], munich: [] };
    Object.entries(itemsByLocation).forEach(([location, list]) => {
      const buckets = new Map();
      const matchedIds = new Set();
      const sameSubjectOnly = new Set();
      (list || []).forEach((item) => {
        const groupNum = Number(item.group_number);
        const generalFlag = item.is_general === true || Number(item.is_general) === 1;
        const baseEligible = isSeminarType(item.lesson_type)
          && (groupNum === 1 || groupNum === 2)
          && !item.mirror_key
          && !(item.fixed_day || item.fixed_class_number || item.weeks_set)
          && generalFlag;
        if (!baseEligible) return;
        const key = `${item.course_id}|${item.semester_id || ''}|${String(item.lesson_type || '')}|${item.pairs_count || 0}`;
        if (!buckets.has(key)) {
          buckets.set(key, { group1: [], group2: [] });
        }
        const bucket = buckets.get(key);
        if (groupNum === 1) bucket.group1.push(item);
        if (groupNum === 2) bucket.group2.push(item);
      });
      const candidates = [];
      buckets.forEach((bucket) => {
        const group1 = [...bucket.group1].sort((a, b) => a.subject_name.localeCompare(b.subject_name) || a.id - b.id);
        const group2 = [...bucket.group2].sort((a, b) => a.subject_name.localeCompare(b.subject_name) || a.id - b.id);
        const used = new Set();
        group1.forEach((a) => {
          const idx = group2.findIndex((b, i) => !used.has(i) && Number(b.subject_id) !== Number(a.subject_id));
          if (idx === -1) return;
          const b = group2[idx];
          used.add(idx);
          matchedIds.add(a.id);
          matchedIds.add(b.id);
          candidates.push({
            a,
            b,
            course_name: courseById[a.course_id] || '',
            lesson_type: a.lesson_type,
            pairs_count: a.pairs_count,
          });
        });
      });
      buckets.forEach((bucket) => {
        bucket.group1.forEach((a) => {
          if (matchedIds.has(a.id)) return;
          const hasSame = bucket.group2.some((b) => Number(b.subject_id) === Number(a.subject_id));
          if (hasSame) sameSubjectOnly.add(a.id);
        });
        bucket.group2.forEach((b) => {
          if (matchedIds.has(b.id)) return;
          const hasSame = bucket.group1.some((a) => Number(a.subject_id) === Number(b.subject_id));
          if (hasSame) sameSubjectOnly.add(b.id);
        });
      });
      const exclusions = [];
      (list || []).forEach((item) => {
        const reasons = [];
        const groupNum = Number(item.group_number);
        const generalFlag = item.is_general === true || Number(item.is_general) === 1;
        if (!isSeminarType(item.lesson_type)) reasons.push('Не семінар');
        if (!(groupNum === 1 || groupNum === 2)) reasons.push('Не група 1/2');
        if (item.mirror_key) reasons.push('Вже має ключ дзеркала');
        if (item.fixed_day || item.fixed_class_number || item.weeks_set) reasons.push('Є фіксований день/слот/тижні');
        if (!generalFlag) reasons.push('Не загальний предмет');
        if (!reasons.length && !matchedIds.has(item.id)) {
          if (sameSubjectOnly.has(item.id)) {
            reasons.push('У іншій групі лише такий самий предмет');
          } else {
            reasons.push('Немає пари для групи 1/2');
          }
        }
        if (!reasons.length) return;
        exclusions.push({
          id: item.id,
          subject_name: item.subject_name,
          course_name: courseById[item.course_id] || '',
          group_number: item.group_number,
          lesson_type: item.lesson_type,
          pairs_count: item.pairs_count,
          reasons,
        });
      });
      autoMirrorCandidatesByLocation[location] = candidates;
      autoMirrorExclusionsByLocation[location] = exclusions;
    });
    const generationInsightsByLocation = buildGenerationInsights({
      validationByLocation,
      conflictDetails,
      heatmapByLocation,
      mirrorSummaryByLocation,
      config,
    });

    return res.render('admin-schedule-generator', {
      username: req.session.user.username,
      role: req.session.role,
      run,
      config,
      activeLocation,
      coursesByLocation,
      courseSemestersByLocation,
      courseDaysByLocation,
      subjectsByCourse,
      semestersByCourse,
      selectedSemestersByLocation,
      courseLocationMap,
      courseById,
      teachers,
      items,
      limitsByTeacher,
      lastConflicts,
      lastStats,
      mirrorSummaryByLocation,
      validationByLocation,
      conflictDetails,
      conflictItemIds,
      problemItemLookupByLocation,
      heatmapByLocation,
      generationInsightsByLocation,
      autoMirrorCandidatesByLocation,
      autoMirrorExclusionsByLocation,
      dayOptions: fullWeekDays,
      dayLabels: studyDayLabels,
      classOptions: [1, 2, 3, 4, 5, 6, 7],
    });
  } catch (err) {
    return handleDbError(res, err, 'admin.scheduleGenerator.render');
  }
});

